import{_ as a,c as m,o as e,b as t}from"./app.648408b7.js";const k='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 15-16","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 15-16","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-02-02T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/3/15-16/index.md"}',r={},i=t('<div class="stanza"><a href="#s3.15" id="s3.15" class="num">3.15</a><div class="sans"><p>\u0928 \u091A\u0948\u0935\u092E\u092A\u094D\u092F\u0941\u0926\u093E\u0938\u0940\u0928\u0947\u0928\u093E\u0928\u0947\u0928 \u092D\u093E\u0935\u094D\u092F\u092E\u092A\u093F \u0924\u0941\u2014</p><blockquote><p><strong>\u092C\u0940\u091C\u093E\u0935\u0927\u093E\u0928\u092E\u094D\u0965\u0967\u096B\u0965</strong></p></blockquote><p>\u0915\u0930\u094D\u0924\u0935\u094D\u092F\u092E\u093F\u0924\u093F \u0936\u0947\u0937\u0903\u0964 \u092C\u0940\u091C\u0902 \u0935\u093F\u0936\u094D\u0935\u0915\u093E\u0930\u0923\u0902 \u0938\u094D\u092B\u0941\u0930\u0924\u094D\u0924\u093E\u0924\u094D\u092E\u093E \u092A\u0930\u093E \u0936\u0915\u094D\u0924\u093F\u0903\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u092E\u0943\u0924\u094D\u092F\u0941\u091C\u093F\u0926\u094D\u092D\u091F\u094D\u091F\u093E\u0930\u0915\u0947</p><blockquote><p>\u0938\u093E \u092F\u094B\u0928\u093F\u0903 \u0938\u0930\u094D\u0935\u0926\u0947\u0935\u093E\u0928\u093E\u0902 \u0936\u0915\u094D\u0924\u0940\u0928\u093E\u0902 \u091A\u093E\u092A\u094D\u092F\u0928\u0947\u0915\u0927\u093E\u0964<br> \u0905\u0917\u094D\u0928\u0940\u0937\u094B\u092E\u093E\u0924\u094D\u092E\u093F\u0915\u093E \u092F\u094B\u0928\u093F\u0938\u094D\u0924\u0938\u094D\u092F\u093E\u0903 \u0938\u0930\u094D\u0935\u0902 \u092A\u094D\u0930\u0935\u0930\u094D\u0924\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u093E\u0926\u093F\u0964 \u0924\u0924\u094D\u0930 \u092A\u0930\u0936\u0915\u094D\u0924\u094D\u092F\u093E\u0924\u094D\u092E\u0928\u093F \u092C\u0940\u091C \u0905\u0935\u0927\u093E\u0928\u0902 \u092D\u0942\u092F\u094B \u092D\u0942\u092F\u0936\u094D\u091A\u093F\u0924\u094D\u0924\u0928\u093F\u0935\u0947\u0936\u0928\u0902 \u0915\u093E\u0930\u094D\u092F\u092E\u094D\u0965\u0967\u096B\u0965</p></div><hr><div class="trans"><p>Na caivamapyud\u0101s\u012Bnen\u0101nena bh\u0101vyamapi tu\u2014</p><blockquote><p><strong>B\u012Bj\u0101vadh\u0101nam||15||</strong></p></blockquote><p>Kartavyamiti \u015Be\u1E63a\u1E25| B\u012Bja\u1E41 vi\u015Bvak\u0101ra\u1E47a\u1E41 sphuratt\u0101tm\u0101 par\u0101 \u015Bakti\u1E25| Yadukta\u1E41 \u015Br\u012Bm\u1E5Btyujidbha\u1E6D\u1E6D\u0101rake</p><blockquote><p>S\u0101 yoni\u1E25 sarvadev\u0101n\u0101\u1E41 \u015Bakt\u012Bn\u0101\u1E41 c\u0101pyanekadh\u0101|<br> Agn\u012B\u1E63om\u0101tmik\u0101 yonistasy\u0101\u1E25 sarva\u1E41 pravartate||</p></blockquote><p>ity\u0101di| Tatra para\u015Bakty\u0101tmani b\u012Bja avadh\u0101na\u1E41 bh\u016Byo bh\u016Bya\u015Bcittanive\u015Bana\u1E41 k\u0101ryam||15||</p></div><hr><p>\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 --\u0442.\u0435. \u0434\u0430\u0436\u0435 \u043F\u043E\u0441\u043B\u0435 \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u044F \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0445 \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0441\u0438\u043B-- <em>(evam api)</em>, \u044D\u0442\u043E\u043C\u0443 [Yog\u012B] \u043D\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u044C\u0441\u044F \u0431\u0435\u0437\u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C <em>(na ca eva... ud\u0101s\u012Bnena anena bh\u0101vyam)</em> , \u0430 \u0441\u043A\u043E\u0440\u0435\u0435 <em>(api tu)</em>\u2014</p><blockquote><p><strong>[\u0422\u043E\u0442 Yog\u012B \u0434\u043E\u043B\u0436\u0435\u043D \u0441\u0444\u043E\u043A\u0443\u0441\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0432\u0441\u0435] \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 <em>(avadh\u0101nam)</em> \u043D\u0430 \u0421\u0435\u043C\u0435\u043D\u0438, [\u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, &quot;\u043D\u0430 \u0412\u044B\u0441\u0448\u0435\u0439 \u015Aakti, \u0438\u043B\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u043C \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0438, \u044F\u0432\u043B\u044F\u044E\u0449\u0438\u043C\u0441\u044F \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u043C \u0432\u0441\u0435\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F&quot;] <em>(b\u012Bja)</em>||15||</strong></p></blockquote><p>&quot;\u0414\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u043E\u0442\u0434\u0430\u043D\u043E, \u0438\u043B\u0438 \u0443\u0434\u0435\u043B\u0435\u043D\u043E&quot; <em>(kartavyam)</em>, \u044D\u0442\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u043F\u043E\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u043E [\u0432 \u0430\u0444\u043E\u0440\u0438\u0437\u043C \u0434\u043B\u044F \u043F\u043E\u043B\u043D\u043E\u0442\u044B \u0441\u043C\u044B\u0441\u043B\u0430] <em>(iti \u015Be\u1E63a\u1E25)</em> --\u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, &quot;\u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u043E\u0442\u0434\u0430\u043D\u043E, \u0438\u043B\u0438 \u0443\u0434\u0435\u043B\u0435\u043D\u043E \u0421\u0435\u043C\u0435\u043D\u0438&quot;--|</p><p>\u0421\u0435\u043C\u044F <em>(b\u012Bjam)</em> [\u2014 \u044D\u0442\u043E] \u0412\u044B\u0441\u0448\u0430\u044F <em>(par\u0101)</em> \u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 <em>(k\u0101ra\u1E47am)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em> [\u0438] \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(\u0101tm\u0101)</em> [\u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437] Sphuratt\u0101 --\u0441\u0432\u0435\u0440\u043A\u0430\u044E\u0449\u0435\u0433\u043E \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(sphuratt\u0101)</em>|</p><p>\u042D\u0442\u043E <em>(yad)</em> \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E <em>(uktam)</em> \u0432 \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u043F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u043E\u043C M\u1E5Btyujit --\u0442.\u0435. Netratantra-- <em>(\u015Br\u012B-m\u1E5Btyujit-bha\u1E6D\u1E6D\u0101rake)</em>:</p><blockquote><p>&quot;\u041E\u043D\u0430 --\u0412\u044B\u0441\u0448\u0430\u044F \u015Aakti-- <em>(s\u0101)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C\u0438 \u0441\u043F\u043E\u0441\u043E\u0431\u0430\u043C\u0438 [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] <em>(anekadh\u0101)</em>, \u0418\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u043C <em>(yoni\u1E25)</em> \u0432\u0441\u0435\u0445 \u0431\u043E\u0433\u043E\u0432 <em>(sarva-dev\u0101n\u0101m)</em>, \u0430 <em>(ca)</em> \u0442\u0430\u043A\u0436\u0435 <em>(api)</em> \u015Bakti-s, \u0438\u043B\u0438 \u0441\u0438\u043B <em>(\u015Bakt\u012Bn\u0101m)</em>. [\u042D\u0442\u043E\u0442] \u0418\u0441\u0442\u043E\u0447\u043D\u0438\u043A <em>(yoni\u1E25)</em> \u0438\u043C\u0435\u0435\u0442 \u043E\u0433\u043E\u043D\u044C \u0438 \u043B\u0443\u043D\u0443 \u043F\u043E \u0441\u0432\u043E\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435 <em>(agn\u012B-soma-\u0101tmik\u0101)</em><sup>1</sup>. \u0412\u0441\u0435 <em>(sarvam)</em> \u0431\u0435\u0440\u0435\u0442 \u0441\u0432\u043E\u0435 \u043D\u0430\u0447\u0430\u043B\u043E <em>(pravartate)</em> \u0432 \u043D\u0435\u043C --\u0438\u0437 \u0442\u0430\u043A\u043E\u0433\u043E \u0418\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430-- <em>(tasy\u0101\u1E25)</em>, \u0438 \u0442.\u043F. <em>(iti \u0101di)</em>&quot;||<br> [\u0421\u043C. VII, 40 \u0432 Netratantra]</p></blockquote><p>\u0412\u043D\u0438\u043C\u0430\u043D\u0438\u0435 <em>(avadh\u0101nam)</em> [\u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u043E\u0442\u0434\u0430\u043D\u043E, \u0438\u043B\u0438 \u0443\u0434\u0435\u043B\u0435\u043D\u043E] \u0442\u043E\u043C\u0443 <em>(tatra)</em> \u0421\u0435\u043C\u0435\u043D\u0438 <em>(b\u012Bje)</em>, \u0447\u044C\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C <em>(\u0101tmani)</em> [\u0435\u0441\u0442\u044C] \u0412\u044B\u0441\u0448\u0430\u044F <em>(par\u0101)</em> \u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u0430 <em>(\u015Bakti)</em>, \u0442.\u0435. \u0443\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044F <em>(citta-nive\u015Banam)</em> [\u043D\u0430 \u0442\u043E\u043C \u0421\u0435\u043C\u0435\u043D\u0438] \u0434\u043E\u043B\u0436\u043D\u0430 \u0431\u044B\u0442\u044C \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u0430 <em>(k\u0101ryam)</em> \u043C\u043D\u043E\u0433\u043E\u043A\u0440\u0430\u0442\u043D\u043E <em>(bh\u016Byas bh\u016Byas)</em>||15||</p><hr><ol><li>\u041E\u0433\u043E\u043D\u044C \u0438 \u043B\u0443\u043D\u0430 \u0438\u043C\u0435\u044E\u0442 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F \u0432 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u043E\u0442 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0430: \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0437\u043D\u0430\u043D\u0438\u0435 \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435, \u0438 \u0442.\u0434.</li></ol></div><div class="stanza"><a href="#s3.16" id="s3.16" class="num">3.16</a><div class="sans"><p>\u090F\u0935\u0902 \u0939\u093F \u0938\u0924\u094D\u092F\u0938\u094C \u092F\u094B\u0917\u0940\u2014</p><blockquote><p><strong>\u0906\u0938\u0928\u0938\u094D\u0925\u0903 \u0938\u0941\u0916\u0902 \u0939\u094D\u0930\u0926\u0947 \u0928\u093F\u092E\u091C\u094D\u091C\u0924\u093F\u0965\u0967\u096C\u0965</strong></p></blockquote><p>\u0906\u0938\u094D\u092F\u0924\u0947 \u0928\u093F\u0924\u094D\u092F\u092E\u0948\u0915\u093E\u0924\u094D\u092E\u094D\u092F\u0947\u0928 \u0938\u094D\u0925\u0940\u092F\u0924 \u0905\u0938\u094D\u092E\u093F\u0928\u093F\u0924\u094D\u092F\u093E\u0938\u0928\u0902 \u092A\u0930\u0902 \u0936\u093E\u0915\u094D\u0924\u0902 \u092C\u0932\u0902 \u092F\u0938\u094D\u0924\u0924\u094D\u0930 \u0924\u093F\u0937\u094D\u0920\u0924\u093F \u092A\u0930\u093F\u0939\u0943\u0924\u092A\u0930\u093E\u092A\u0930\u0927\u094D\u092F\u093E\u0928\u0927\u093E\u0930\u0923\u093E\u0926\u093F\u0938\u0930\u094D\u0935\u0915\u094D\u0930\u093F\u092F\u093E\u092A\u094D\u0930\u092F\u093E\u0938\u094B \u0928\u093F\u0924\u094D\u092F\u092E\u0928\u094D\u0924\u0930\u094D\u092E\u0941\u0916\u0924\u092F\u093E \u0924\u0926\u0947\u0935 \u092A\u0930\u093E\u092E\u0943\u0936\u0924\u093F \u092F\u0903 \u0938 \u0938\u0941\u0916\u092E\u0928\u093E\u092F\u093E\u0938\u0924\u092F\u093E \u0939\u094D\u0930\u0926\u0947 \u0935\u093F\u0936\u094D\u0935\u092A\u094D\u0930\u0935\u093E\u0939\u092A\u094D\u0930\u0938\u0930\u0939\u0947\u0924\u094C \u0938\u094D\u0935\u091A\u094D\u091B\u094B\u091A\u094D\u091B\u0932\u0924\u094D\u0924\u093E\u0926\u093F\u092F\u094B\u0917\u093F\u0928\u093F \u092A\u0930\u093E\u092E\u0943\u0924\u0938\u092E\u0941\u0926\u094D\u0930\u0947 \u0928\u093F\u092E\u091C\u094D\u091C\u0924\u093F \u0926\u0947\u0939\u093E\u0926\u093F\u0938\u0919\u094D\u0915\u094B\u091A\u0938\u0902\u0938\u094D\u0915\u093E\u0930\u092C\u094D\u0930\u094B\u0921\u0928\u0947\u0928 \u0924\u0928\u094D\u092E\u092F\u0940\u092D\u0935\u0924\u093F\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u092E\u0943\u0924\u094D\u092F\u0941\u091C\u093F\u0926\u094D\u092D\u091F\u094D\u091F\u093E\u0930\u0915 \u090F\u0935</p><blockquote><p>\u0928\u094B\u0930\u094D\u0927\u094D\u0935\u0947 \u0927\u094D\u092F\u093E\u0928\u0902 \u092A\u094D\u0930\u092F\u0941\u091E\u094D\u091C\u0940\u0924 \u0928\u093E\u0927\u0938\u094D\u0924\u093E\u0928\u094D\u0928 \u091A \u092E\u0927\u094D\u092F\u0924\u0903\u0964<br> \u0928\u093E\u0917\u094D\u0930\u0924\u0903 \u092A\u0943\u0937\u094D\u0920\u0924\u0903 \u0915\u093F\u091E\u094D\u091A\u093F\u0928\u094D\u0928 \u092A\u093E\u0930\u094D\u0936\u094D\u0935\u094B\u0930\u0941\u092D\u092F\u094B\u0930\u092A\u093F\u0965<br> \u0928\u093E\u0928\u094D\u0924\u0903\u0936\u0930\u0940\u0930\u0938\u0902\u0938\u094D\u0925\u093E\u0928\u0947 \u0928 \u092C\u093E\u0939\u094D\u092F\u0947 \u092D\u093E\u0935\u092F\u0947\u0924\u094D\u0915\u094D\u0935\u091A\u093F\u0924\u094D\u0964<br> \u0928\u093E\u0915\u093E\u0936\u0947 \u092C\u0928\u094D\u0927\u092F\u0947\u0932\u094D\u0932\u0915\u094D\u0937\u094D\u092F\u0902 \u0928\u093E\u0927\u094B \u0926\u0943\u0937\u094D\u091F\u093F\u0902 \u0928\u093F\u0935\u0947\u0936\u092F\u0947\u0924\u094D\u0965<br> \u0928 \u091A\u093E\u0915\u094D\u0937\u094D\u0923\u094B\u0930\u094D\u092E\u0940\u0932\u0928\u0902 \u0915\u093F\u091E\u094D\u091A\u093F\u0928\u094D\u0928 \u0915\u093F\u091E\u094D\u091A\u093F\u0926\u094D\u0926\u0943\u0937\u094D\u091F\u093F\u092C\u0928\u094D\u0927\u0928\u092E\u094D\u0964<br> \u0905\u0935\u0932\u092E\u094D\u092C\u0902 \u0928\u093F\u0930\u093E\u0932\u092E\u094D\u092C\u0902 \u0938\u093E\u0932\u092E\u094D\u092C\u0902 \u0928 \u091A \u092D\u093E\u0935\u092F\u0947\u0924\u094D\u0965<br> \u0928\u0947\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u093E\u0923\u093F \u0928 \u092D\u0942\u0924\u093E\u0928\u093F \u0936\u092C\u094D\u0926\u0938\u094D\u092A\u0930\u094D\u0936\u0930\u0938\u093E\u0926\u093F \u092F\u0924\u094D\u0964<br> \u0938\u0930\u094D\u0935\u0902 \u0924\u094D\u092F\u0915\u094D\u0924\u094D\u0935\u093E \u0938\u092E\u093E\u0927\u093F\u0938\u094D\u0925\u0903 \u0915\u0947\u0935\u0932\u0902 \u0924\u0928\u094D\u092E\u092F\u094B \u092D\u0935\u0947\u0924\u094D\u0965<br> \u0938\u093E\u0935\u0938\u094D\u0925\u093E \u092A\u0930\u092E\u093E \u092A\u094D\u0930\u094B\u0915\u094D\u0924\u093E \u092A\u0930\u0938\u094D\u092F \u092A\u0930\u092E\u093E\u0924\u094D\u092E\u0928\u0903\u0964<br> \u0928\u093F\u0930\u093E\u092D\u093E\u0938\u0902 \u092A\u0926\u0902 \u0924\u0924\u094D\u0924\u0941 \u0924\u0924\u094D\u092A\u094D\u0930\u093E\u092A\u094D\u092F \u0935\u093F\u0928\u093F\u0935\u0930\u094D\u0924\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u0967\u096C\u0965</p></div><hr><div class="trans"><p>Eva\u1E41 hi satyasau yog\u012B\u2014</p><blockquote><p><strong>\u0100sanastha\u1E25 sukha\u1E41 hrade nimajjati||16||</strong></p></blockquote><p>\u0100syate nityamaik\u0101tmyena sth\u012Byata asminity\u0101sana\u1E41 para\u1E41 \u015B\u0101kta\u1E41 bala\u1E41 yastatra ti\u1E63\u1E6Dhati parih\u1E5Btapar\u0101paradhy\u0101nadh\u0101ra\u1E47\u0101disarvakriy\u0101pray\u0101so nityamantarmukhatay\u0101 tadeva par\u0101m\u1E5B\u015Bati ya\u1E25 sa sukhaman\u0101y\u0101satay\u0101 hrade vi\u015Bvaprav\u0101haprasarahetau svacchocchalatt\u0101diyogini par\u0101m\u1E5Btasamudre nimajjati deh\u0101disa\u1E45kocasa\u1E41sk\u0101rabro\u1E0Danena tanmay\u012Bbhavati| Yadukta\u1E41 \u015Br\u012Bm\u1E5Btyujidbha\u1E6D\u1E6D\u0101raka eva</p><blockquote><p>Nordhve dhy\u0101na\u1E41 prayu\xF1j\u012Bta n\u0101dhast\u0101nna ca madhyata\u1E25|<br> N\u0101grata\u1E25 p\u1E5B\u1E63\u1E6Dhata\u1E25 ki\xF1cinna p\u0101r\u015Bvorubhayorapi||<br> N\u0101nta\u1E25\u015Bar\u012Brasa\u1E41sth\u0101ne na b\u0101hye bh\u0101vayetkvacit|<br> N\u0101k\u0101\u015Be bandhayellak\u1E63ya\u1E41 n\u0101dho d\u1E5B\u1E63\u1E6Di\u1E41 nive\u015Bayet||<br> Na c\u0101k\u1E63\u1E47orm\u012Blana\u1E41 ki\xF1cinna ki\xF1cidd\u1E5B\u1E63\u1E6Dibandhanam|<br> Avalamba\u1E41 nir\u0101lamba\u1E41 s\u0101lamba\u1E41 na ca bh\u0101vayet||<br> Nendriy\u0101\u1E47i na bh\u016Bt\u0101ni \u015Babdaspar\u015Baras\u0101di yat|<br> Sarva\u1E41 tyaktv\u0101 sam\u0101dhistha\u1E25 kevala\u1E41 tanmayo bhavet||<br> S\u0101vasth\u0101 param\u0101 prokt\u0101 parasya param\u0101tmana\u1E25|<br> Nir\u0101bh\u0101sa\u1E41 pada\u1E41 tattu tatpr\u0101pya vinivartate||</p></blockquote><p>iti||16||</p></div><hr><p>\u0414\u043E\u0431\u0438\u0432\u0448\u0438\u0439\u0441\u044F [\u044D\u0442\u043E\u0433\u043E] <em>(sati)</em> \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam hi)</em>, \u0442\u043E\u0442 <em>(asau)</em> Yog\u012B <em>(yog\u012B)</em>\u2014</p><blockquote><p><strong>\u0423\u043A\u043E\u0440\u0435\u043D\u0435\u043D\u043D\u044B\u0439 <em>(stha\u1E25)</em> \u0432 \u0441\u0438\u043B\u0435 \u0412\u044B\u0441\u0448\u0435\u0439 \u015Aakti [\u0438\u043B\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u043C \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0438, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F &quot;\u0441\u0438\u0434\u0435\u043D\u044C\u0435\u043C&quot; \u0434\u043B\u044F \u043D\u0435\u0433\u043E] <em>(\u0101sana)</em>, [\u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u044B\u0439 Yog\u012B] \u0441 \u043B\u0435\u0433\u043A\u043E\u0441\u0442\u044C\u044E <em>(sukham)</em> \u043F\u043E\u0433\u0440\u0443\u0436\u0430\u0435\u0442\u0441\u044F <em>(nimajjati)</em> \u0432 \u041E\u0437\u0435\u0440\u043E [\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0438 \u0431\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(hrade)</em>||16||</strong></p></blockquote><p>\u0100sana, \u0438\u043B\u0438 \u0441\u0438\u0434\u0435\u043D\u044C\u0435 \u2014 \u044D\u0442\u043E <em>(iti \u0101sanam)</em> [\u0442\u043E], \u043D\u0430 \u0447\u0435\u043C \u043E\u043D --Yog\u012B-- \u0432\u043E\u0441\u0441\u0435\u0434\u0430\u0435\u0442 <em>(\u0101syate)</em>, \u0442.\u0435 \u0442\u043E, \u043D\u0430 \u0447\u0435\u043C \u043E\u043D \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 <em>(sth\u012Byate asmin)</em> \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E <em>(nityam)</em> \u0441 [\u0447\u0443\u0432\u0441\u0442\u0432\u043E\u043C] \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430, \u0438\u043B\u0438 \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(aik\u0101tmyena)</em>. [\u0417\u0434\u0435\u0441\u044C \u0100sana, \u0438\u043B\u0438 \u0441\u0438\u0434\u0435\u043D\u044C\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0441\u0438\u043B\u0443 <em>(balam)</em> \u0412\u044B\u0441\u0448\u0435\u0439 \u015Aakti <em>(param \u015B\u0101ktam)</em>. \u041E\u043D <em>(sa\u1E25)</em>, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 <em>(ti\u1E63\u1E6Dhati)</em> \u0442\u0430\u043C <em>(tatra)</em> [\u0438] \u043A\u0442\u043E <em>(ya\u1E25)</em> \u0432\u0441\u0435\u0433\u0434\u0430 <em>(nityam)</em> \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 <em>(par\u0101m\u1E5B\u015Bati)</em> \u0442\u0443 \u0441\u0430\u043C\u0443\u044E [\u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C] --\u0442.\u0435. \u0441\u0438\u043B\u0443 \u0412\u044B\u0441\u0448\u0435\u0439 \u015Aakti-- <em>(tad eva)</em> \u0438\u043D\u0442\u0440\u043E\u0441\u043F\u0435\u043A\u0442\u0438\u0432\u043D\u044B\u043C \u0441\u043F\u043E\u0441\u043E\u0431\u043E\u043C <em>(antar-mukhatay\u0101)</em>, \u043F\u043E\u0441\u043B\u0435 \u043E\u0442\u043A\u0430\u0437\u0430 \u043E\u0442 <em>(parih\u1E5Bta)</em> \u0432\u0441\u0435\u0445 <em>(sarva)</em> \u0443\u0441\u0438\u043B\u0438\u0439 <em>(pray\u0101sa\u1E25)</em>, [\u0432\u043A\u043B\u044E\u0447\u0430\u044E\u0449\u0438\u0445 \u0432 \u0441\u0435\u0431\u044F] \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(kriy\u0101)</em>, [\u0442\u0430\u043A\u0443\u044E \u043A\u0430\u043A], \u0432\u044B\u0441\u0448\u0443\u044E --\u0442.\u0435. \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0443\u044E\u0441\u044F \u043A \u015A\u0101ktop\u0101ya-- <em>(para)</em> [\u0438] \u043D\u0438\u0437\u0448\u0443\u044E --\u0442.\u0435. \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0443\u044E\u0441\u044F \u043A \u0100\u1E47avop\u0101ya-- <em>(apara)</em> \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u044E <em>(dhy\u0101na)</em>, \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044E <em>(dh\u0101ra\u1E47\u0101)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u043B\u0435\u0433\u043A\u043E <em>(sukham)</em> \u2014\u0431\u0435\u0437 \u0432\u0441\u044F\u043A\u0438\u0445 \u0443\u0441\u0438\u043B\u0438\u0439 <em>(an\u0101y\u0101satay\u0101)</em>\u2014 \u043F\u043E\u0433\u0440\u0443\u0436\u0430\u0435\u0442\u0441\u044F <em>(nimajjati)</em> \u0432 \u041E\u0437\u0435\u0440\u043E <em>(hrade)</em> \u2014\u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0441\u044C <em>(bhavati)</em> \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C <em>(may\u012B)</em> \u0441 \u044D\u0442\u0438\u043C [\u041E\u0437\u0435\u0440\u043E\u043C] <em>(tad)</em> \u043F\u0443\u0442\u0435\u043C \u0443\u043C\u0435\u043D\u044C\u0448\u0435\u043D\u0438\u044F <em>(bro\u1E0Danena)</em> \u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u044B\u0445 \u0432\u043F\u0435\u0447\u0430\u0442\u043B\u0435\u043D\u0438\u0439 <em>(sa\u1E41sk\u0101ra)</em> \u043E\u0442 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F <em>(sa\u1E45koca)</em> [\u0432 \u0444\u043E\u0440\u043C\u0435] \u0442\u0435\u043B\u0430 <em>(deha)</em> \u0438 \u0442.\u043F. <em>(\u0101di)</em>\u2014. [\u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043E\u043D \u043F\u043E\u0433\u0440\u0443\u0436\u0430\u0435\u0442\u0441\u044F] \u0432 \u0432\u044B\u0441\u0448\u0438\u0439 \u043E\u043A\u0435\u0430\u043D \u0431\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u0438\u044F <em>(para-am\u1E5Bta-samudre)</em>, \u043E\u0431\u043B\u0430\u0434\u0430\u044E\u0449\u0438\u0439 [\u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A\u043E\u0439] <em>(yogini)</em> \u043F\u0440\u043E\u0437\u0440\u0430\u0447\u043D\u043E\u0441\u0442\u0438 <em>(svaccha)</em>, \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F <em>(ucchalatt\u0101)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em> [\u0438] \u044F\u0432\u043B\u044F\u044E\u0449\u0438\u0439\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 <em>(hetau)</em> \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u044F <em>(prasara)</em> \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u0433\u043E \u0432\u0441\u0435\u043E\u0431\u044A\u0435\u043C\u043B\u044E\u0449\u0435\u0433\u043E \u043F\u043E\u0442\u043E\u043A\u0430 <em>(vi\u015Bva-prav\u0101ha)</em>|</p><p>\u0422\u043E \u0436\u0435 <em>(yad)</em> [\u0431\u044B\u043B\u043E] \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0441\u0430\u043C\u043E\u043C \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C M\u1E5Btyujit --Netratantra-- <em>(\u015Br\u012B-m\u1E5Btyujit-bha\u1E6D\u1E6D\u0101rake eva)</em>:</p><blockquote><p>&quot;\u041C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u044F <em>(dhy\u0101nam)</em> \u043D\u0435 \u0434\u043E\u043B\u0436\u043D\u0430 \u0431\u044B\u0442\u044C \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0430 <em>(prayu\xF1j\u012Bta)</em> \u043D\u0438 <em>(na)</em> \u0432\u0432\u0435\u0440\u0445 <em>(\u016Brdhve)</em>, \u043D\u0438 <em>(na)</em> \u0432\u043D\u0438\u0437 <em>(adhast\u0101t)</em>, \u043D\u0438 <em>(na ca)</em> \u043A \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 <em>(madhyata\u1E25)</em>, \u043D\u0438 <em>(na)</em> \u043F\u0435\u0440\u0435\u0434 \u0441\u043E\u0431\u043E\u0439 <em>(agratas)</em> [\u0438\u043B\u0438] \u043D\u0430\u0437\u0430\u0434 <em>(p\u1E5B\u1E63\u1E6Dhatas)</em>, \u043D\u0438 <em>(na)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u043D\u0430 \u0447\u0442\u043E-\u0442\u043E <em>(ki\xF1cid)</em>, [\u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u043D\u043E\u0435] \u0441 \u043E\u0431\u0435\u0438\u0445 \u0441\u0442\u043E\u0440\u043E\u043D <em>(p\u0101r\u015Bvo\u1E25 ubhayo\u1E25)</em><sup>1</sup>.</p></blockquote><blockquote><p>\u041D\u0435 <em>(na)</em> \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C <em>(bh\u0101vayet)</em> \u0447\u0442\u043E-\u0442\u043E <em>(kvacid)</em>, \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u043D\u043E\u0435 <em>(sa\u1E41sth\u0101ne)</em> \u043A\u0430\u043A \u0432\u043D\u0443\u0442\u0440\u0438 <em>(antar)</em> \u0442\u0435\u043B\u0430 <em>(\u015Bar\u012Bra)</em>, \u0442\u0430\u043A \u0438 *(na)*\u0432\u043E\u0432\u043D\u0435 <em>(b\u0101hye)</em>. \u041D\u0435 <em>(na)</em> \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0444\u0438\u043A\u0441\u0438\u0440\u043E\u0432\u0430\u0442\u044C [\u0441\u0432\u043E\u0439] \u0432\u0437\u043E\u0440 <em>(bandhayet lak\u1E63yam)</em> \u043D\u0430 \u043D\u0435\u0431\u0435 <em>(\u0101k\u0101\u015Be)</em>, \u0438 \u043D\u0435 <em>(na)</em> \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u0442\u044C <em>(nive\u015Bayet)</em> [\u0441\u0432\u043E\u0439] \u0432\u0437\u0433\u043B\u044F\u0434 <em>(d\u1E5B\u1E63\u1E6Di)</em> \u043D\u0430 [\u0447\u0442\u043E-\u043B\u0438\u0431\u043E] \u0432\u043D\u0438\u0437\u0443 <em>(adhas)</em><sup>2</sup>.</p></blockquote><blockquote><p>\u041D\u0438\u043A\u0430\u043A\u043E\u0433\u043E <em>(na ki\xF1cid)</em> \u0437\u0430\u043A\u0440\u044B\u0442\u0438\u044F <em>(m\u012Blanam)</em> [\u0441\u0432\u043E\u0438\u0445] \u0433\u043B\u0430\u0437 <em>(c\u0101k\u1E63\u1E47o\u1E25)</em> [\u0438] \u043D\u0438\u043A\u0430\u043A\u043E\u0439 <em>(na ki\xF1cid)</em> \u0444\u0438\u043A\u0441\u0430\u0446\u0438\u0438 <em>(bandhanam)</em> [\u0441\u0432\u043E\u0435\u0433\u043E] \u0432\u0437\u0433\u043B\u044F\u0434\u0430 <em>(d\u1E5B\u1E63\u1E6Di)</em> [\u0432\u043E\u043E\u0431\u0449\u0435] --\u0447\u0442\u043E \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442, \u0447\u0442\u043E \u0432\u0430\u0448\u0438 \u043D\u0435\u043C\u0438\u0433\u0430\u044E\u0449\u0438\u0435 \u0433\u043B\u0430\u0437\u0430 \u0448\u0438\u0440\u043E\u043A\u043E \u043E\u0442\u043A\u0440\u044B\u0442\u044B--; \u043D\u0435 <em>(na ca)</em> \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C <em>(bh\u0101vayet)</em> \u0447\u0442\u043E-\u043B\u0438\u0431\u043E \u043D\u0438 \u043A\u0430\u043A \u043E\u043F\u043E\u0440\u0443 <em>(avalambam)</em>, [\u043D\u0438] \u043A\u0430\u043A \u043E\u0442\u0440\u0438\u0446\u0430\u043D\u0438\u0435 \u043E\u043F\u043E\u0440\u044B <em>(nir\u0101lamba)</em>, [\u043D\u0438] \u043A\u0430\u043A \u043E\u043F\u043E\u0440\u0443 \u0441\u043D\u043E\u0432\u0430 \u0438 \u0441\u043D\u043E\u0432\u0430 <em>(s\u0101lambam)</em><sup>3</sup>.</p></blockquote><blockquote><p>\u041D\u0435 [\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C] <em>(na)</em> \u043D\u0438 Indriya-s --\u0421\u0438\u043B\u044B \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u0442\u0430\u0442\u0442\u0432\u044B \u0441 17 \u043F\u043E 26-- <em>(indriy\u0101\u1E47i)</em>, \u043D\u0438 <em>(na)</em> Mah\u0101bh\u016Bta-s --\u0413\u0440\u0443\u0431\u044B\u0435 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B, \u0442\u0430\u0442\u0442\u0432\u044B \u0441 32 \u043F\u043E 36-- <em>(bh\u016Bt\u0101ni)</em>, [\u043D\u0438] \u0442\u043E, \u0447\u0442\u043E <em>(yad)</em> [\u0441\u043E\u0441\u0442\u043E\u0438\u0442] \u0438\u0437 \u0417\u0432\u0443\u043A\u0430-\u043A\u0430\u043A-\u0442\u0430\u043A\u043E\u0432\u043E\u0433\u043E <em>(\u015Babda)</em>, \u041A\u0430\u0441\u0430\u043D\u0438\u044F-\u043A\u0430\u043A-\u0442\u0430\u043A\u043E\u0432\u043E\u0433\u043E <em>(spar\u015Ba)</em>, \u0412\u043A\u0443\u0441\u0430-\u043A\u0430\u043A-\u0442\u0430\u043A\u043E\u0432\u043E\u0433\u043E <em>(rasa)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em> --\u0442.\u0435. \u043F\u044F\u0442\u044C \u0422\u0430\u043D\u043C\u0430\u0442\u0440 (Tanm\u0101tra-s), \u0438\u043B\u0438 \u0442\u043E\u043D\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432, \u0442\u0430\u0442\u0442\u0432\u044B \u0441 27 \u043F\u043E 31--. \u041E\u0442\u043A\u0430\u0437\u0430\u0432\u0448\u0438\u0441\u044C \u043E\u0442 <em>(tyaktv\u0101)</em> \u0432\u0441\u0435\u0433\u043E [\u044D\u0442\u043E\u0433\u043E] <em>(sarvam)</em>, \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0432\u0448\u0438\u0441\u044C <em>(stha\u1E25)</em> \u0432 Sam\u0101dhi <em>(sam\u0101dhi)</em>, \u0432\u044B \u0434\u043E\u043B\u0436\u043D\u044B \u0441\u0442\u0430\u0442\u044C <em>(kevalam... bhavet)</em> \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C <em>(maya\u1E25)</em> \u0441 \u042D\u0442\u0438\u043C --\u0442.\u0435. \u0441 \u0412\u044B\u0441\u0448\u0435\u0439 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E-- <em>(tad)</em><sup>4</sup>.</p></blockquote><blockquote><p>\u042D\u0442\u043E <em>(s\u0101)</em> \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(prokt\u0101)</em> \u0432\u044B\u0441\u0448\u0438\u043C <em>(param\u0101)</em> \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C <em>(avasth\u0101)</em> \u0412\u0441\u0435\u0432\u044B\u0448\u043D\u0435\u0433\u043E <em>(parasya)</em>, \u0442.\u0435. \u0412\u044B\u0441\u0448\u0435\u0439 \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u0438 <em>(parama-\u0101tmana\u1E25)</em>. \u042D\u0442\u043E <em>(tad)</em> \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(padam)</em> \u043B\u0438\u0448\u0435\u043D\u043E [\u0432\u043D\u0435\u0448\u043D\u0438\u0445] \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0439 <em>(nis-\u0101bh\u0101sam)</em> --\u0442.\u0435. \u043D\u0438\u0447\u0442\u043E \u0432 \u044D\u0442\u043E\u043C \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u043D\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F, \u0438\u043B\u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u043C--. \u0414\u043E\u0431\u0438\u0432\u0448\u0438\u0441\u044C <em>(pr\u0101pya)</em> \u042D\u0442\u043E\u0433\u043E --\u0438\u043B\u0438 \u043E\u0431\u0440\u0435\u0442\u044F \u044D\u0442\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435-- <em>(tad)</em>, \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F [\u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u044F] <em>(vinivartate... iti)</em><sup>5</sup>&quot;||<br> [\u0421\u043C. VIII, 41-45 \u0432 Netratantra]</p></blockquote><p>||16||</p><hr><ol><li>\u041C\u0443\u0434\u0440\u0435\u0446 K\u1E63emar\u0101ja \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 \u0432\u0441\u0435 \u044D\u0442\u0438 \u0441\u0442\u0440\u043E\u0444\u044B Netratantra \u0432 \u0441\u0432\u043E\u0435\u0439 Netroddyota (\u0441\u0432\u043E\u0435\u043C \u043D\u0430\u0443\u0447\u043D\u043E\u043C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430 Netratantra), \u043D\u043E \u0442\u0435\u043C\u0430 \u0442\u0430\u043A\u0430\u044F \u0434\u043B\u0438\u043D\u043D\u0430\u044F \u0438 \u0441\u043B\u043E\u0436\u043D\u0430\u044F, \u0447\u0442\u043E \u044F \u043D\u0435 \u043C\u043E\u0433\u0443 \u0437\u0434\u0435\u0441\u044C \u044D\u0442\u043E \u043F\u0440\u043E\u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C &quot;\u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043D\u0430 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435&quot; \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u043E\u0441\u0442\u044B\u0435 \u043F\u043E\u044F\u0441\u043D\u0435\u043D\u0438\u044F (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0447\u0442\u043E\u0431\u044B \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0438\u0437 \u043F\u044F\u0442\u0438 \u0441\u0442\u0440\u043E\u0444 \u044D\u0442\u043E\u0433\u043E \u0446\u0438\u043A\u043B\u0430, \u043E\u043D \u0446\u0438\u0442\u0438\u0440\u0443\u0435\u0442 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0441\u0442\u0440\u043E\u0444 \u0438\u0437 Vij\xF1\u0101nabhairavatantra, \u043A\u0430\u0436\u0434\u0430\u044F \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043F\u043E\u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043B\u0430 \u0431\u044B \u043C\u043E\u0438\u0445 &quot;\u043E\u0441\u043E\u0431\u044B\u0445&quot; \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0439 \u043F\u043E\u043C\u0438\u043C\u043E \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430). \u0427\u0442\u043E\u0431\u044B \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C \u0431\u043E\u043B\u0435\u0435 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u0443\u044E \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044E \u043E\u0431 \u044D\u0442\u043E\u0439 \u0441\u043B\u043E\u0436\u043D\u043E\u0439 \u0438 \u0434\u043B\u0438\u043D\u043D\u043E\u0439 \u0442\u0435\u043C\u0435, \u043E\u0431\u0440\u0430\u0449\u0430\u0439\u0442\u0435\u0441\u044C \u0432\u0441\u0435\u0433\u0434\u0430 \u043A \u0440\u0430\u0437\u0434\u0435\u043B\u0443 &quot;\u041F\u0438\u0441\u0430\u043D\u0438\u044F (\u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435)/\u015Aivas\u016Btravimar\u015Bin\u012B&quot; \u0432 \u0440\u0430\u0437\u0434\u0435\u043B\u0435 \u0422\u0440\u0438\u043A\u0430. \u0422\u0430\u043A \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435, \u0432 \u044D\u0442\u043E\u0439 \u043F\u0435\u0440\u0432\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u0435 (41), \u043C\u0443\u0434\u0440\u0435\u0446 \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435: &quot; \u090A\u0930\u094D\u0927\u094D\u0935\u0947 \u0926\u094D\u0935\u093E\u0926\u0936\u093E\u0928\u094D\u0924\u0947\u093D\u0927\u0903 \u0915\u0928\u094D\u0926\u093E\u0926\u094C \u092E\u0927\u094D\u092F\u0947 \u0939\u0943\u0926\u093E\u0926\u093E\u0935\u0917\u094D\u0930\u0924\u0903 \u092A\u0943\u0937\u094D\u0920\u0924\u0903 \u092A\u093E\u0930\u094D\u0936\u094D\u0935\u092F\u094B\u0938\u094D\u0924\u0924\u094D\u092A\u0941\u0930\u0941\u0937\u0938\u0926\u094D\u092F\u094B\u091C\u093E\u0924\u093E\u0926\u093F\u0930\u0942\u092A\u092E\u094D\u0964&quot; - &quot;\u016Ardhve dv\u0101da\u015B\u0101nte&#39;dha\u1E25 kand\u0101dau madhye h\u1E5Bd\u0101d\u0101vagrata\u1E25 p\u1E5B\u1E63\u1E6Dhata\u1E25 p\u0101r\u015Bvayostatpuru\u1E63asadyoj\u0101t\u0101dir\u016Bpam|&quot; - &quot;\u0412\u0432\u0435\u0440\u0445 \u2014\u043F\u043E \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044E \u043A [\u016Brdhva] dv\u0101da\u015B\u0101nta [\u0438\u043B\u0438 \u0442\u043E\u0447\u043A\u0435 \u043A\u043E\u043D\u0446\u0430 12-\u0442\u0438 \u043F\u0430\u043B\u044C\u0446\u0435\u0432 \u043E\u0442 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0430 \u043C\u0435\u0436\u0434\u0443 \u0431\u0440\u043E\u0432\u044F\u043C\u0438 \u0434\u043E Brahmarandhra \u043D\u0430 \u043C\u0430\u043A\u0443\u0448\u043A\u0435 \u0433\u043E\u043B\u043E\u0432\u044B]\u2014; \u0432\u043D\u0438\u0437 \u2014\u043A Kanda --\u044F\u0439\u0446\u0435\u043F\u043E\u0434\u043E\u0431\u043D\u043E\u043C\u0443 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0443 \u0432\u0441\u0435\u0445 \u043A\u0430\u043D\u0430\u043B\u043E\u0432 \u0432 \u0442\u043E\u043D\u043A\u043E\u043C \u0442\u0435\u043B\u0435--, \u0438 \u0442.\u043F.\u2014; \u043A \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 \u2014\u0432 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0438 \u043A \u0441\u0435\u0440\u0434\u0446\u0443, \u0438 \u0442.\u0434.\u2014, \u0432\u043F\u0435\u0440\u0435\u0434, \u043D\u0430\u0437\u0430\u0434, \u043A [\u0447\u0435\u043C\u0443-\u0442\u043E \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u043D\u043E\u043C\u0443] \u043F\u043E \u043E\u0431\u0435 \u0441\u0442\u043E\u0440\u043E\u043D\u044B, \u043A \u0442\u043E\u043C\u0443, \u0447\u044C\u0435\u0439 \u0444\u043E\u0440\u043C\u043E\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F Tatpuru\u1E63a, Sadyoj\u0101ta, \u0438 \u0442.\u0434. --\u0442.\u0435. Tatpuru\u1E63a, Sadyoj\u0101ta, V\u0101madeva \u0438 Aghora--\u2014&quot;.</li></ol><p>\u0418\u043C\u0435\u0435\u0442\u0441\u044F \u043F\u044F\u0442\u044C \u0430\u0441\u043F\u0435\u043A\u0442\u043E\u0432, \u0438\u043B\u0438 \u0433\u043E\u043B\u043E\u0432 \u015Aiva: (1) Tatpuru\u1E63a (\u043B\u0438\u0446\u043E\u043C \u043D\u0430 \u0432\u043E\u0441\u0442\u043E\u043A --\u0432\u043F\u0435\u0440\u0435\u0434--, \u0438 \u0441\u0438\u043C\u0432\u043E\u043B\u0438\u0437\u0438\u0440\u0443\u044E\u0449\u0438\u0439 \u015Aakti, \u0432\u0442\u043E\u0440\u0443\u044E \u0442\u0430\u0442\u0442\u0432\u0443, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044E), (2) Sadyoj\u0101ta (\u043B\u0438\u0446\u043E\u043C \u043D\u0430 \u0437\u0430\u043F\u0430\u0434 --\u043D\u0430\u0437\u0430\u0434--, \u0438 \u0441\u0438\u043C\u0432\u043E\u043B\u0438\u0437\u0438\u0440\u0443\u044E\u0449\u0438\u0439 Sad\u0101\u015Biva, \u0442\u0440\u0435\u0442\u044C\u044E \u0442\u0430\u0442\u0442\u0432\u0443, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044E), (3) V\u0101madeva (\u043B\u0438\u0446\u043E\u043C \u043D\u0430 \u0441\u0435\u0432\u0435\u0440 --\u043D\u0430\u043B\u0435\u0432\u043E--, \u0438 \u0441\u0438\u043C\u0432\u043E\u043B\u0438\u0437\u0438\u0440\u0443\u044E\u0449\u0438\u0439 \u012A\u015Bvara, \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0443\u044E \u0442\u0430\u0442\u0442\u0432\u0443, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044E), (4) Aghora (\u043B\u0438\u0446\u043E\u043C \u043D\u0430 \u044E\u0433 --\u043D\u0430\u043F\u0440\u0430\u0432\u043E--, \u0438 \u0441\u0438\u043C\u0432\u043E\u043B\u0438\u0437\u0438\u0440\u0443\u044E\u0449\u0438\u0439 Sadvidy\u0101, \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0443\u044E \u0442\u0430\u0442\u0442\u0432\u0443, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044E) \u2014\u044D\u0442\u0438 \u043F\u0435\u0440\u0432\u044B\u0435 \u0447\u0435\u0442\u044B\u0440\u0435 \u0430\u0441\u043F\u0435\u043A\u0442\u0430, \u0438\u043B\u0438 \u0433\u043E\u043B\u043E\u0432\u044B \u0431\u044B\u043B\u0438 \u043E\u0442\u043C\u0435\u0447\u0435\u043D\u044B K\u1E63emar\u0101ja \u043A\u0430\u0441\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438, \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u0439 \u0432\u043F\u0435\u0440\u0435\u0434 (\u043F\u0435\u0440\u0435\u0434 \u0441\u043E\u0431\u043E\u0439), \u043D\u0430\u0437\u0430\u0434 \u0438 \u043A \u0447\u0435\u043C\u0443-\u043B\u0438\u0431\u043E \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u043D\u043E\u043C\u0443 \u0441 \u043E\u0431\u0435\u0438\u0445 \u0441\u0442\u043E\u0440\u043E\u043D (\u0441\u043B\u0435\u0432\u0430 \u0438 \u0441\u043F\u0440\u0430\u0432\u0430)\u2014, \u0438 \u043D\u0430\u043A\u043E\u043D\u0435\u0446, (5) \u012A\u015B\u0101na (\u043E\u0431\u0440\u0430\u0449\u0435\u043D\u043D\u044B\u0439 \u0432\u0432\u0435\u0440\u0445 \u0438 \u0441\u0438\u043C\u0432\u043E\u043B\u0438\u0437\u0438\u0440\u0443\u044E\u0449\u0438\u0439 \u015Aiva, \u043F\u0435\u0440\u0432\u0443\u044E \u0442\u0430\u0442\u0442\u0432\u0443, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044E). \u0411\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E, \u044D\u0442\u0430 \u0442\u0435\u043C\u0430 \u043D\u0430\u043C\u043D\u043E\u0433\u043E \u0441\u043B\u043E\u0436\u043D\u0435\u0435 \u0438 \u043C\u0430\u0441\u0441\u0438\u0432\u043D\u0435\u0435... \u042F \u043B\u0438\u0448\u044C \u0435\u0434\u0432\u0430 \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u0443\u043B\u0441\u044F \u043A \u0435\u0435 \u043F\u043E\u0432\u0435\u0440\u0445\u043D\u043E\u0441\u0442\u0438. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u043F\u0440\u043E\u0441\u0442\u043E \u043F\u043E\u0432\u0435\u0440\u044C\u0442\u0435 \u043C\u043D\u0435, \u043F\u043E\u0436\u0430\u043B\u0443\u0439\u0441\u0442\u0430.</p><ol start="2"><li><p>\u042D\u0442\u043E \u0441\u0442\u0440\u043E\u0444\u0430 VIII, 42 \u0438\u0437 Netratantra. \u0412\u0435\u043B\u0438\u043A\u0438\u0439 K\u1E63emar\u0101ja \u0446\u0438\u0442\u0438\u0440\u0443\u0435\u0442 28<sup>\u0443\u044E</sup> \u0441\u0442\u0440\u043E\u0444\u0443 \u0438\u0437 Vij\xF1\u0101nabhairavatantra, \u0447\u0442\u043E\u0431\u044B \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435 \u0447\u0435\u0433\u043E-\u043B\u0438\u0431\u043E,\u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0435\u0433\u043E\u0441\u044F \u0432\u043D\u0443\u0442\u0440\u0438 \u0442\u0435\u043B\u0430. \u042D\u0442\u0430 \u0441\u0442\u0440\u043E\u0444\u0430 \u0440\u0430\u0437\u044A\u044F\u0441\u043D\u044F\u0435\u0442 \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u044E \u043D\u0430 Ku\u1E47\u1E0Dalin\u012B, \u043F\u043E\u0434\u043D\u0438\u043C\u0430\u044E\u0449\u0443\u044E\u0441\u044F \u0438\u0437 M\u016Bl\u0101dh\u0101ra (\u0447\u0430\u043A\u0440\u0430, \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u043D\u0430\u044F \u0432 \u043A\u043E\u0440\u043D\u0435 \u043F\u043E\u0437\u0432\u043E\u043D\u043E\u0447\u043D\u043E\u0433\u043E \u0441\u0442\u043E\u043B\u0431\u0430) \u0438 \u0434\u0432\u0438\u0436\u0443\u0449\u0443\u044E\u0441\u044F \u043A Brahmarandhra \u043D\u0430 \u043C\u0430\u043A\u0443\u0448\u043A\u0435 \u0433\u043E\u043B\u043E\u0432\u044B. \u0417\u0430\u0442\u0435\u043C, \u043E\u043D \u0446\u0438\u0442\u0438\u0440\u0443\u0435\u0442 \u0441\u0442\u0440\u043E\u0444\u0443 122 \u0438\u0437 \u0442\u043E\u0439 \u0436\u0435 \u043A\u043D\u0438\u0433\u0438, \u0447\u0442\u043E\u0431\u044B \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435 \u0447\u0435\u0433\u043E-\u043B\u0438\u0431\u043E, \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0435\u0433\u043E\u0441\u044F \u0441\u043D\u0430\u0440\u0443\u0436\u0438. \u042D\u0442\u0430 \u0441\u0442\u0440\u043E\u0444\u0430 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044E \u0431\u0435\u0437\u043C\u044B\u0441\u043B\u0438\u044F \u043F\u0440\u0438 \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0438 \u043D\u0430 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u043C \u043E\u0431\u044A\u0435\u043A\u0442\u0435. \u041D\u0430\u043A\u043E\u043D\u0435\u0446, \u0447\u0442\u043E\u0431\u044B \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044E \u043D\u0430 \u043D\u0435\u0431\u0435 \u0438 \u043D\u0430 \u0447\u0435\u043C-\u0442\u043E \u0432\u043D\u0438\u0437\u0443, \u043E\u043D \u043F\u0440\u0438\u0432\u043E\u0434\u0438\u0442 \u0446\u0438\u0442\u0430\u0442\u044B 76 \u0438 115 \u0438\u0437 Vij\xF1\u0101nabhairavatantra, \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E. \u041F\u0435\u0440\u0432\u0430\u044F \u0438\u043C\u0435\u0435\u0442 \u0434\u0435\u043B\u043E \u0441 \u043F\u0440\u043E\u0441\u0442\u044B\u043C \u0444\u0438\u043A\u0441\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435\u043C \u0432\u0437\u0433\u043B\u044F\u0434\u0430 \u043D\u0430 \u0447\u0430\u0441\u0442\u0438 \u043D\u0435\u0431\u0430, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u044F\u044F \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442, \u043A\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u0437\u0430\u0444\u0438\u043A\u0441\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0433\u043B\u0430\u0437\u0430 \u043D\u0430 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 \u0432\u043D\u0443\u0442\u0440\u0438 \u043E\u0447\u0435\u043D\u044C \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u043A\u043E\u043B\u043E\u0434\u0446\u0430, \u0447\u0442\u043E\u0431\u044B \u043C\u043E\u0436\u043D\u043E \u0431\u044B\u043B\u043E \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0438\u0442\u044C \u0443\u043C.</p></li><li><p>\u042D\u0442\u0430 \u0441\u0442\u0440\u043E\u0444\u0430 VIII, 43 \u0438\u0437 Netratantra. K\u1E63emar\u0101ja \u0446\u0438\u0442\u0438\u0440\u0443\u0435\u0442 \u0441\u0442\u0440\u043E\u0444\u0443 88 \u0438\u0437 Vij\xF1\u0101nabhairavatantra, \u0447\u0442\u043E\u0431\u044B \u043E\u043F\u0438\u0441\u0430\u0442\u044C \u0437\u0430\u043A\u0440\u044B\u0442\u0438\u0435 \u0433\u043B\u0430\u0437. \u042D\u0442\u0430 \u0441\u0442\u0440\u043E\u0444\u0430 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044E \u0443\u0436\u0430\u0441\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u044B Bhairava (\u0413\u043E\u0441\u043F\u043E\u0434\u0430 \u015Aiva), \u0441\u043D\u0430\u0447\u0430\u043B\u0430 \u0437\u0430\u043A\u0440\u044B\u0432\u0430\u044F \u0433\u043B\u0430\u0437\u0430 \u0438 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0443\u0436\u0430\u0441\u043D\u0443\u044E \u0442\u044C\u043C\u0443 \u043F\u0435\u0440\u0435\u0434 \u0441\u043E\u0431\u043E\u0439, \u0438 \u0442.\u0434. \u041F\u043E\u0437\u0436\u0435 \u043C\u0443\u0434\u0440\u0435\u0446 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442 \u0441\u0442\u0440\u043E\u0444\u0443 60 \u044D\u0442\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F, \u0447\u0442\u043E\u0431\u044B \u043F\u0440\u0438\u0432\u0435\u0441\u0442\u0438 \u043F\u0440\u0438\u043C\u0435\u0440 \u0444\u0438\u043A\u0441\u0430\u0446\u0438\u0438 \u0432\u0437\u0433\u043B\u044F\u0434\u0430. \u042D\u0442\u0430 \u0441\u0442\u0440\u043E\u0444\u0430 \u0440\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0443\u0435\u0442 \u0441\u043C\u043E\u0442\u0440\u0435\u043D\u0438\u0435 \u043D\u0430 \u043E\u0431\u043B\u0430\u0441\u0442\u044C, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044E\u0442 \u0434\u0435\u0440\u0435\u0432\u044C\u044F, \u043D\u0430 \u0433\u043E\u0440\u0443, \u043D\u0430 \u0441\u0442\u0435\u043D\u0443 \u0438 \u043F\u0440., \u0447\u0442\u043E\u0431\u044B \u0443\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u043A\u043E\u043B\u0435\u0431\u0430\u043D\u0438\u044F \u043F\u0440\u0435\u043A\u0440\u0430\u0442\u0438\u043B\u0438\u0441\u044C.</p></li></ol><p>\u0417\u0430\u0442\u0435\u043C, \u0447\u0442\u043E\u0431\u044B \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0441\u043B\u043E\u0432\u0430 &quot;avalamba&quot; \u043E\u043D \u0433\u043E\u0432\u043E\u0440\u0438\u0442: &quot;\u0905\u0935\u0932\u092E\u094D\u092C\u094D\u092F\u0924 \u0907\u0924\u093F \u0905\u0935\u0932\u092E\u094D\u092C\u094B \u0927\u094D\u092F\u0947\u092F \u0906\u0915\u093E\u0930\u0938\u094D&quot; - &quot;avalambyata iti avalambo dhyeya \u0101k\u0101ras&quot; - &quot;Avalamba, \u0438\u043B\u0438 \u043E\u043F\u043E\u0440\u0430\u2014 \u044D\u0442\u043E \u0444\u043E\u0440\u043C\u0430, [\u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u043C\u0430\u044F] \u043A\u0430\u043A \u043E\u0431\u044A\u0435\u043A\u0442 \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438 \u0434\u043B\u044F \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043D\u0438\u044F \u043D\u0430 \u043D\u0435\u0439 [\u0441\u0432\u043E\u0435\u0433\u043E \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u044F]&quot;. \u041C\u0443\u0434\u0440\u0435\u0446 \u0446\u0438\u0442\u0438\u0440\u0443\u0435\u0442 \u0441\u0442\u0440\u043E\u0444\u0443 62 \u0438\u0437 Vij\xF1\u0101nabhairavatantra, \u0447\u0442\u043E\u0431\u044B \u043F\u0440\u043E\u0438\u043B\u043B\u044E\u0441\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u044D\u0442\u043E. \u042D\u0442\u0430 \u0441\u0442\u0440\u043E\u0444\u0430 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u0443\u044E \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044E \u043D\u0430 \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043A\u0435 \u043C\u0435\u0436\u0434\u0443 \u0434\u0432\u0443\u043C\u044F bh\u0101va-s, \u0438\u043B\u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u043C\u0438 \u0432 \u0432\u0430\u0448\u0435\u043C \u0443\u043C\u0435. \u041A\u043E\u0433\u0434\u0430 \u043F\u0435\u0440\u0432\u044B\u0439 bh\u0101va \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442, \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044C \u0435\u0433\u043E, \u0447\u0442\u043E \u043F\u043E\u0437\u0432\u043E\u043B\u0438\u0442 \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0442\u044C\u0441\u044F \u0432\u0442\u043E\u0440\u043E\u043C\u0443. \u0412 \u044D\u0442\u043E\u043C \u0441\u043C\u044B\u0441\u043B\u0435, \u043F\u0435\u0440\u0432\u044B\u0439 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F &quot;\u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u044B\u0439&quot;, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u0432\u0442\u043E\u0440\u043E\u0439 \u2014 &quot;\u043D\u0435\u0433\u0430\u0442\u0438\u0432\u043D\u044B\u0439&quot;. \u041F\u043E \u043C\u0435\u0440\u0435 \u0442\u043E\u0433\u043E \u043A\u0430\u043A \u0432\u044B \u0442\u0432\u0435\u0440\u0434\u043E \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442\u0435 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044C \u0441\u0432\u043E\u0435 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u043D\u0430 \u043F\u0435\u0440\u0432\u043E\u043C bh\u0101va, \u0432\u044B \u0441\u043A\u043E\u043B\u044C\u0437\u0438\u0442\u0435 \u043A \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043A\u0443 \u043C\u0435\u0436\u0434\u0443 \u0434\u0432\u0443\u043C\u044F bh\u0101va-s (\u043E\u0434\u043D\u0438\u043C \u0432\u043E\u0437\u043D\u0438\u043A\u0448\u0438\u043C \u0438 \u043D\u0438 \u0440\u0430\u0437\u0443 \u043D\u0435 \u0432\u043E\u0437\u043D\u0438\u043A\u0448\u0438\u043C \u0434\u0440\u0443\u0433\u0438\u043C... \u0434\u0430, \u0437\u0432\u0443\u0447\u0438\u0442 \u0431\u0435\u0437\u0443\u043C\u043D\u043E, \u043D\u043E \u044F \u0433\u043E\u0432\u043E\u0440\u044E \u043F\u0440\u0430\u0432\u0434\u0443).</p><p>\u0418 \u043C\u0443\u0434\u0440\u0435\u0446 \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442 &quot;nir\u0101lamba&quot;, \u0446\u0438\u0442\u0438\u0440\u0443\u044F 61<sup>\u0443\u044E</sup> \u0441\u0442\u0440\u043E\u0444\u0443, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044E \u043D\u0430 \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043A\u0435 \u043C\u0435\u0436\u0434\u0443 \u0434\u0432\u0443\u043C\u044F bh\u0101va-s, \u0438\u043B\u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438. \u041E\u0431\u0430 bh\u0101va-s \u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u044B, \u0442.\u0435. \u0438\u043C \u043F\u043E\u0437\u0432\u043E\u043B\u0435\u043D\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0442\u044C, \u043D\u043E \u0432 \u0442\u043E \u0436\u0435 \u0432\u0440\u0435\u043C\u044F \u043E\u043D\u0438 &quot;\u043E\u0442\u0440\u0438\u0446\u0430\u044E\u0442\u0441\u044F/\u043E\u0442\u0432\u0435\u0440\u0433\u0430\u044E\u0442\u0441\u044F&quot; \u0432 \u0442\u043E\u043C \u0441\u043C\u044B\u0441\u043B\u0435, \u0447\u0442\u043E \u0432\u0430\u0448\u0435 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043E \u043D\u0430 \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u043A \u043C\u0435\u0436\u0434\u0443 \u043D\u0438\u043C\u0438. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u044D\u0442\u043E \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F nir\u0101lamba, \u0438\u043B\u0438 \u043E\u0442\u0440\u0438\u0446\u0430\u043D\u0438\u0435 \u043E\u043F\u043E\u0440\u044B, \u0438\u043B\u0438 \u0101lamba.</p><p>\u041D\u0430\u043A\u043E\u043D\u0435\u0446, K\u1E63emar\u0101ja \u0440\u0430\u0437\u044A\u044F\u0441\u043D\u044F\u0435\u0442 &quot;s\u0101lamba&quot; \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C: &quot;\u0938\u0939\u093E\u0932\u092E\u094D\u092C\u0947\u0928 \u0935\u0930\u094D\u0924\u0924\u0947 \u0938\u093E\u0932\u092E\u094D\u092C\u0902 \u0938\u093E\u0915\u093E\u0930\u0902 \u091C\u094D\u091E\u093E\u0928\u092E\u094D&quot; - &quot;sah\u0101lambena vartate s\u0101lamba\u1E41 s\u0101k\u0101ra\u1E41 j\xF1\u0101nam&quot; - &quot;s\u0101lamba [\u2014 \u044D\u0442\u043E] \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u043D\u0430 \u0444\u043E\u0440\u043C\u0435 \u0437\u043D\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 [\u0432 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435] \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u0447\u0435\u0440\u0435\u0437 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u0435 \u0447\u0435\u0433\u043E-\u043B\u0438\u0431\u043E \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u043E\u043F\u043E\u0440\u044B&quot;. \u041F\u043E\u0441\u043B\u0435 \u044D\u0442\u043E\u0433\u043E, \u043E\u043D \u0446\u0438\u0442\u0438\u0440\u0443\u0435\u0442 98<sup>\u0443\u044E</sup> \u0441\u0442\u0440\u043E\u0444\u0443 \u0438\u0437 Vij\xF1\u0101nabhairavatantra, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044E \u043D\u0430 bh\u0101va, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0433\u043E\u0441\u044F \u043A\u0430\u043A \u0436\u0435\u043B\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 \u0437\u043D\u0430\u043D\u0438\u0435 \u0432 \u0443\u043C\u0435. \u042D\u0442\u043E\u0442 bh\u0101va \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u044B\u043C, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0435\u043C\u0443 \u043F\u043E\u0437\u0432\u043E\u043B\u0435\u043D\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u0443\u0442\u044C. \u0417\u0430\u0442\u0435\u043C, \u0435\u0441\u043B\u0438 \u0432\u044B \u0444\u0438\u043A\u0441\u0438\u0440\u0443\u0435\u0442\u0435 \u0441\u0432\u043E\u0435 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u043D\u0430 \u044D\u0442\u043E\u043C, \u0441\u0447\u0438\u0442\u0430\u044F \u044D\u0442\u043E \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u044C\u044E, \u0441\u0438\u044F\u044E\u0449\u0435\u0439 \u043D\u0430\u0440\u0443\u0436\u0443 \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0432\u044B \u0438\u043C\u0435\u0435\u0442\u0435 \u0432\u0438\u0434\u0435\u043D\u0438\u0435 \u044D\u0442\u043E\u0439 \u0441\u0430\u043C\u043E\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u0438. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u043E\u043F\u043E\u0440\u0430, \u0438\u043B\u0438 \u0101valamba \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0443\u0441\u043A\u043E\u043B\u044C\u0437\u0430\u0435\u0442 \u0438 \u0432\u0430\u043C \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u0432\u043E\u0437\u0432\u0440\u0430\u0449\u0430\u0442\u044C \u0435\u0435 \u0441\u043D\u043E\u0432\u0430 \u0438 \u0441\u043D\u043E\u0432\u0430, \u0447\u0442\u043E\u0431\u044B \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0442\u044C \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044E. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u0442\u0430\u043A, \u043A\u0430\u043A \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043E \u0432\u044B\u0448\u0435, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, &quot;... \u043A\u0430\u043A \u043E\u043F\u043E\u0440\u0443 \u0441\u043D\u043E\u0432\u0430 \u0438 \u0441\u043D\u043E\u0432\u0430&quot;. \u0412 \u044D\u0442\u043E\u043C \u0437\u0430\u043A\u043B\u044E\u0447\u0430\u0435\u0442\u0441\u044F \u0440\u0430\u0437\u043D\u0438\u0446\u0430 \u043C\u0435\u0436\u0434\u0443 &quot;avalamba&quot; \u0438 &quot;s\u0101lamba&quot;, \u0442.\u0435. \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u0432 \u043F\u0435\u0440\u0432\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 \u043C\u044B \u0438\u043C\u0435\u0435\u043C \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u0443\u044E \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044E \u043D\u0430 bh\u0101va, \u0438\u043B\u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u0435, \u0432\u043E\u0437\u043D\u0438\u043A\u0448\u0435\u043C \u0432 \u0443\u043C\u0435 (\u0432\u0441\u0435\u0433\u0434\u0430 \u043F\u0440\u0435\u0441\u0435\u043A\u0430\u044F \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u0432\u0442\u043E\u0440\u043E\u0433\u043E bh\u0101va), \u0432\u043E \u0432\u0442\u043E\u0440\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 bh\u0101va \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0442\u0435\u0440\u044F\u0435\u0442\u0441\u044F, \u0438 \u0435\u0433\u043E \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u0432\u043E\u0441\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u0442\u044C, \u0447\u0442\u043E\u0431\u044B \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0442\u044C (\u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044E). \u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E, \u043F\u043E\u0434\u0430\u0432\u043B\u044F\u044E\u0449\u0435\u0435 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u043B\u044E\u0434\u0435\u0439 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442 \u043C\u0435\u0442\u043E\u0434 s\u0101lamba, \u0441\u0438\u0434\u044F \u0432 \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438. \u0414\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u043D\u0430 \u0441\u0435\u0439\u0447\u0430\u0441.</p><ol start="4"><li>\u041C\u043D\u0435 \u043D\u0443\u0436\u043D\u043E \u043F\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 K\u1E63emar\u0101ja \u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0438 Sam\u0101dhi \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435:</li></ol><p>&quot;... \u0938\u092E\u093E\u0927\u093F\u0938\u094D\u0925 \u0907\u0924\u094D\u092F\u0915\u093F\u091E\u094D\u091A\u093F\u091A\u094D\u091A\u093F\u0928\u094D\u0924\u0915\u0924\u094D\u0935\u0947\u0928 \u0938\u094D\u0935\u0938\u094D\u0935\u0930\u0942\u092A\u0935\u093F\u092E\u0930\u094D\u0936\u0928\u092A\u094D\u0930\u0935\u0923\u0938\u094D\u0924\u0928\u094D\u092E\u092F \u0907\u0924\u094D\u092F\u093E\u0928\u0928\u094D\u0926\u092A\u0926\u0938\u0902\u0932\u0940\u0928\u0938\u092E\u0930\u0938\u091C\u094D\u091E\u093E\u0928\u092E\u092F\u0903\u0965\u096A\u096A\u0965&quot; - &quot;... sam\u0101dhistha ityaki\xF1ciccintakatvena svasvar\u016Bpavimar\u015Banaprava\u1E47astanmaya ity\u0101nandapadasa\u1E41l\u012Bnasamarasaj\xF1\u0101namaya\u1E25||44||&quot; - &quot;&#39;... \u0423\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u0439 \u0432 Sam\u0101dhi&#39;, \u0442.\u0435. \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u044B\u0439 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044E \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0438\u0440\u043E\u0434\u044B [\u0438 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E] \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u043D\u044B\u0439 \u0441 \u042D\u0442\u0438\u043C \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043F\u043E\u043B\u043D\u043E\u043C\u0443 \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u044E \u043C\u044B\u0441\u043B\u0435\u0439. [\u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438,] \u043F\u043E\u043B\u043D\u044B\u0439 \u043E\u0434\u043D\u043E\u0440\u043E\u0434\u043D\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F, \u0442\u0435\u0441\u043D\u043E \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0433\u043E \u0441 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C \u0100nanda, \u0438\u043B\u0438 [\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E] \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430||44||&quot;.</p><p>\u042F \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u043B \u0441\u0435\u0440\u044C\u0435\u0437\u043D\u043E \u043F\u0440\u043E\u044F\u0441\u043D\u0438\u0442\u044C \u044D\u0442\u043E \u0441 \u0442\u0435\u043C, \u0447\u0442\u043E\u0431\u044B \u0447\u0438\u0442\u0430\u0442\u0435\u043B\u044C \u043D\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u043B \u0437\u0434\u0435\u0441\u044C Sam\u0101dhi, \u043A\u0430\u043A \u044D\u0442\u043E \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043E \u0443 Pata\xF1jali \u0432 \u0435\u0433\u043E Yogas\u016Btra-s.</p><ol start="5"><li>K\u1E63emar\u0101ja \u043A\u0440\u0430\u0442\u043A\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 VIII, 45 \u0432 \u0441\u0432\u043E\u0435\u0439 Netroddyota:</li></ol><p>&quot;\u0938\u093E\u0902\u0938\u093E\u0930\u093F\u0915\u0940\u0902 \u0938\u094D\u0925\u093F\u0924\u093F\u092E\u0941\u091C\u094D\u091D\u0924\u093F\u0965\u096A\u096B\u0965&quot; - &quot;S\u0101\u1E41s\u0101rik\u012B\u1E41 sthitimujjhati||45||&quot; - &quot;\u0427\u0435\u043B\u043E\u0432\u0435\u043A \u043F\u043E\u043A\u0438\u0434\u0430\u0435\u0442 \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435||45||&quot;.</p></div><div class="stanza"><a href="#s3.17" id="s3.17" class="num">3.17</a><div class="sans"><p>\u0924\u0926\u0947\u0935\u0902 \u0928\u093E\u0921\u0940\u0938\u0902\u0939\u093E\u0930\u093E\u0926\u094D\u092F\u093E\u0923\u0935\u094B\u092A\u093E\u092F\u0915\u094D\u0930\u092E\u093E\u0938\u093E\u0926\u093F\u0924\u092E\u094B\u0939\u091C\u092F\u094B\u0928\u094D\u092E\u091C\u094D\u091C\u091A\u094D\u091B\u0941\u0926\u094D\u0927\u0935\u093F\u0926\u094D\u092F\u093E\u0924\u094D\u092E\u0915\u0936\u093E\u0915\u094D\u0924\u092C\u0932\u093E\u0938\u093E\u0926\u0928\u092A\u094D\u0930\u0915\u0930\u094D\u0937\u093E\u0926\u093E\u0924\u094D\u092E\u0940\u0915\u0943\u0924\u092A\u0930\u093E\u092E\u0943\u0924\u0939\u094D\u0930\u0926\u093E\u0924\u094D\u092E\u0915\u0936\u093E\u092E\u094D\u092D\u0935\u092A\u0926\u094B \u092F\u094B\u0917\u0940\u2014</p><blockquote><p><strong>\u0938\u094D\u0935\u092E\u093E\u0924\u094D\u0930\u093E\u0928\u093F\u0930\u094D\u092E\u093E\u0923\u092E\u093E\u092A\u093E\u0926\u092F\u0924\u093F\u0965\u0967\u096D\u0965</strong></p></blockquote><p>\u0938\u094D\u0935\u0938\u094D\u092F \u091A\u0948\u0924\u0928\u094D\u092F\u0938\u094D\u092F \u0938\u092E\u094D\u092C\u0928\u094D\u0927\u093F\u0928\u0940 \u092E\u093E\u0924\u094D\u0930\u093E \u091A\u093F\u0926\u094D\u0930\u0938\u093E\u0936\u094D\u092F\u093E\u0928\u0924\u093E\u0924\u094D\u092E\u093E\u0902\u0936\u0938\u094D\u0924\u0926\u094D\u0930\u0942\u092A\u0902 \u092F\u0925\u0947\u0937\u094D\u091F\u0935\u0947\u0926\u094D\u092F\u0935\u0947\u0926\u0915\u093E\u0935\u092D\u093E\u0938\u093E\u0924\u094D\u092E\u0915\u0902 \u0928\u093F\u0930\u094D\u092E\u093E\u0923\u092E\u093E\u092A\u093E\u0926\u092F\u0924\u093F \u0928\u093F\u0930\u094D\u092E\u093F\u0924\u0924\u094D\u0935\u0947\u0928 \u0926\u0930\u094D\u0936\u092F\u0924\u093F\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947</p><blockquote><p>\u0924\u0926\u0947\u0935 \u092D\u0935\u0924\u093F \u0938\u094D\u0925\u0942\u0932\u0902 \u0938\u094D\u0925\u0942\u0932\u094B\u092A\u093E\u0927\u093F\u0935\u0936\u093E\u0924\u094D\u092A\u094D\u0930\u093F\u092F\u0947\u0964<br> \u0938\u094D\u0925\u0942\u0932\u0938\u0942\u0915\u094D\u0937\u094D\u092E\u0935\u093F\u092D\u0947\u0926\u0947\u0928 \u0924\u0926\u0947\u0915\u0902 \u0938\u0902\u0935\u094D\u092F\u0935\u0938\u094D\u0925\u093F\u0924\u092E\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u092A\u094D\u0930\u0924\u094D\u092F\u092D\u093F\u091C\u094D\u091E\u093E\u092F\u093E\u092E\u092A\u093F</p><blockquote><p>\u0906\u0924\u094D\u092E\u093E\u0928\u092E\u0924 \u090F\u0935\u093E\u092F\u0902 \u091C\u094D\u091E\u0947\u092F\u0940\u0915\u0941\u0930\u094D\u092F\u093E\u0924\u094D\u092A\u0943\u0925\u0915\u094D\u0938\u094D\u0925\u093F\u0924\u093F\u0964<br> \u091C\u094D\u091E\u0947\u092F\u0902 \u0928 \u0924\u0941...\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0906\u0917\u092E\u0947\u093D\u092A\u093F</p><blockquote><p>\u091C\u0932\u0902 \u0939\u093F\u092E\u0902 \u091A \u092F\u094B \u0935\u0947\u0926 \u0917\u0941\u0930\u0941\u0935\u0915\u094D\u0924\u094D\u0930\u093E\u0917\u092E\u093E\u0924\u094D\u092A\u094D\u0930\u093F\u092F\u0947\u0964<br> \u0928\u093E\u0938\u094D\u0924\u094D\u092F\u0947\u0935 \u0924\u0938\u094D\u092F \u0915\u0930\u094D\u0924\u0935\u094D\u092F\u0902 \u0924\u0938\u094D\u092F\u093E\u092A\u0936\u094D\u091A\u093F\u092E\u091C\u0928\u094D\u092E\u0924\u093E\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928\u0948\u0935\u093E\u0936\u092F\u0947\u0928\u094B\u0915\u094D\u0924\u092E\u094D\u0964 \u090F\u0924\u0926\u0947\u0935</p><blockquote><p>\u0907\u0924\u093F \u0935\u093E \u092F\u0938\u094D\u092F \u0938\u0902\u0935\u093F\u0924\u094D\u0924\u093F\u0903 \u0915\u094D\u0930\u0940\u0921\u093E\u0924\u094D\u0935\u0947\u0928\u093E\u0916\u093F\u0932\u0902 \u091C\u0917\u0924\u094D\u0964<br> \u0938 \u092A\u0936\u094D\u092F\u0928\u094D\u0938\u0924\u0924\u0902 \u092F\u0941\u0915\u094D\u0924\u094B \u091C\u0940\u0935\u0928\u094D\u092E\u0941\u0915\u094D\u0924\u094B \u0928 \u0938\u0902\u0936\u092F\u0903\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928 \u0938\u094D\u092A\u0928\u094D\u0926\u0947 \u092A\u094D\u0930\u0924\u093F\u092A\u093E\u0926\u093F\u0924\u092E\u094D\u0965\u0967\u096D\u0965</p></div><hr><div class="trans"><p>Tadeva\u1E41 n\u0101\u1E0D\u012Bsa\u1E41h\u0101r\u0101dy\u0101\u1E47avop\u0101yakram\u0101s\u0101ditamohajayonmajjacchuddhavidy\u0101tmaka\u015B\u0101ktabal\u0101s\u0101danaprakar\u1E63\u0101d\u0101tm\u012Bk\u1E5Btapar\u0101m\u1E5Btahrad\u0101tmaka\u015B\u0101mbhavapado yog\u012B\u2014</p><blockquote><p><strong>Svam\u0101tr\u0101nirm\u0101\u1E47am\u0101p\u0101dayati||17||</strong></p></blockquote><p>Svasya caitanyasya sambandhin\u012B m\u0101tr\u0101 cidras\u0101\u015By\u0101nat\u0101tm\u0101\u1E41\u015Bastadr\u016Bpa\u1E41 yathe\u1E63\u1E6Davedyavedak\u0101vabh\u0101s\u0101tmaka\u1E41 nirm\u0101\u1E47am\u0101p\u0101dayati nirmitatvena dar\u015Bayati| Yadukta\u1E41 \u015Br\u012Bsvacchande</p><blockquote><p>Tadeva bhavati sth\u016Bla\u1E41 sth\u016Blop\u0101dhiva\u015B\u0101tpriye|<br> Sth\u016Blas\u016Bk\u1E63mavibhedena tadeka\u1E41 sa\u1E41vyavasthitam||</p></blockquote><p>iti| Pratyabhij\xF1\u0101y\u0101mapi</p><blockquote><p>\u0100tm\u0101namata ev\u0101ya\u1E41 j\xF1ey\u012Bkury\u0101tp\u1E5Bthaksthiti|<br> J\xF1eya\u1E41 na tu...||</p></blockquote><p>iti| \u0100game&#39;pi</p><blockquote><p>Jala\u1E41 hima\u1E41 ca yo veda guruvaktr\u0101gam\u0101tpriye|<br> N\u0101styeva tasya kartavya\u1E41 tasy\u0101pa\u015Bcimajanmat\u0101||</p></blockquote><p>ityanenaiv\u0101\u015Bayenoktam| Etadeva</p><blockquote><p>Iti v\u0101 yasya sa\u1E41vitti\u1E25 kr\u012B\u1E0D\u0101tven\u0101khila\u1E41 jagat|<br> Sa pa\u015Byansatata\u1E41 yukto j\u012Bvanmukto na sa\u1E41\u015Baya\u1E25||</p></blockquote><p>ityanena spande pratip\u0101ditam||17||</p></div><hr><p>\u042D\u0442\u043E <em>(tad)</em> [\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E] \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u0435\u0438\u043C\u0443\u0449\u0435\u0441\u0442\u0432\u043E \u0438 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u0441\u0442\u0432\u043E <em>(prakar\u1E63\u0101t)</em>, \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u044B\u0435 <em>(\u0101s\u0101dana)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0441\u0438\u043B\u044B <em>(bala)</em> \u015Aakti <em>(\u015B\u0101kta)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0439 \u0438\u0437 <em>(\u0101tmaka)</em> \u015Auddhavidy\u0101 --\u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F<sup>1</sup>-- <em>(\u015Buddha-vidy\u0101)</em>, \u0432\u043E\u0437\u043D\u0438\u043A\u0448\u0435\u0433\u043E <em>(unmajjat)</em> \u0438\u0437 \u043F\u043E\u043A\u043E\u0440\u0435\u043D\u0438\u044F <em>(jaya)</em> Moha, \u0438\u043B\u0438 \u041D\u0430\u0432\u0430\u0436\u0434\u0435\u043D\u0438\u044F --M\u0101y\u0101-- <em>(moha)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F <em>(\u0101s\u0101dita)</em> \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E <em>(krama)</em> \u043C\u0435\u0442\u043E\u0434\u043E\u0432 <em>(up\u0101ya)</em> \u0432 \u0101\u1E47ava --\u0442.\u0435. \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u0445\u0441\u044F \u043A \u0100\u1E47avop\u0101ya-- <em>(\u0101\u1E47ava)</em>, [\u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A] \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 [\u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438] <em>(sa\u1E41h\u0101ra)</em> \u0432 \u0442\u043E\u043D\u043A\u0438\u0445 \u043A\u0430\u043D\u0430\u043B\u0430\u0445 <em>(n\u0101\u1E0D\u012B)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em> --\u0421\u043C. III, 5--, Yog\u012B <em>(yog\u012B)</em> \u043E\u0432\u043B\u0430\u0434\u0435\u0432\u0430\u0435\u0442 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C <em>(\u0101tm\u012B-k\u1E5Bta... pada\u1E25)</em> \u015Aiva <em>(\u015B\u0101mbhava)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0435\u0441\u0442\u044C [\u043D\u0438\u0447\u0442\u043E \u0438\u043D\u043E\u0435, \u043A\u0430\u043A] <em>(\u0101tmaka)</em> \u041E\u0437\u0435\u0440\u043E <em>(hrada)</em> \u0432\u044B\u0441\u0448\u0435\u0433\u043E <em>(para)</em> \u0431\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u0438\u044F <em>(am\u1E5Bta)</em>\u2014</p><blockquote><p><strong>[\u042D\u0442\u043E\u0442 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u0439 Yog\u012B \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D] \u0441\u043E\u0437\u0434\u0430\u0442\u044C <em>(nirm\u0101\u1E47am \u0101p\u0101dayati)</em> [\u043B\u044E\u0431\u0443\u044E \u0444\u043E\u0440\u043C\u0443, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E] \u043C\u0435\u0440\u0435, \u0438\u043B\u0438 \u0430\u0441\u043F\u0435\u043A\u0442\u0443 \u0441\u043E\u0437\u0438\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F [\u0441\u043B\u0443\u0436\u0430\u0449\u0435\u0433\u043E \u0435\u043C\u0443 &quot;\u0101sana&quot;, \u0438\u043B\u0438 &quot;\u0441\u0438\u0434\u0435\u043D\u044C\u0435\u043C&quot; --\u0441\u043C. 16<sup>\u044B\u0439</sup> \u0430\u0444\u043E\u0440\u0438\u0437\u043C--] <em>(svam\u0101tr\u0101)</em>||17||</strong></p></blockquote><p>[\u0422\u0435\u0440\u043C\u0438\u043D svam\u0101tr\u0101 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u043C\u0435\u0440\u0443 <em>(m\u0101tr\u0101)</em>, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u0443\u044E \u0441 <em>(sambandhin\u012B)</em> \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C <em>(svasya)</em> [\u0441\u043E\u0437\u0438\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u043C] \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(caitanyasya)</em>, [\u043A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F,] \u0441 \u0430\u0441\u043F\u0435\u043A\u0442\u043E\u043C <em>(a\u1E41\u015Ba\u1E25)</em>, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(\u0101tm\u0101)</em> \u043A\u043E\u0430\u0433\u0443\u043B\u044F\u0446\u0438\u044F <em>(\u0101\u015By\u0101nat\u0101)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 <em>(rasa)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em><sup>2</sup>. \u0412 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u043C\u0435\u0440\u043E\u0439 \u044D\u0442\u043E\u0433\u043E [\u0441\u043E\u0437\u0438\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(tad-r\u016Bpam)</em>, [\u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u0439 Yog\u012B] \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u0435\u0442 <em>(\u0101p\u0101dayati)</em> \u043F\u043E\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0443 <em>(nirm\u0101\u1E47am)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0443\u044E \u0438\u0437 <em>(\u0101tmakam)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(avabh\u0101sa)</em> \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0445 --\u0442.\u0435. \u0441\u0443\u0449\u0435\u0441\u0442\u0432-- <em>(vedaka)</em> [\u0438] \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0433\u043E --\u0442.\u0435. \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432-- <em>(vedya)</em> \u043A\u0430\u043A <em>(yath\u0101)</em> [\u043E\u043D] \u043F\u043E\u0436\u0435\u043B\u0430\u0435\u0442 <em>(i\u1E63\u1E6Da)</em>. [\u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438,] \u043E\u043D \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 [\u0432\u0441\u0435 \u044D\u0442\u0438 \u0432\u0435\u0449\u0438] <em>(dar\u015Bayati)</em> \u043F\u0443\u0442\u0435\u043C [\u0438\u0445] \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430\u0446\u0438\u0438 <em>(nirmitatvena)</em>|</p><p>\u042D\u0442\u043E <em>(yad)</em> \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Svacchandatantra <em>(\u015Br\u012B-svacchande)</em>:</p><blockquote><p>&quot;\u041E, \u0414\u043E\u0440\u043E\u0433\u0430\u044F <em>(priye)</em>!, \u0422\u043E\u0442 <em>(tad)</em><sup>3</sup> \u043E\u0434\u0438\u043D <em>(eva)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(bhavati)</em> \u043A\u0430\u043A \u0433\u0440\u0443\u0431\u043E\u0435 <em>(sth\u016Blam)</em> \u0438\u0437-\u0437\u0430 [\u0415\u0433\u043E] \u0436\u0435\u043B\u0430\u043D\u0438\u044F *(va\u015B\u0101t)*\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(up\u0101dhi)</em> \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0433\u0440\u0443\u0431\u044B\u043C <em>(sth\u016Bla)</em>. \u0422\u043E\u0442 <em>(tad)</em> \u043E\u0434\u0438\u043D <em>(ekam)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A <em>(sa\u1E41vyavasthitam)</em> \u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u0438\u0435, \u0438\u043B\u0438 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435 <em>(vibhedena)</em> \u0433\u0440\u0443\u0431\u043E\u0433\u043E <em>(sth\u016Bla)</em> [\u0438] \u0442\u043E\u043D\u043A\u043E\u0433\u043E <em>(s\u016Bk\u1E63ma... iti)</em>&quot;||<br> [\u0421\u043C. IV, 295 \u0432 Svacchandatantra]</p></blockquote><p>\u0412 \u012A\u015Bvarapratyabhij\xF1\u0101 <em>(pratyabhij\xF1\u0101y\u0101m)</em> [\u044D\u0442\u043E] \u0442\u0430\u043A\u0436\u0435 [\u0431\u044B\u043B\u043E \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u043E] <em>(api)</em>:</p><blockquote><p>&quot;\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u0439 \u0441\u0430\u043C\u043E\u0439 [Vimar\u015Ba\u015Bakti --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0441\u0438\u043B\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0433\u043E \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F--] <em>(atas eva)</em>, \u041E\u043D <em>(ayam)</em> \u0434\u0435\u043B\u0430\u0435\u0442 \u0441\u0435\u0431\u044F j\xF1eya, \u0438\u043B\u0438 \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u044B\u043C --\u0442.\u0435. \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u043C-- <em>(\u0101tm\u0101nam... j\xF1ey\u012B-kury\u0101t)</em>. \u041F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435 <em>(j\xF1eyam)</em> \u043D\u0435 <em>(na tu)</em> \u0438\u043C\u0435\u0435\u0442 \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(p\u1E5Bthak-sthiti... iti)</em>. [\u0415\u0441\u043B\u0438 \u0431\u044B [\u041E\u043D] \u0431\u044B\u043B \u0437\u0430\u0432\u0438\u0441\u0438\u043C --\u0431\u0443\u043A\u0432. \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u043C \u0441-- \u043E\u0442 \u044D\u0442\u043E\u0433\u043E [\u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0433\u043E], \u0442\u043E \u0415\u0433\u043E \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u0430\u044F \u0441\u0432\u043E\u0431\u043E\u0434\u0430 \u0431\u044B\u043B\u0430 \u0431\u044B \u043D\u0430\u0440\u0443\u0448\u0435\u043D\u0430]<sup>4</sup>&quot;|<br> [\u0421\u043C. I, 5, 15 \u0432 \u012A\u015Bvarapratyabhij\xF1\u0101]</p></blockquote><p>\u0412 \u0100gama --\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u043C \u041F\u0438\u0441\u0430\u043D\u0438\u0438-- <em>(\u0101game)</em> \u0442\u0430\u043A\u0436\u0435 <em>(api)</em>, \u0441\u043A\u0430\u0437\u0430\u043D\u043E [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435] <em>(uktam)</em> \u0441 \u0442\u0435\u043C \u0436\u0435 \u0441\u0430\u043C\u044B\u043C \u043D\u0430\u043C\u0435\u0440\u0435\u043D\u0438\u0435\u043C <em>(anena eva \u0101\u015Bayena)</em>:</p><blockquote><p>&quot;\u041E, \u0414\u043E\u0440\u043E\u0433\u0430\u044F <em>(priye)</em>!, \u0442\u043E\u0442, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u0437\u043D\u0430\u0435\u0442 <em>(veda)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0438\u0437 <em>(\u0101gam\u0101t)</em> \u0443\u0441\u0442 <em>(vaktra)</em> [\u0435\u0433\u043E] \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0433\u043E \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A\u0430 <em>(guru)</em>, \u0447\u0442\u043E \u0432\u043E\u0434\u0430 <em>(jalam)</em> \u0438 <em>(ca)</em> \u043B\u0435\u0434 <em>(himam)</em> [\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043E\u0434\u043D\u043E\u0439 \u0438 \u0442\u043E\u0439 \u0436\u0435 \u0432\u0435\u0449\u044C\u044E, \u2014 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D]. \u0414\u043B\u044F \u043D\u0435\u0433\u043E <em>(tasya)</em> \u043D\u0435\u0442 \u043D\u0438\u0447\u0435\u0433\u043E, \u0447\u0442\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0441\u0434\u0435\u043B\u0430\u043D\u043E <em>(na asti eva... kartavyam)</em>. \u041E\u043D \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F <em>(tasya)</em> \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0433\u043E \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(apa\u015Bcima-janmat\u0101)</em> --\u0442.\u0435. \u043E\u043D \u043D\u0435 \u0438\u043C\u0435\u0435\u0442 \u043D\u0438 \u0435\u0434\u0438\u043D\u043E\u0433\u043E \u043F\u043E\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0433\u043E \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E, \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0432 \u0446\u0435\u043B\u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0435\u043C\u0443 \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435 \u0442\u0440\u0435\u0431\u0443\u0435\u0442\u0441\u044F Sa\u1E41s\u0101ra, \u0438\u043B\u0438 \u0422\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u044F--&quot;||</p></blockquote><p>\u042D\u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435 [\u0443\u0447\u0435\u043D\u0438\u0435] <em>(etad)</em> \u0431\u044B\u043B\u043E \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u043E <em>(pratip\u0101ditam)</em> \u044D\u0442\u0438\u043C [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u043C] <em>(anena)</em> \u0432 Spandak\u0101rik\u0101-s <em>(spande)</em>:</p><blockquote><p>&quot;\u0418\u043B\u0438 <em>(iti v\u0101)</em> \u0442\u043E\u0442 <em>(sa\u1E25)</em>, \u043A\u0442\u043E \u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442 \u044D\u0442\u0438\u043C <em>(yasya)</em> \u0437\u043D\u0430\u043D\u0438\u0435\u043C, \u0438\u043B\u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(sa\u1E41vitti\u1E25)</em> [\u0438] \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 <em>(satatam)</em> \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 [\u0441 \u0412\u044B\u0441\u0448\u0438\u043C \u042F] <em>(yukta\u1E25)</em>, \u0432\u0438\u0434\u0438\u0442 <em>(pa\u015Byan)</em> \u0432\u0435\u0441\u044C <em>(akhilam)</em> \u043C\u0438\u0440 <em>(jagat)</em>, \u043A\u0430\u043A [\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E] \u0438\u0433\u0440\u0443 <em>(kr\u012B\u1E0D\u0101tvena)</em>. \u041E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C \u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438 <em>(j\u012Bvanmukta\u1E25)</em>, \u043D\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u0438\u0445 <em>(na)</em> \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0439 <em>(sa\u1E41\u015Baya\u1E25... iti)</em> [\u0432 \u044D\u0442\u043E\u043C]&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s II, 5]</p></blockquote><p>||17||</p><hr><ol><li><p>\u042D\u0442\u043E \u0432\u043E\u0432\u0441\u0435 \u043D\u0435 \u043F\u044F\u0442\u0430\u044F \u0442\u0430\u0442\u0442\u0432\u0430, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F (\u0442\u0430\u043A\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430\u044F \u043A\u0430\u043A Sadvidy\u0101). \u0427\u0438\u0441\u0442\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435 \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u2014 \u043D\u0435 \u0447\u0442\u043E \u0438\u043D\u043E\u0435, \u043A\u0430\u043A \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F. II, 10 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0440\u0430\u0437\u043E\u0431\u0440\u0430\u0442\u044C\u0441\u044F \u0441 \u044D\u0442\u0438\u043C.</p></li><li><p>\u0421\u043E\u0437\u0438\u0434\u0430\u043D\u0438\u0435 \u0432 \u0422\u0440\u0438\u043A\u0435 \u043D\u0435 \u043F\u043E\u0445\u043E\u0436\u0435 \u043D\u0430 \u0440\u0430\u0431\u043E\u0442\u0443 \u0440\u0435\u043C\u0435\u0441\u043B\u0435\u043D\u043D\u0438\u043A\u0430, \u0442.\u0435. \u043A\u0430\u043A \u043D\u0435\u0447\u0442\u043E, \u0441\u043E\u0437\u0434\u0430\u043D\u043D\u043E\u0435 \u043A\u0435\u043C-\u0442\u043E, \u043A\u0442\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043B \u0432\u043D\u0435\u0448\u043D\u0438\u0435 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0438 \u043D\u0430\u043A\u043E\u043D\u0435\u0446, \u0441\u043E\u0437\u0434\u0430\u043B \u0447\u0442\u043E-\u0442\u043E, \u043E\u0442\u043B\u0438\u0447\u043D\u043E\u0435 \u043E\u0442 \u043D\u0435\u0433\u043E \u0441\u0430\u043C\u043E\u0433\u043E. \u041D\u0435\u0442. \u0422\u043E\u043B\u044C\u043A\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 Caitanya \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F \u0432\u0441\u0435\u043C \u0438 \u043A\u0430\u0436\u0434\u044B\u043C, \u0442.\u0435. \u041E\u043D\u043E \u043A\u043E\u0430\u0433\u0443\u043B\u0438\u0440\u0443\u0435\u0442, \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0444\u043E\u0440\u043C\u0443 \u0432\u0435\u0449\u0435\u0439 \u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432, \u043D\u0435 \u043F\u0440\u0438\u0431\u0435\u0433\u0430\u044F \u043D\u0438 \u043A \u0447\u0435\u043C\u0443 \u0434\u0440\u0443\u0433\u043E\u043C\u0443, \u043A\u0440\u043E\u043C\u0435 \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u0442\u0435\u0440\u043C\u0438\u043D &quot;\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435&quot; \u0431\u043E\u043B\u0435\u0435 \u0443\u043C\u0435\u0441\u0442\u0435\u043D, \u0438\u043B\u0438 \u043F\u0440\u0430\u0432\u0438\u043B\u0435\u043D, \u0447\u0435\u043C &quot;\u0441\u043E\u0437\u0438\u0434\u0430\u043D\u0438\u0435&quot;\u0432 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u0422\u0440\u0438\u043A\u0438.</p></li><li><p>\u0412 \u0441\u0432\u043E\u0435\u0439 Svacchandoddyota, K\u1E63emar\u0101ja \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u0443\u0435\u0442 &quot;\u0422\u043E\u0442&quot; \u043A\u0430\u043A &quot; \u092E\u0939\u093E\u092A\u094D\u0930\u0915\u093E\u0936\u093E\u0924\u094D\u092E\u093E \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u0928\u093E\u0925\u0903&quot; - &quot;Mah\u0101prak\u0101\u015B\u0101tm\u0101 \u015Br\u012Bsvatantran\u0101tha\u1E25&quot; - &quot;\u0414\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u044B\u0439 \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u2014 \u0412\u0435\u043B\u0438\u043A\u0438\u0439 \u0421\u0432\u0435\u0442&quot;. \u0422\u0430\u043A \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435, \u041E\u043D \u2014 \u043D\u0438\u043A\u0442\u043E \u0438\u043D\u043E\u0439, \u043A\u0430\u043A Caitanya, \u0438\u043B\u0438 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0432 \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u0435.</p></li><li><p>\u042F \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u043B \u043F\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438 \u0432\u0441\u044E \u0441\u0442\u0440\u043E\u0444\u0443, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C \u043F\u043E\u043B\u043D\u043E\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435. \u041E\u0441\u0442\u0430\u0432\u0448\u0430\u044F\u0441\u044F \u0447\u0430\u0441\u0442\u044C, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0431\u044B\u043B\u0430 \u043E\u0442\u0431\u0440\u043E\u0448\u0435\u043D\u0430 \u0438 \u043E\u0442\u043C\u0435\u0447\u0435\u043D\u0430 \u043C\u043D\u043E\u0433\u043E\u0442\u043E\u0447\u0438\u0435\u043C, \u044D\u0442\u043E: &quot; \u0924\u0926\u094C\u0928\u094D\u092E\u094D\u092F\u094D\u0916\u094D\u092F\u093E\u0924\u094D\u0916\u0923\u094D\u0921\u094D\u092F\u0947\u0924\u093E\u0938\u094D\u092F \u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u0924\u093E\u0965\u0967\u096B\u0965 &quot; - &quot;tadaunmykhy\u0101tkha\u1E47\u1E0Dyet\u0101sya svatantrat\u0101||15||&quot;. \u042D\u0442\u043E\u0442 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043F\u0440\u0438\u0432\u043E\u0434\u0438\u0442\u0441\u044F \u0432 \u0441\u0430\u043C\u043E\u043C \u0442\u0435\u043A\u0441\u0442\u0435 \u0432\u044B\u0448\u0435. \u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, \u044F \u0434\u043E\u0431\u0430\u0432\u0438\u043B \u0432 \u043C\u043E\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u0442\u0435\u0440\u043C\u0438\u043D &quot;Vimar\u015Ba\u015Bakti&quot;. \u041F\u043E\u0447\u0435\u043C\u0443? \u041F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0434\u043E \u0442\u043E\u0433\u043E, \u043A\u0430\u043A \u0437\u043D\u0430\u043C\u0435\u043D\u0438\u0442\u044B\u0439 \u043C\u0443\u0434\u0440\u0435\u0446 Abhinavagupta (\u0413\u0443\u0440\u0443 \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0438) \u043F\u0440\u043E\u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043B \u044D\u0442\u0443 \u0441\u0442\u0440\u043E\u0444\u0443 (\u0444\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438, \u043E\u043D \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E \u043F\u0440\u043E\u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043B \u0441\u0442\u0440\u043E\u0444\u044B 15 \u0438 16) \u0432 \u0441\u0432\u043E\u0435\u0439 \u012A\u015Bvarapratyabhij\xF1\u0101vimar\u015Bin\u012B (\u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u043D\u0430\u0443\u0447\u043D\u044B\u0439 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 \u043D\u0430 \u012A\u015Bvarapratyabhij\xF1\u0101 \u0423\u0442\u043F\u0430\u043B\u0430\u0434\u0435\u0432\u044B), \u043E\u043D \u0432\u044B\u0434\u0432\u0438\u043D\u0443\u043B \u0432\u043E\u0437\u0440\u0430\u0436\u0435\u043D\u0438\u0435, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u0435\u0442\u0441\u044F \u0442\u0435\u0440\u043C\u0438\u043D Vimar\u015Ba\u015Bakti. \u0417\u0430\u0442\u0435\u043C, \u0441\u0442\u0440\u043E\u0444\u044B 15 \u0438 16, \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u0440\u0430\u0441\u0441\u0435\u0438\u0432\u0430\u044E\u0442 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F, \u0432\u044B\u0434\u0432\u0438\u043D\u0443\u0442\u044B\u0435 \u0438\u043C. \u042D\u0442\u0438 \u0430\u0432\u0442\u043E\u0440\u044B (\u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A, Abhinavagupta, K\u1E63emar\u0101ja, \u0438 \u0434\u0440.) \u043E\u0431\u044B\u0447\u043D\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442 \u043C\u0435\u0442\u043E\u0434 \u0432\u044B\u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F \u0432\u043E\u0437\u0440\u0430\u0436\u0435\u043D\u0438\u0439, \u0447\u0442\u043E\u0431\u044B \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0438\u0445 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u0431\u043E\u043B\u0435\u0435 \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u044B\u043C\u0438 \u0438 \u0434\u0438\u0434\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u043C\u0438 (\u0434\u0438\u0434\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u043C\u0438 \u0434\u043B\u044F \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0445 \u0443\u0447\u0435\u043D\u044B\u0445, \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E, \u0445\u0430-\u0445\u0430!). \u041E\u041A, \u0442\u0435\u043F\u0435\u0440\u044C \u0432\u0441\u0435 \u043F\u043E\u043D\u044F\u0442\u043D\u043E. \u041F\u0440\u043E\u0441\u0442\u043E \u0434\u043E\u0432\u0435\u0440\u044F\u0439 \u043C\u043D\u0435, \u0447\u0438\u0442\u0430\u0442\u0435\u043B\u044C, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432 \u0446\u0435\u043B\u043E\u043C, \u044F \u0447\u0438\u0442\u0430\u044E \u043C\u043D\u043E\u0433\u043E &quot;\u0431\u0435\u0437\u0443\u043C\u043D\u043E \u0434\u043B\u0438\u043D\u043D\u044B\u0445&quot; \u043F\u0438\u0441\u0430\u043D\u0438\u0439 \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E, \u043F\u043E\u043A\u0430 \u043F\u0435\u0440\u0435\u0432\u043E\u0436\u0443 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0435. \u0418\u043D\u043E\u0433\u0434\u0430 \u044F \u043D\u0435 \u043C\u043E\u0433\u0443 \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C \u0432\u0441\u0435 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E, \u0432\u044B \u0437\u043D\u0430\u0435\u0442\u0435, \u0438\u043D\u0430\u0447\u0435 \u044D\u0442\u043E\u0442 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043F\u0440\u0435\u0432\u0440\u0430\u0442\u0438\u0442\u0441\u044F \u0432 \u0446\u0435\u043B\u0443\u044E \u044D\u043D\u0446\u0438\u043A\u043B\u043E\u043F\u0435\u0434\u0438\u044E.</p></li></ol></div><div class="stanza"><a href="#s3.18" id="s3.18" class="num">3.18</a><div class="sans"><p>\u0928 \u091A\u0948\u0935\u0902 \u0938\u094D\u0935\u0936\u0915\u094D\u0924\u093F\u0928\u093F\u0930\u094D\u092E\u093F\u0924\u092D\u0942\u0924\u092D\u093E\u0935\u0936\u0930\u0940\u0930\u0935\u0924\u094B\u093D\u0938\u094D\u092F \u091C\u0928\u094D\u092E\u093E\u0926\u093F\u092C\u0928\u094D\u0927\u0903 \u0915\u0936\u094D\u091A\u093F\u0926\u093F\u0924\u094D\u092F\u093E\u0939\u2014</p><blockquote><p><strong>\u0935\u093F\u0926\u094D\u092F\u093E\u0935\u093F\u0928\u093E\u0936\u0947 \u091C\u0928\u094D\u092E\u0935\u093F\u0928\u093E\u0936\u0903\u0965\u0967\u096E\u0965</strong></p></blockquote><p>\u092A\u094D\u0930\u094B\u0915\u094D\u0924\u093E\u092F\u093E\u0903 \u0938\u0939\u091C\u0935\u093F\u0926\u094D\u092F\u093E\u092F\u093E \u0905\u0935\u093F\u0928\u093E\u0936\u0947 \u0938\u0924\u0924\u094B\u0928\u094D\u092E\u0917\u094D\u0928\u0924\u092F\u093E \u0938\u094D\u092B\u0941\u0930\u0923\u0947 \u091C\u0928\u094D\u092E\u0928\u094B\u093D\u091C\u094D\u091E\u093E\u0928\u0938\u0939\u0915\u093E\u0930\u093F\u0915\u0930\u094D\u092E\u0939\u0947\u0924\u0941\u0915\u0938\u094D\u092F \u0926\u0941\u0903\u0916\u092E\u092F\u0938\u094D\u092F \u0926\u0947\u0939\u0947\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u093E\u0926\u093F\u0938\u092E\u0941\u0926\u093E\u092F\u0938\u094D\u092F \u0928\u093E\u0936\u094B \u0935\u093F\u0927\u094D\u0935\u0902\u0938\u0903 \u0938\u092E\u094D\u092A\u0928\u094D\u0928 \u090F\u0935\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0915\u0923\u094D\u0920\u094D\u092F\u093E\u092E\u094D</p><blockquote><p>\u0938\u092A\u094D\u0930\u092A\u091E\u094D\u091A\u0902 \u092A\u0930\u093F\u0924\u094D\u092F\u091C\u094D\u092F \u0939\u0947\u092F\u094B\u092A\u093E\u0926\u0947\u092F\u0932\u0915\u094D\u0937\u0923\u092E\u094D\u0964<br> \u0924\u0943\u0923\u093E\u0926\u093F\u0915\u0902 \u0924\u0925\u093E \u092A\u0930\u094D\u0923\u0902 \u092A\u093E\u0937\u093E\u0923\u0902 \u0938\u091A\u0930\u093E\u091A\u0930\u092E\u094D\u0965<br> \u0936\u093F\u0935\u093E\u0926\u094D\u092F\u0935\u0928\u093F\u092A\u0930\u094D\u092F\u0928\u094D\u0924\u0902 \u092D\u093E\u0935\u093E\u092D\u093E\u0935\u094B\u092A\u092C\u0943\u0902\u0939\u093F\u0924\u092E\u094D\u0964<br> \u0938\u0930\u094D\u0935\u0902 \u0936\u093F\u0935\u092E\u092F\u0902 \u0927\u094D\u092F\u093E\u0924\u094D\u0935\u093E \u092D\u0942\u092F\u094B \u091C\u0928\u094D\u092E \u0928 \u092A\u094D\u0930\u093E\u092A\u094D\u0928\u0941\u092F\u093E\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947</p><blockquote><p>\u0938\u0941\u0928\u093F\u0930\u094D\u0935\u093E\u0923\u0902 \u092A\u0930\u0902 \u0936\u0941\u0926\u094D\u0927\u0902 \u0917\u0941\u0930\u0941\u092A\u093E\u0930\u092E\u094D\u092A\u0930\u093E\u0917\u0924\u092E\u094D\u0964<br> \u0924\u0926\u094D\u0935\u093F\u0926\u093F\u0924\u094D\u0935\u093E \u0935\u093F\u092E\u0941\u091A\u094D\u092F\u0947\u0924 \u0917\u0924\u094D\u0935\u093E \u092D\u0942\u092F\u094B \u0928 \u091C\u093E\u092F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u092E\u0943\u0924\u094D\u092F\u0941\u091C\u093F\u0924\u094D\u092F\u092A\u093F</p><blockquote><p>\u0924\u0924\u094D\u0924\u094D\u0935\u0924\u094D\u0930\u092F\u0935\u093F\u0928\u093F\u0930\u094D\u092E\u0941\u0915\u094D\u0924\u0902 \u0936\u093E\u0936\u094D\u0935\u0924\u0902 \u0924\u094D\u0935\u091A\u0932\u0902 \u0927\u094D\u0930\u0941\u0935\u092E\u094D\u0964<br> \u0926\u093F\u0935\u094D\u092F\u0947\u0928 \u092F\u094B\u0917\u092E\u093E\u0930\u094D\u0917\u0947\u0923 \u0926\u0943\u0937\u094D\u091F\u094D\u0935\u093E \u092D\u0942\u092F\u094B \u0928 \u091C\u093E\u092F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u0967\u096E\u0965</p></div><hr><div class="trans"><p>Na caiva\u1E41 sva\u015Baktinirmitabh\u016Btabh\u0101va\u015Bar\u012Bravato&#39;sya janm\u0101dibandha\u1E25 ka\u015Bcidity\u0101ha\u2014</p><blockquote><p><strong>Vidy\u0101vin\u0101\u015Be janmavin\u0101\u015Ba\u1E25||18||</strong></p></blockquote><p>Prokt\u0101y\u0101\u1E25 sahajavidy\u0101y\u0101 avin\u0101\u015Be satatonmagnatay\u0101 sphura\u1E47e janmano&#39;j\xF1\u0101nasahak\u0101rikarmahetukasya du\u1E25khamayasya dehendriy\u0101disamud\u0101yasya n\u0101\u015Bo vidhva\u1E41sa\u1E25 sampanna eva| Yadukta\u1E41 \u015Br\u012Bka\u1E47\u1E6Dhy\u0101m</p><blockquote><p>Saprapa\xF1ca\u1E41 parityajya heyop\u0101deyalak\u1E63a\u1E47am|<br> T\u1E5B\u1E47\u0101dika\u1E41 tath\u0101 par\u1E47a\u1E41 p\u0101\u1E63\u0101\u1E47a\u1E41 sacar\u0101caram||<br> \u015Aiv\u0101dyavaniparyanta\u1E41 bh\u0101v\u0101bh\u0101vopab\u1E5B\u1E41hitam|<br> Sarva\u1E41 \u015Bivamaya\u1E41 dhy\u0101tv\u0101 bh\u016Byo janma na pr\u0101pnuy\u0101t||</p></blockquote><p>iti| \u015Ar\u012Bsvacchande</p><blockquote><p>Sunirv\u0101\u1E47a\u1E41 para\u1E41 \u015Buddha\u1E41 gurup\u0101rampar\u0101gatam|<br> Tadviditv\u0101 vimucyeta gatv\u0101 bh\u016Byo na j\u0101yate||</p></blockquote><p>iti| \u015Ar\u012Bm\u1E5Btyujityapi</p><blockquote><p>Tattvatrayavinirmukta\u1E41 \u015B\u0101\u015Bvata\u1E41 tvacala\u1E41 dhruvam|<br> Divyena yogam\u0101rge\u1E47a d\u1E5B\u1E63\u1E6Dv\u0101 bh\u016Byo na j\u0101yate||</p></blockquote><p>iti||18||</p></div><hr><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(na ca... ka\u015Bcid)</em> \u0440\u0430\u0431\u0441\u0442\u0432\u043E <em>(bandha\u1E25)</em> [\u0432 \u0444\u043E\u0440\u043C\u0435] \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(janma)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u0434\u043B\u044F \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u043B \u0442\u0435\u043B\u043E <em>(\u015Bar\u012Bravata\u1E25)</em>, \u0441\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0435 <em>(nirmita)</em> \u0438\u0437 \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva)</em> \u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u044B <em>(\u015Bakti)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 --\u0442.\u0435. \u0442\u0435\u043B\u043E-- \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 bh\u016Bta-s --\u0442.\u0435. Mah\u0101bh\u016Bta-s, \u0438\u043B\u0438 \u0433\u0440\u0443\u0431\u044B\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 (tattva-s 32 to 36)-- <em>(bh\u016Bta)</em> [\u0438] bh\u0101va-s --\u0442.\u0435. Tanm\u0101tra-s, \u0438\u043B\u0438 \u0422\u043E\u043D\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 (\u0442\u0430\u0442\u0442\u0432\u044B \u0441 27 \u043F\u043E 31), \u044D\u043C\u043E\u0446\u0438\u0439 \u0438 \u0442.\u0434.-- <em>(bh\u0101va)</em>. [\u0410\u0432\u0442\u043E\u0440 \u015Aivas\u016Btra-s, \u0442.\u0435. \u015Aiva,] \u0441\u043A\u0430\u0437\u0430\u043B \u0442\u0430\u043A <em>(iti \u0101ha)</em>\u2014</p><blockquote><p><strong>\u0414\u043E \u0442\u0435\u0445 \u043F\u043E\u0440 \u043F\u043E\u043A\u0430 Sahajavidy\u0101, \u0438\u043B\u0438 \u015Auddhavidy\u0101, [\u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435, \u0438\u043B\u0438 \u0427\u0438\u0441\u0442\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435] <em>(vidy\u0101)</em> \u043D\u0435 \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 <em>(avin\u0101\u015Be)</em>, [\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0434\u0440\u0443\u0433\u043E\u0433\u043E] \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(janma)</em> \u0443\u0442\u0440\u0430\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F [\u0434\u043B\u044F \u044D\u0442\u043E\u0433\u043E \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u043E\u0433\u043E Yog\u012B] <em>(vin\u0101\u015Ba\u1E25)</em>||18||</strong></p></blockquote><p>\u0414\u043E \u0442\u0435\u0445 \u043F\u043E\u0440 \u043F\u043E\u043A\u0430 \u043D\u0435 \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 <em>(avin\u0101\u015Be)</em> \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0435 <em>(prokt\u0101y\u0101\u1E25)</em> \u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435 <em>(sahajavidy\u0101y\u0101\u1E25)</em>, \u0442.\u0435. \u043F\u043E\u043A\u0430 \u043E\u043D\u043E \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0442\u044C\u0441\u044F <em>(sphura\u1E47e)</em> \u043A\u0430\u043A \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0430\u044F \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(unmagnatay\u0101)</em>, \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(n\u0101\u015Ba\u1E25)</em>, [\u0438\u043B\u0438] \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435 <em>(vidhva\u1E41sa\u1E25)</em> [\u0434\u0440\u0443\u0433\u043E\u0433\u043E] \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(janmana\u1E25)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u0438\u0437 \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u0438 <em>(samud\u0101yasya)</em> \u0442\u0435\u043B\u0430 <em>(deha)</em>, \u0447\u0443\u0432\u0441\u0442\u0432 <em>(indriya)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u043F\u043E\u043B\u043D\u043E\u0433\u043E <em>(mayasya)</em> \u0431\u043E\u043B\u0438 <em>(du\u1E25kha)</em>, [\u0438] \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u043E\u0433\u043E <em>(hetukasya)</em> [\u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438] \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F\u043C\u0438 <em>(karma)</em> \u0432\u043E \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0438 \u0441 <em>(sahak\u0101ri)</em> \u041D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435\u043C, [\u0438\u043B\u0438 M\u0101y\u0101 \u0438 \u0435\u0435 \u043F\u043E\u0442\u043E\u043C\u0441\u0442\u0432\u043E\u043C] <em>(aj\xF1\u0101na)</em>, \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(sampanna\u1E25)</em> \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(eva)</em><sup>1</sup>|</p><p>\u042D\u0442\u043E <em>(yad)</em> \u0441\u0444\u043E\u0440\u043C\u0443\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Ka\u1E47\u1E6Dh\u012B <em>(\u015Br\u012B-ka\u1E47\u1E6Dhy\u0101m)</em>:</p><blockquote><p>&quot;\u041E\u0441\u0442\u0430\u0432\u0438\u0432 <em>(parityajya)</em> [\u043C\u0438\u0440] \u0441 [\u0435\u0433\u043E] \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u0430\u043C\u0438 <em>(sa-prapa\xF1cam)</em>, \u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0438\u043C\u0438\u0441\u044F \u043A\u0430\u043A <em>(lak\u1E63a\u1E47am)</em> \u0447\u0442\u043E-\u043B\u0438\u0431\u043E \u0436\u0435\u043B\u0430\u0435\u043C\u043E\u0435 <em>(up\u0101deya)</em> [\u0438\u043B\u0438] \u043E\u0442\u0432\u0435\u0440\u0433\u0430\u0435\u043C\u043E\u0435 <em>(heya)</em>, \u0438 \u0442\u0430\u043A\u0436\u0435 <em>(tath\u0101)</em> [\u043A\u0430\u043A] \u0442\u0440\u0430\u0432\u0438\u043D\u043A\u0430 <em>(t\u1E5B\u1E47a)</em> \u0438 \u043A\u0430\u043A <em>(\u0101dikam)</em>, \u043B\u0438\u0441\u0442 <em>(par\u1E47am)</em>, \u043A\u0430\u043C\u0435\u043D\u044C <em>(p\u0101\u1E63\u0101\u1E47am)</em>, \u043D\u0430\u0440\u044F\u0434\u0443 \u0441 <em>(sa)</em> \u043F\u043E\u0434\u0432\u0438\u0436\u043D\u044B\u043C\u0438 \u0438 \u043D\u0435\u043F\u043E\u0434\u0432\u0438\u0436\u043D\u044B\u043C\u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430\u043C\u0438 <em>(cara-acaram)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>(\u0101di)</em> \u015Aiva --\u0442\u0430\u0442\u0442\u0432\u044B, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 1-- <em>(\u015Biva)</em> [\u0438] \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F <em>(paryantam)</em> \u0437\u0435\u043C\u043B\u0435\u0439 --\u0442\u0430\u0442\u0442\u0432\u043E\u0439, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0435\u0439 36-- <em>(avani)</em>, \u0441\u043E\u043F\u0440\u043E\u0432\u043E\u0436\u0434\u0430\u0435\u043C\u044B\u043C\u0438 <em>(upab\u1E5B\u1E41hitam)</em> \u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u044B\u043C\u0438 \u0438 \u043D\u0435\u0433\u0430\u0442\u0438\u0432\u043D\u044B\u043C\u0438 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044F\u043C\u0438 <em>(bh\u0101va-abh\u0101va)</em>; [\u0438] \u043F\u043E\u0441\u043B\u0435 \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438 <em>(dhy\u0101tv\u0101)</em> \u043D\u0430 \u0432\u0441\u0435\u043C <em>(sarvam)</em>, \u043A\u0430\u043A \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C <em>(mayam)</em> \u0428\u0438\u0432\u0435 <em>(\u015Biva)</em>, \u043E\u043D \u043D\u0435 \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442 <em>(na pr\u0101pnuy\u0101t)</em> \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(janma)</em> \u0441\u043D\u043E\u0432\u0430 <em>(bh\u016Byas... iti)</em>&quot;||</p></blockquote><p>[\u0418] \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Svacchandatantra <em>(\u015Br\u012B-svacchande)</em>:</p><blockquote><p>&quot;\u041F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u043D\u043E\u0435 <em>(su)</em> \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 <em>(nirv\u0101\u1E47am)</em>, \u043F\u0440\u0438\u0445\u043E\u0434\u044F\u0449\u0435\u0435 \u043E\u0442 <em>(\u0101gatam)</em> \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 <em>(p\u0101rampara)</em> \u0434\u0443\u0445\u043E\u0432\u043D\u044B\u0445 \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A\u043E\u0432 <em>(guru)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043D\u0435\u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E <em>(param)</em> \u0447\u0438\u0441\u0442\u044B\u043C <em>(\u015Buddham)</em>. \u041E\u0431\u043B\u0430\u0434\u0430\u044F \u0437\u043D\u0430\u043D\u0438\u0435\u043C \u044D\u0442\u043E\u0433\u043E [\u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F] --\u0442.\u0435. \u0438\u0441\u043F\u044B\u0442\u0430\u0432 \u044D\u0442\u043E-- <em>(tad-viditv\u0101)</em> \u043E\u043D \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C [\u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438] <em>(vimucyeta)</em><sup>2</sup></p></blockquote><p>, [\u0438] \u043F\u043E\u0441\u043B\u0435 \u0441\u043C\u0435\u0440\u0442\u0438 <em>(gatv\u0101)</em> \u043E\u043D \u043D\u0435 \u0440\u043E\u0434\u0438\u0442\u0441\u044F <em>(na j\u0101yate)</em> \u0432\u043D\u043E\u0432\u044C <em>(bh\u016Byas... iti)</em><sup>3</sup>&quot;| [\u0421\u043C. IV, 240-241 \u0432 Svacchandatantra]</p><p>[\u042D\u0442\u043E] \u0442\u0430\u043A\u0436\u0435 [\u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E] <em>(api)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C M\u1E5Btyujit --Netratantra-- <em>(\u015Br\u012B-m\u1E5Btyujiti)</em>:</p><blockquote><p>&quot;\u041F\u0440\u043E\u0439\u0434\u044F <em>(d\u1E5B\u1E63\u1E6Dv\u0101)</em>, \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C <em>(divyena)</em> \u043F\u0443\u0442\u0435\u043C <em>(m\u0101rge\u1E47a)</em> \u0419\u043E\u0433\u0438 <em>(yoga)</em>, \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0439 <em>(vinirmuktam)</em> \u043E\u0442 \u0442\u0440\u0435\u0445 \u0442\u0430\u0442\u0442\u0432, \u0438\u043B\u0438 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u0432 <em>(tattva-traya)</em>, \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E \u0432\u0435\u0447\u043D\u044B\u0439 <em>(\u015B\u0101\u015Bvatam tu)</em>, \u043D\u0435\u0438\u0437\u043C\u0435\u043D\u043D\u044B\u0439 <em>(acalam)</em> [\u0438] \u043F\u0435\u0440\u043C\u0430\u043D\u0435\u043D\u0442\u043D\u044B\u0439 <em>(dhruvam)</em>, \u043E\u043D \u043D\u0435 \u0440\u043E\u0436\u0434\u0430\u0435\u0442\u0441\u044F <em>(na j\u0101yate)</em> \u0432\u043D\u043E\u0432\u044C <em>(bh\u016Byas... iti)</em><sup>4</sup>&quot;||<br> [\u0421\u043C. VIII, 26-27 \u0432 Netratantra]</p></blockquote><p>||18||</p><hr><ol><li><p>\u0425\u043E\u0442\u044F \u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0438 \u0427\u0438\u0441\u0442\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0442\u044C\u0441\u044F \u043A\u0430\u043A \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0430\u044F \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C, \u0434\u043B\u044F \u0442\u0430\u043A\u043E\u0433\u043E \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E Yog\u012B \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435 \u0431\u0443\u0434\u0435\u0442 \u0434\u0440\u0443\u0433\u043E\u0433\u043E \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F. \u0420\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 \u0432\u0435\u0449\u0435\u0439 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0442\u0435\u043B\u043E, \u0447\u0443\u0432\u0441\u0442\u0432\u0430 \u0438 \u043F\u0440.), \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043E \u0431\u043E\u043B\u044C\u044E \u0438 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u043E \u0437\u0430\u043A\u043E\u043D\u0443 \u041A\u0430\u0440\u043C\u044B (\u0442.\u0435. \u0441\u043E\u0437\u0434\u0430\u0435\u0442\u0441\u044F \u0432\u0430\u0448\u0438\u043C\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F\u043C\u0438). \u041E\u043D\u043E \u0442\u0430\u043A\u0436\u0435 \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442 \u0441\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435, \u0438\u043B\u0438 \u043F\u043E\u043C\u043E\u0449\u044C \u041D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F \u0432 \u0444\u043E\u0440\u043C\u0435 M\u0101y\u012Byamala (\u043C\u0430\u0439\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435, \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u044E\u0449\u0435\u0435 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435 \u0438 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435) \u0438 K\u0101rmamala (\u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435, \u0432\u044B\u0437\u044B\u0432\u0430\u044E\u0449\u0435\u0435 \u043F\u0443\u0442\u0430\u043D\u0438\u0446\u0443 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043F\u0440\u0438\u0440\u043E\u0434\u044B \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0433\u043E \u0414\u0435\u043B\u0430\u0442\u0435\u043B\u044F). \u0412 \u0437\u0430\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0442\u0435\u043B\u0430, \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u0435 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C Yog\u012B \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0442 \u0438\u0437 \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 Icch\u0101\u015Bakti, \u0430 \u043D\u0435 \u0438\u0437 \u0437\u0430\u043A\u043E\u043D\u0430 \u041A\u0430\u0440\u043C\u044B, \u043F\u0435\u0440\u0435\u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u043C \u0434\u043B\u044F \u044D\u0442\u043E\u0433\u043E \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u043E\u0433\u043E Yog\u012B, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0432\u0441\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0435 \u044D\u0442\u0438\u043C\u0438 \u0442\u0435\u043B\u0430\u043C\u0438, \u043D\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0434\u043B\u044F \u043D\u0435\u0433\u043E \u043A\u0430\u0440\u043C\u0438\u0447\u0435\u0441\u043A\u0438\u043C\u0438 \u0438 \u043F\u043E\u044D\u0442\u043E\u043C\u0443 \u043D\u0435 \u043F\u0440\u0438\u0432\u0435\u0434\u0443\u0442 \u043A \u0434\u0440\u0443\u0433\u043E\u043C\u0443 \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044E.</p></li><li><p>\u041C\u0443\u0434\u0440\u0435\u0446 K\u1E63emar\u0101ja \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 \u0432 \u0441\u0432\u043E\u0435\u0439 Svacchandoddyota: &quot; \u0935\u093F\u092E\u0941\u091A\u094D\u092F\u0924 \u0907\u0924\u093F \u091C\u0940\u0935\u0928\u094D\u0928\u0947\u0935 \u0935\u093F\u092E\u0941\u0915\u094D\u0924\u0903 \u0938\u094D\u092F\u093E\u0924\u094D&quot; - &quot;vimucyata iti j\u012Bvanneva vimukta\u1E25 sy\u0101t&quot; - &quot;&#39;vimucyate&#39; [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u043E\u0441\u0432\u043E\u0431\u043E\u0434\u0438\u043B\u0441\u044F \u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438&quot;. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u044F \u0434\u043E\u0431\u0430\u0432\u0438\u043B &quot;\u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438&quot; \u0432 \u0441\u0432\u043E\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434, \u043D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E &quot;vimucyate&quot; \u043F\u0440\u044F\u043C\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C&quot;.</p></li><li><p>K\u1E63emar\u0101ja \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442 \u044D\u0442\u0443 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u044E\u044E \u0447\u0430\u0441\u0442\u044C \u0441\u0442\u0440\u043E\u0444\u044B \u0432 \u0441\u0432\u043E\u0435\u043C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430 Svacchandatantra: &quot;\u0917\u0924\u094D\u0935\u0947\u0924\u093F \u0926\u0947\u0939\u093E\u0928\u094D\u0924\u0947 \u0924\u0926\u0948\u0915\u093E\u0924\u094D\u092E\u094D\u092F\u092E\u0947\u0924\u093F\u0965&quot; - &quot;gatveti deh\u0101nte tadaik\u0101tmyameti||&quot; - &quot;&#39;gatv\u0101&#39; [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &#39;\u0432 \u043A\u043E\u043D\u0446\u0435 \u0442\u0435\u043B\u0430&#39; --\u0442.\u0435. \u043A\u043E\u0433\u0434\u0430 \u043D\u0430\u0441\u0442\u0443\u043F\u0438\u0442 \u0441\u043C\u0435\u0440\u0442\u044C--, [\u0432 \u044D\u0442\u043E\u0442 \u043C\u043E\u043C\u0435\u043D\u0442,] \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 \u0441 \u0422\u0435\u043C --\u0441 \u0412\u044B\u0441\u0448\u0435\u0439 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E, \u0438 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u043E\u043D \u043D\u0435 \u0440\u043E\u0434\u0438\u0442\u0441\u044F \u0432\u043D\u043E\u0432\u044C--&quot;. \u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0422\u0440\u0438\u043A\u0435 \u0438 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u0443 \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0441\u043A\u0438\u0445 \u0441\u0438\u0441\u0442\u0435\u043C \u0418\u043D\u0434\u0438\u0438, \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0440\u043E\u0436\u0434\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u0434\u043B\u044F \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F. \u041A\u0430\u0436\u0434\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430, \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E, \u043F\u043E\u0441\u0442\u0443\u043B\u0438\u0440\u0443\u0435\u0442 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u043F\u043E-\u0440\u0430\u0437\u043D\u043E\u043C\u0443. \u0412 \u0422\u0440\u0438\u043A\u0435, \u043E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u2014 \u044D\u0442\u043E \u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435, \u0447\u0442\u043E \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 \u0441 \u0412\u044B\u0441\u0448\u0435\u0439 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E. \u0412\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 \u0434\u0440\u0443\u0433\u043E\u0435 \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u043D\u0435 \u0442\u0440\u0435\u0431\u0443\u0435\u0442\u0441\u044F \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0439 \u0434\u0443\u0448\u0438.</p></li><li><p>\u041C\u0443\u0434\u0440\u0435\u0446 K\u1E63emar\u0101ja \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 \u0432 \u0441\u0432\u043E\u0435\u0439 Netroddyota \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0432\u0435\u0449\u0435\u0439 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u043C\u0438 \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0440\u0435\u0447\u0438\u0432\u044B\u043C\u0438 \u0442\u0435\u0440\u043C\u0438\u043D\u0430\u043C\u0438 \u0438 \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u044F\u043C\u0438 \u0432 \u044D\u0442\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u0435 Netratantra:</p></li><li><p>&quot; \u0926\u0943\u0937\u094D\u091F\u094D\u0935\u093E \u0938\u093E\u0915\u094D\u0937\u093E\u0924\u094D\u0915\u0943\u0924\u094D\u092F&quot; - &quot;d\u1E5B\u1E63\u1E6Dv\u0101 s\u0101k\u1E63\u0101tk\u1E5Btya&quot; - &quot;\u041F\u043E\u0441\u043B\u0435 \u0432\u0438\u0434\u0435\u043D\u0438\u044F, \u0442.\u0435. \u043F\u043E\u0441\u043B\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F&quot;;</p></li><li><p>&quot; \u0926\u093F\u0935\u094D\u092F\u0947\u0928 \u092F\u094B\u0917\u092E\u093E\u0930\u094D\u0917\u0947\u0923 \u0935\u093F\u0915\u0932\u094D\u092A\u0939\u093E\u0928\u094B\u0928\u094D\u092E\u093F\u0937\u0926\u0935\u093F\u0915\u0932\u094D\u092A\u0935\u093F\u092E\u0930\u094D\u0936\u093E\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u094B\u092A\u093E\u092F\u0947\u0928&quot; - &quot;divyena yogam\u0101rge\u1E47a vikalpah\u0101nonmi\u1E63adavikalpavimar\u015B\u0101va\u1E63\u1E6Dambhop\u0101yena&quot; - &quot;\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u043F\u0443\u0442\u0435\u043C \u0419\u043E\u0433\u0438, \u0442.\u0435. \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043C\u0435\u0442\u043E\u0434\u0430, \u0438\u043B\u0438 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430, \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u043E\u0433\u043E \u043D\u0430 avikalpavimar\u015Ba, \u0438\u043B\u0438 &#39;\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0438, \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u043C \u043C\u044B\u0441\u043B\u0435\u0439&#39; , \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0441\u0438\u044F\u0435\u0442 \u0441 \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435\u043C \u043C\u044B\u0441\u043B\u0435\u0439&quot;;</p></li><li><p>&quot;\u0924\u0924\u094D\u0924\u094D\u0935\u0924\u094D\u0930\u092F\u0902 \u0928\u0930\u0936\u0915\u094D\u0924\u093F\u0936\u093F\u0935\u093E\u0916\u094D\u092F\u092E\u094D\u0964&quot; - &quot;Tattvatraya\u1E41 nara\u015Bakti\u015Biv\u0101khyam|&quot; - &quot;\u0422\u0440\u0438 \u0442\u0430\u0442\u0442\u0432\u044B, \u0438\u043B\u0438 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0430, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u0435 \u043A\u0430\u043A nara (\u0447\u0435\u043B\u043E\u0432\u0435\u043A), \u015Aakti \u0438 \u015Aiva&quot;, \u0433\u0434\u0435 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0438\u0435 \u0434\u0432\u0430 \u0435\u0441\u0442\u044C \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u0422\u043E\u0433\u043E (Parama\u015Biva), \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u0432\u043E\u0431\u043E\u0434\u0435\u043D \u043E\u0442 \u044D\u0442\u043E\u0433\u043E \u0442\u0440\u043E\u0439\u043D\u043E\u0433\u043E \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u044F, \u043A\u043E\u0440\u043E\u0447\u0435, \u042D\u0442\u043E \u0434\u0430\u0436\u0435 \u043D\u0435 \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0438 \u0415\u0433\u043E \u0421\u0438\u043B\u0430, \u043D\u0435 \u0433\u043E\u0432\u043E\u0440\u044F \u0443\u0436\u0435 \u043E \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0435 (\u0437\u0430\u0433\u0430\u0434\u043E\u0447\u043D\u0430\u044F \u0442\u0435\u043C\u0430, \u043A\u043E\u0442\u043E\u0440\u0443\u044E \u044F \u043D\u0435 \u043C\u043E\u0433\u0443 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u0437\u0434\u0435\u0441\u044C \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0442\u044C);</p></li><li><p>&quot;\u0905\u091A\u0932\u092E\u092A\u0930\u093F\u0923\u093E\u092E\u093F&quot; - &quot;acalamapari\u1E47\u0101mi&quot; - &quot;acala, \u0442.\u0435. \u043D\u0435\u0438\u0437\u043C\u0435\u043D\u043D\u044B\u0439&quot;; \u0438 \u043D\u0430\u043A\u043E\u043D\u0435\u0446</p></li><li><p>&quot;\u0927\u094D\u0930\u0941\u0935\u0902 \u0928\u093F\u0924\u094D\u092F\u092E\u094D&quot; - &quot;dhruva\u1E41 nityam&quot; - &quot;dhruva, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043F\u0435\u0440\u043C\u0430\u043D\u0435\u043D\u0442\u043D\u044B\u0439&quot;.</p></li></ol></div><div class="stanza"><a href="#s3.19" id="s3.19" class="num">3.19</a><div class="sans"><p>\u092F\u0926\u093E \u0924\u0941 \u0936\u0941\u0926\u094D\u0927\u0935\u093F\u0926\u094D\u092F\u093E\u0938\u094D\u0935\u0930\u0942\u092A\u092E\u0938\u094D\u092F \u0928\u093F\u092E\u091C\u094D\u091C\u0924\u093F \u0924\u0926\u093E\u2014</p><blockquote><p><strong>\u0915\u0935\u0930\u094D\u0917\u093E\u0926\u093F\u0937\u0941 \u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u094D\u092F\u093E\u0926\u094D\u092F\u093E\u0903 \u092A\u0936\u0941\u092E\u093E\u0924\u0930\u0903\u0965\u0967\u096F\u0965</strong></p></blockquote><p>\u0905\u0927\u093F\u0937\u094D\u0920\u093E\u0924\u094D\u0930\u094D\u092F\u094B \u092D\u0935\u0928\u094D\u0924\u0940\u0924\u093F \u0936\u0947\u0937\u0903\u0964</p><blockquote><p>\u092F\u093E \u0938\u093E \u0936\u0915\u094D\u0924\u093F\u0930\u094D\u091C\u0917\u0926\u094D\u0927\u093E\u0924\u0941\u0903 \u0915\u0925\u093F\u0924\u093E \u0938\u092E\u0935\u093E\u092F\u093F\u0928\u0940\u0964<br> \u0907\u091A\u094D\u091B\u093E\u0924\u094D\u0935\u0902 \u0924\u0938\u094D\u092F \u0938\u093E \u0926\u0947\u0935\u093F \u0938\u093F\u0938\u0943\u0915\u094D\u0937\u094B\u0903 \u092A\u094D\u0930\u0924\u093F\u092A\u0926\u094D\u092F\u0924\u0947\u0964<br> \u0938\u0948\u0915\u093E\u092A\u093F \u0938\u0924\u094D\u092F\u0928\u0947\u0915\u0924\u094D\u0935\u0902 \u092F\u0925\u093E \u0917\u091A\u094D\u091B\u0924\u093F \u0924\u091A\u094D\u091B\u0943\u0923\u0941\u0965<br> \u090F\u0935\u092E\u0947\u0924\u0926\u093F\u0924\u093F \u091C\u094D\u091E\u0947\u092F\u0902 \u0928\u093E\u0928\u094D\u092F\u0925\u0947\u0924\u093F \u0938\u0941\u0928\u093F\u0936\u094D\u091A\u093F\u0924\u092E\u094D\u0964<br> \u091C\u094D\u091E\u093E\u092A\u092F\u0928\u094D\u0924\u0940 \u091C\u0917\u0924\u094D\u092F\u0924\u094D\u0930 \u091C\u094D\u091E\u093E\u0928\u0936\u0915\u094D\u0924\u093F\u0930\u094D\u0928\u093F\u0917\u0926\u094D\u092F\u0924\u0947\u0965<br> \u090F\u0935\u092E\u094D\u092D\u0942\u0924\u092E\u093F\u0926\u0902 \u0935\u0938\u094D\u0924\u0941 \u092D\u0935\u0924\u094D\u0935\u093F\u0924\u093F \u092F\u0926\u093E \u092A\u0941\u0928\u0903\u0964<br> \u091C\u093E\u0924\u093E \u0924\u0926\u0948\u0935 \u0924\u0924\u094D\u0924\u0926\u094D\u0935\u0924\u094D\u0915\u0941\u0930\u094D\u0935\u0924\u094D\u092F\u0924\u094D\u0930 \u0915\u094D\u0930\u093F\u092F\u094B\u091A\u094D\u092F\u0924\u0947\u0965<br> \u090F\u0935\u0902 \u0938\u0948\u0937\u093E \u0926\u094D\u0935\u093F\u0930\u0942\u092A\u093E\u092A\u093F \u092A\u0941\u0928\u0930\u094D\u092D\u0947\u0926\u0948\u0930\u0928\u0928\u094D\u0924\u0924\u093E\u092E\u094D\u0964<br> \u0905\u0930\u094D\u0925\u094B\u092A\u093E\u0927\u093F\u0935\u0936\u093E\u0924\u094D\u092A\u094D\u0930\u093E\u092A\u094D\u0924\u093E \u091A\u093F\u0928\u094D\u0924\u093E\u092E\u0923\u093F\u0930\u093F\u0935\u0947\u0936\u094D\u0935\u0930\u0940\u0965<br> \u0924\u0924\u094D\u0930 \u0924\u093E\u0935\u0924\u094D\u0938\u092E\u093E\u092A\u0928\u094D\u0928\u092E\u093E\u0924\u0943\u092D\u093E\u0935\u093E \u0935\u093F\u092D\u093F\u0926\u094D\u092F\u0924\u0947\u0964<br> \u0926\u094D\u0935\u093F\u0927\u093E \u091A \u0928\u0935\u0927\u093E \u091A\u0948\u0935 \u092A\u091E\u094D\u091A\u093E\u0936\u0926\u094D\u0927\u093E \u091A \u092E\u093E\u0932\u093F\u0928\u0940\u0965<br> \u092C\u0940\u091C\u092F\u094B\u0928\u094D\u092F\u093E\u0924\u094D\u092E\u0915\u093E\u0926\u094D\u092D\u0947\u0926\u093E\u0926\u094D\u0926\u094D\u0935\u093F\u0927\u093E \u092C\u0940\u091C\u0902 \u0938\u094D\u0935\u0930\u093E \u092E\u0924\u093E\u0903\u0964<br> \u0915\u093E\u0926\u093F\u092D\u093F\u0936\u094D\u091A \u0938\u094D\u092E\u0943\u0924\u093E \u092F\u094B\u0928\u093F\u0930\u094D\u0928\u0935\u0927\u093E \u0935\u0930\u094D\u0917\u092D\u0947\u0926\u0924\u0903\u0965<br> \u092C\u0940\u091C\u092E\u0924\u094D\u0930 \u0936\u093F\u0935\u0903 \u0936\u0915\u094D\u0924\u093F\u0930\u094D\u092F\u094B\u0928\u093F\u0930\u093F\u0924\u094D\u092F\u092D\u093F\u0927\u0940\u092F\u0924\u0947\u0964<br> \u0935\u0930\u094D\u0917\u093E\u0937\u094D\u091F\u0915\u0935\u093F\u092D\u0947\u0926\u0947\u0928 \u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u094D\u092F\u093E\u0926\u093F \u091A\u093E\u0937\u094D\u091F\u0915\u092E\u094D\u0965<br> \u092A\u094D\u0930\u0924\u093F\u0935\u0930\u094D\u0923\u0935\u093F\u092D\u0947\u0926\u0947\u0928 \u0936\u0924\u093E\u0930\u094D\u0927\u0915\u093F\u0930\u0923\u094B\u091C\u094D\u091C\u094D\u0935\u0932\u093E\u0964<br> \u0930\u0941\u0926\u094D\u0930\u093E\u0923\u093E\u0902 \u0935\u093E\u091A\u0915\u0924\u094D\u0935\u0947\u0928 \u0924\u0924\u094D\u0938\u0919\u094D\u0916\u094D\u092F\u093E\u0928\u093E\u0902 \u0928\u093F\u0935\u0947\u0936\u093F\u0924\u093E\u0965</p></blockquote><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u092E\u093E\u0932\u093F\u0928\u0940\u0935\u093F\u091C\u092F\u0928\u093F\u0930\u0942\u092A\u093F\u0924\u0928\u0940\u0924\u094D\u092F\u093E \u092A\u093E\u0930\u092E\u0947\u0936\u094D\u0935\u0930\u0940 \u092A\u0930\u093E\u0935\u093E\u0915\u094D \u092A\u094D\u0930\u0938\u0930\u0928\u094D\u0924\u0940\u091A\u094D\u091B\u093E\u091C\u094D\u091E\u093E\u0928\u0915\u094D\u0930\u093F\u092F\u093E\u0930\u0942\u092A\u0924\u093E\u0902 \u0936\u094D\u0930\u093F\u0924\u094D\u0935\u093E \u092C\u0940\u091C\u092F\u094B\u0928\u093F\u0935\u0930\u094D\u0917\u0935\u0930\u094D\u0917\u094D\u092F\u093E\u0926\u093F\u0930\u0942\u092A\u093E \u0936\u093F\u0935\u0936\u0915\u094D\u0924\u093F\u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u094D\u092F\u093E\u0926\u093F\u0935\u093E\u091A\u0915\u093E\u0926\u093F\u0915\u094D\u0937\u093E\u0928\u094D\u0924\u0930\u0942\u092A\u093E\u0902 \u092E\u093E\u0924\u0943\u0915\u093E\u0924\u094D\u092E\u0924\u093E\u0902 \u0936\u094D\u0930\u093F\u0924\u094D\u0935\u093E \u0938\u0930\u094D\u0935\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u0937\u094D\u0935\u0935\u093F\u0915\u0932\u094D\u092A\u0915\u0938\u0935\u093F\u0915\u0932\u094D\u092A\u0915\u0924\u0924\u094D\u0924\u0924\u094D\u0938\u0902\u0935\u0947\u0926\u0928\u0926\u0936\u093E\u0938\u094D\u0935\u0928\u094D\u0924\u0903\u092A\u0930\u093E\u092E\u0930\u094D\u0936\u093E\u0924\u094D\u092E\u0928\u093E \u0938\u094D\u0925\u0942\u0932\u0938\u0942\u0915\u094D\u0937\u094D\u092E\u0936\u092C\u094D\u0926\u093E\u0928\u0941\u0935\u0947\u0927\u0928\u0902 \u0935\u093F\u0926\u0927\u093E\u0928\u093E \u0935\u0930\u094D\u0917\u0935\u0930\u094D\u0917\u094D\u092F\u093E\u0926\u093F\u0926\u0947\u0935\u0924\u093E\u0927\u093F\u0937\u094D\u0920\u093E\u0928\u093E\u0926\u093F\u0926\u094D\u0935\u093E\u0930\u0947\u0923 \u0938\u094D\u092E\u092F\u0939\u0930\u094D\u0937\u092D\u092F\u0930\u093E\u0917\u0926\u094D\u0935\u0947\u0937\u093E\u0926\u093F\u092A\u094D\u0930\u092A\u091E\u094D\u091A\u0902 \u092A\u094D\u0930\u092A\u091E\u094D\u091A\u092F\u0928\u094D\u0924\u094D\u092F\u0938\u0919\u094D\u0915\u0941\u091A\u093F\u0924\u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u091A\u093F\u0926\u094D\u0918\u0928\u0938\u094D\u0935\u0938\u094D\u0935\u0930\u0942\u092A\u092E\u093E\u0935\u0943\u0923\u094D\u0935\u093E\u0928\u093E \u0938\u0919\u094D\u0915\u0941\u091A\u093F\u0924\u092A\u0930\u0924\u0928\u094D\u0924\u094D\u0930\u0926\u0947\u0939\u093E\u0926\u093F\u092E\u092F\u0924\u094D\u0935\u092E\u093E\u092A\u093E\u0926\u092F\u0924\u093F\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0924\u093F\u092E\u093F\u0930\u094B\u0926\u094D\u0918\u093E\u091F\u0947\u093D\u092A\u093F</p><blockquote><p>\u0915\u0930\u0928\u094D\u0927\u094D\u0930\u091A\u093F\u0924\u093F\u092E\u0927\u094D\u092F\u0938\u094D\u0925\u093E \u092C\u094D\u0930\u0939\u094D\u092E\u092A\u093E\u0936\u093E\u0935\u0932\u092E\u094D\u092C\u093F\u0915\u093E\u0903\u0964<br> \u092A\u0940\u0920\u0947\u0936\u094D\u0935\u0930\u094D\u092F\u094B \u092E\u0939\u093E\u0918\u094B\u0930\u093E \u092E\u094B\u0939\u092F\u0928\u094D\u0924\u094D\u092F\u094B \u092E\u0941\u0939\u0941\u0930\u094D\u092E\u0941\u0939\u0941\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F \u092A\u0942\u0930\u094D\u0935\u092E\u092A\u093F \u0938\u0902\u0935\u093E\u0926\u093F\u0924\u092E\u094D\u0964 \u091C\u094D\u091E\u093E\u0928\u093E\u0927\u093F\u0937\u094D\u0920\u093E\u0928\u0902 \u092E\u093E\u0924\u0943\u0915\u093E (\u0967-\u096A) \u0907\u0924\u093F \u0938\u093E\u092E\u093E\u0928\u094D\u092F\u0947\u0928\u094B\u0915\u094D\u0924\u092E\u093F\u0926\u0902 \u0924\u0941 \u092A\u094D\u0930\u093E\u092A\u094D\u0924\u0924\u0924\u094D\u0924\u094D\u0935\u094B\u093D\u092A\u093F \u092A\u094D\u0930\u092E\u093E\u0926\u094D\u092F\u0928\u094D \u092E\u093E\u0939\u0947\u0936\u094D\u092F\u093E\u0926\u093F\u092D\u093F\u0903 \u092A\u0936\u0941\u091C\u0928\u093E\u0927\u093F\u0937\u094D\u0920\u093E\u0924\u0943\u092D\u0942\u0924\u093E\u092D\u093F\u0930\u092A\u093F \u0936\u092C\u094D\u0926\u093E\u0928\u0941\u0935\u0947\u0927\u0926\u094D\u0935\u093E\u0930\u0947\u0923 \u092E\u094B\u0939\u094D\u092F\u0924 \u0907\u0924\u094D\u092F\u093E\u0936\u092F\u0947\u0928\u0947\u0924\u093F \u0935\u093F\u0936\u0947\u0937\u0903\u0965\u0967\u096F\u0965</p></div><hr><div class="trans"><p>Yad\u0101 tu \u015Buddhavidy\u0101svar\u016Bpamasya nimajjati tad\u0101\u2014</p><blockquote><p><strong>Kavarg\u0101di\u1E63u m\u0101he\u015Bvary\u0101dy\u0101\u1E25 pa\u015Bum\u0101tara\u1E25||19||</strong></p></blockquote><p>Adhi\u1E63\u1E6Dh\u0101tryo bhavant\u012Bti \u015Be\u1E63a\u1E25|</p><blockquote><p>Y\u0101 s\u0101 \u015Baktirjagaddh\u0101tu\u1E25 kathit\u0101 samav\u0101yin\u012B|<br> Icch\u0101tva\u1E41 tasya s\u0101 devi sis\u1E5Bk\u1E63o\u1E25 pratipadyate|<br> Saik\u0101pi satyanekatva\u1E41 yath\u0101 gacchati tacch\u1E5B\u1E47u||<br> Evametaditi j\xF1eya\u1E41 n\u0101nyatheti suni\u015Bcitam|<br> J\xF1\u0101payant\u012B jagatyatra j\xF1\u0101na\u015Baktirnigadyate||<br> Evambh\u016Btamida\u1E41 vastu bhavatviti yad\u0101 puna\u1E25|<br> J\u0101t\u0101 tadaiva tattadvatkurvatyatra kriyocyate||<br> Eva\u1E41 sai\u1E63\u0101 dvir\u016Bp\u0101pi punarbhedairanantat\u0101m|<br> Arthop\u0101dhiva\u015B\u0101tpr\u0101pt\u0101 cint\u0101ma\u1E47irive\u015Bvar\u012B||<br> Tatra t\u0101vatsam\u0101pannam\u0101t\u1E5Bbh\u0101v\u0101 vibhidyate|<br> Dvidh\u0101 ca navadh\u0101 caiva pa\xF1c\u0101\u015Baddh\u0101 ca m\u0101lin\u012B||<br> B\u012Bjayony\u0101tmak\u0101dbhed\u0101ddvidh\u0101 b\u012Bja\u1E41 svar\u0101 mat\u0101\u1E25|<br> K\u0101dibhi\u015Bca sm\u1E5Bt\u0101 yonirnavadh\u0101 vargabhedata\u1E25||<br> B\u012Bjamatra \u015Biva\u1E25 \u015Baktiryonirityabhidh\u012Byate|<br> Varg\u0101\u1E63\u1E6Dakavibhedena m\u0101he\u015Bvary\u0101di c\u0101\u1E63\u1E6Dakam||<br> Prativar\u1E47avibhedena \u015Bat\u0101rdhakira\u1E47ojjval\u0101|<br> Rudr\u0101\u1E47\u0101\u1E41 v\u0101cakatvena tatsa\u1E45khy\u0101n\u0101\u1E41 nive\u015Bit\u0101||</p></blockquote><p>iti \u015Br\u012Bm\u0101lin\u012Bvijayanir\u016Bpitan\u012Bty\u0101 p\u0101rame\u015Bvar\u012B par\u0101v\u0101k prasarant\u012Bcch\u0101j\xF1\u0101nakriy\u0101r\u016Bpat\u0101\u1E41 \u015Britv\u0101 b\u012Bjayonivargavargy\u0101dir\u016Bp\u0101 \u015Biva\u015Baktim\u0101he\u015Bvary\u0101div\u0101cak\u0101dik\u1E63\u0101ntar\u016Bp\u0101\u1E41 m\u0101t\u1E5Bk\u0101tmat\u0101\u1E41 \u015Britv\u0101 sarvapram\u0101t\u1E5B\u1E63vavikalpakasavikalpakatattatsa\u1E41vedanada\u015B\u0101svanta\u1E25par\u0101mar\u015B\u0101tman\u0101 sth\u016Blas\u016Bk\u1E63ma\u015Babd\u0101nuvedhana\u1E41 vidadh\u0101n\u0101 vargavargy\u0101didevat\u0101dhi\u1E63\u1E6Dh\u0101n\u0101didv\u0101re\u1E47a smayahar\u1E63abhayar\u0101gadve\u1E63\u0101diprapa\xF1ca\u1E41 prapa\xF1cayantyasa\u1E45kucitasvatantracidghanasvasvar\u016Bpam\u0101v\u1E5B\u1E47v\u0101n\u0101 sa\u1E45kucitaparatantradeh\u0101dimayatvam\u0101p\u0101dayati| Tadukta\u1E41 \u015Br\u012Btimirodgh\u0101\u1E6De&#39;pi</p><blockquote><p>Karandhracitimadhyasth\u0101 brahmap\u0101\u015B\u0101valambik\u0101\u1E25|<br> P\u012B\u1E6Dhe\u015Bvaryo mah\u0101ghor\u0101 mohayantyo muhurmuhu\u1E25||</p></blockquote><p>iti p\u016Brvamapi sa\u1E41v\u0101ditam| J\xF1\u0101n\u0101dhi\u1E63\u1E6Dh\u0101na\u1E41 m\u0101t\u1E5Bk\u0101 (1-4) iti s\u0101m\u0101nyenoktamida\u1E41 tu pr\u0101ptatattvo&#39;pi pram\u0101dyan m\u0101he\u015By\u0101dibhi\u1E25 pa\u015Bujan\u0101dhi\u1E63\u1E6Dh\u0101t\u1E5Bbh\u016Bt\u0101bhirapi \u015Babd\u0101nuvedhadv\u0101re\u1E47a mohyata ity\u0101\u015Bayeneti vi\u015Be\u1E63a\u1E25||19||</p></div><hr><p>\u041D\u043E <em>(tu)</em>, \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(sva-r\u016Bpam)</em> \u015Auddhavidy\u0101, \u0438\u043B\u0438 \u0427\u0438\u0441\u0442\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435 <em>(\u015Buddha-vidy\u0101)</em>, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0449\u0435\u0435 \u044D\u0442\u043E\u043C\u0443 [Yog\u012B] <em>(asya)</em>, \u043F\u043E\u0433\u0440\u0443\u0436\u0430\u0435\u0442\u0441\u044F \u0432\u043D\u0438\u0437 <em>(nimajjati)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>\u2014</p><blockquote><p><strong>M\u0101he\u015Bvar\u012B <em>(m\u0101he\u015Bvar\u012B)</em> \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0431\u043E\u0433\u0438\u043D\u0438 <em>(\u0101dy\u0101\u1E25)</em>, [\u0447\u044C\u0435\u0439 \u0441\u0444\u0435\u0440\u043E\u0439 \u0432\u043B\u0438\u044F\u043D\u0438\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] &quot;ka&quot; <em>(ka)</em> \u0433\u0440\u0443\u043F\u043F\u0430 <em>(varga)</em>, \u0438 \u0442.\u0434. <em>(\u0101di\u1E63u)</em>, [\u0438 \u044F\u0432\u043B\u044F\u044E\u0449\u0438\u0435\u0441\u044F] \u043C\u0430\u0442\u0435\u0440\u044F\u043C\u0438 <em>(m\u0101tara\u1E25)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(pa\u015Bu)</em>, [\u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F \u0435\u0433\u043E \u0433\u043B\u0430\u0432\u043D\u044B\u043C\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0430\u043C\u0438]||19||</strong></p></blockquote><p>&quot;[\u042D\u0442\u0438 \u0431\u043E\u0433\u0438\u043D\u0438] \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F <em>(bhavanti)</em> [\u0435\u0433\u043E --\u0442\u0430\u043A\u043E\u0433\u043E Yog\u012B--] \u0433\u043B\u0430\u0432\u043D\u044B\u043C\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0430\u043C\u0438 <em>(adhi\u1E63\u1E6Dh\u0101trya\u1E25... iti)</em>&quot;, \u044D\u0442\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0434\u043E\u0431\u0430\u0432\u0438\u0442\u044C [\u043A \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0443 \u0434\u043B\u044F \u043F\u043E\u043B\u043D\u043E\u0442\u044B \u0441\u043C\u044B\u0441\u043B\u0430] <em>(iti \u015Be\u1E63a\u1E25)</em>|</p><blockquote><p>&quot;\u0413\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(kathit\u0101)</em>, \u0447\u0442\u043E \u044D\u0442\u0430 <em>(y\u0101 s\u0101)</em> \u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em> \u0421\u043E\u0437\u0434\u0430\u0442\u0435\u043B\u044F <em>(dh\u0101tu\u1E25)</em> \u043C\u0438\u0440\u0430 <em>(jagat)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043F\u0440\u0438\u0441\u0443\u0449\u0435\u0439 <em>(samav\u0101yin\u012B)</em> [\u0415\u043C\u0443]. \u041E \u0411\u043E\u0433\u0438\u043D\u044F <em>(devi)</em>!, \u041E\u043D\u0430 <em>(s\u0101)</em> \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(pratipadyate)</em> \u0412\u043E\u043B\u0435\u0439 <em>(icch\u0101tvam)</em> \u044D\u0442\u043E\u0433\u043E [\u0421\u043E\u0437\u0434\u0430\u0442\u0435\u043B\u044F] <em>(tasya)</em>, [\u043A\u043E\u0433\u0434\u0430] \u041E\u043D \u0436\u0435\u043B\u0430\u0435\u0442 \u043F\u0440\u043E\u044F\u0432\u0438\u0442\u044C <em>(sis\u1E5Bk\u1E63o\u1E25)</em> [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E]. \u0421\u043B\u0443\u0448\u0430\u0439 <em>(tad \u015B\u1E5B\u1E47u)</em>, \u043A\u0430\u043A <em>(yath\u0101)</em> \u041E\u043D\u0430 <em>(s\u0101)</em> \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(gacchati)</em> \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E\u043C <em>(anekatvam)</em>, \u043D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E <em>(api)</em> \u041E\u043D\u0430 <em>(sat\u012B)</em> \u043E\u0434\u043D\u0430 <em>(ek\u0101)</em>:</p></blockquote><blockquote><p>\u041E\u0431\u044A\u044F\u0432\u043B\u044F\u044F <em>(j\xF1\u0101payant\u012B)</em> \u0441 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u044C\u044E <em>(suni\u015Bcitam)</em>, \u0447\u0442\u043E &#39;\u042D\u0442\u043E <em>(etad)</em> \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435, \u0438\u043B\u0438 \u043E\u0431\u044A\u0435\u043A\u0442 <em>(j\xF1eyam)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u044D\u0442\u043E\u043C\u0443 <em>(evam... iti)</em>, [\u0438] \u043D\u0435 <em>(na)</em> \u0438\u043D\u0430\u0447\u0435 <em>(anyath\u0101... iti)</em>!&#39;, \u041E\u043D\u0430 \u0437\u043E\u0432\u0435\u0442\u0441\u044F <em>(nigadyate)</em> \u0421\u0438\u043B\u043E\u0439 \u0417\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na-\u015Bakti\u1E25)</em> \u0432 \u044D\u0442\u043E\u043C \u043C\u0438\u0440\u0435 <em>(jagati atra)</em>.</p></blockquote><blockquote><p>\u041E\u0434\u043D\u0430\u043A\u043E <em>(punar)</em>, \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u041E\u043D\u0430 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u0439 <em>(j\u0101t\u0101)</em> [\u043A\u0430\u043A] &#39;\u041F\u0443\u0441\u0442\u044C \u044D\u0442\u0430 \u0432\u0435\u0449\u044C \u0441\u0442\u0430\u043D\u0435\u0442 <em>(idam vastu bhavatu)</em> \u0442\u0430\u043A\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(evam-bh\u016Btam... iti)</em>!&#39;, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101 eva)</em>, \u0441\u043E\u0437\u0434\u0430\u0432\u0430\u044F <em>(kurvat\u012B)</em> \u044D\u0442\u0443 [\u0432\u0435\u0449\u044C] <em>(tad)</em> \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(tad-vat)</em> \u0437\u0434\u0435\u0441\u044C <em>(atra)</em>, \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F, \u0447\u0442\u043E \u041E\u043D\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(ucyate)</em> [\u0421\u0438\u043B\u043E\u0439] \u0414\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(kriy\u0101)</em>.</p></blockquote><blockquote><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u0445\u043E\u0442\u044F <em>(api)</em> \u044D\u0442\u0430 \u0441\u0430\u043C\u0430\u044F [\u015Aakti] <em>(s\u0101 e\u1E63\u0101)</em> \u0438\u043C\u0435\u0435\u0442 \u0434\u0432\u0435 [\u0433\u043B\u0430\u0432\u043D\u044B\u0435] \u0444\u043E\u0440\u043C\u044B <em>(dvi-r\u016Bp\u0101)</em>, \u041E\u043D\u0430 \u043F\u0440\u0435\u0442\u0435\u0440\u043F\u0435\u0432\u0430\u0435\u0442 <em>(pr\u0101pt\u0101)</em> \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u044B\u0435 <em>(anantat\u0101m)</em> \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F <em>(bhedai\u1E25)</em>, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E <em>(va\u015B\u0101t)</em> \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A\u0430\u043C <em>(up\u0101dhi)</em> [\u0436\u0435\u043B\u0430\u0435\u043C\u044B\u0445] \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 <em>(artha)</em>. [\u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u044D\u0442\u0430] \u0413\u043E\u0441\u043F\u043E\u0436\u0430 <em>(\u012B\u015Bvar\u012B)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u0430 <em>(iva)</em> \u0434\u0440\u0430\u0433\u043E\u0446\u0435\u043D\u043D\u043E\u043C\u0443 \u043A\u0430\u043C\u043D\u044E <em>(cint\u0101-ma\u1E47i\u1E25)</em> --\u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0438\u0441\u043F\u043E\u043B\u043D\u044F\u0435\u0442 \u0432\u0441\u0435 \u0436\u0435\u043B\u0430\u043D\u0438\u044F \u0435\u0433\u043E \u043E\u0431\u043B\u0430\u0434\u0430\u0442\u0435\u043B\u044F--.</p></blockquote><blockquote><p>\u0417\u0430\u0442\u0435\u043C <em>(tatra)</em>, [\u043A\u043E\u0433\u0434\u0430 \u0413\u043E\u0441\u043F\u043E\u0436\u0430] \u0432\u043D\u0430\u0447\u0430\u043B\u0435 \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(t\u0101vat sam\u0101panna... bh\u0101v\u0101)</em> \u043C\u0430\u0442\u0435\u0440\u0438 <em>(m\u0101t\u1E5B)</em>, \u041E\u043D\u0430 \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F <em>(vibhidyate)</em> \u0434\u0432\u0443\u043C\u044F \u043F\u0443\u0442\u044F\u043C\u0438 <em>(dvidh\u0101)</em> \u0438 <em>(ca... ca eva)</em> \u0434\u0435\u0432\u044F\u0442\u044C\u044E \u043F\u0443\u0442\u044F\u043C\u0438 <em>(navadh\u0101)</em>, \u0438 <em>(ca)</em> [\u043A\u043E\u0433\u0434\u0430 \u0442\u0430\u043A\u0430\u044F \u0413\u043E\u0441\u043F\u043E\u0436\u0430 \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F] \u043F\u044F\u0442\u044C\u044E\u0434\u0435\u0441\u044F\u0442\u044C\u044E \u043F\u0443\u0442\u044F\u043C\u0438 <em>(pa\xF1c\u0101\u015Baddh\u0101)</em>, [\u041E\u043D\u0430 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F] \u043D\u043E\u0441\u0438\u0442\u0435\u043B\u0435\u043C \u0433\u0438\u0440\u043B\u044F\u043D\u0434\u044B <em>(m\u0101lin\u012B)</em>, [\u0441\u0434\u0435\u043B\u0430\u043D\u043D\u043E\u0439 \u0438\u0437 \u043F\u044F\u0442\u0438\u0434\u0435\u0441\u044F\u0442\u0438 \u0431\u0443\u043A\u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u0433\u043E \u0430\u043B\u0444\u0430\u0432\u0438\u0442\u0430].</p></blockquote><blockquote><p>\u041F\u0440\u0438 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0438, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u043C <em>(\u0101tmak\u0101t bhed\u0101t)</em> \u0438\u0437 b\u012Bja <em>(b\u012Bja)</em> [\u0438] yoni <em>(yoni)</em>, \u041E\u043D\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0434\u0432\u0443\u043C\u044F \u0441\u043F\u043E\u0441\u043E\u0431\u0430\u043C\u0438 <em>(dvidh\u0101)</em>. \u0413\u043B\u0430\u0441\u043D\u044B\u0435 <em>(svar\u0101\u1E25)</em> \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u043A\u0430\u043A <em>(mat\u0101\u1E25)</em> b\u012Bja, \u0438\u043B\u0438 \u0441\u0435\u043C\u044F <em>(b\u012Bjam)</em>. \u041D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 ka, \u0438 \u0442.\u0434. <em>(ka-\u0101dibhi\u1E25)</em> \u043E \u041D\u0435\u0439 \u0433\u043E\u0432\u043E\u0440\u044F\u0442 \u043A\u0430\u043A \u043E <em>(sm\u1E5Bt\u0101)</em> yoni, \u0438\u043B\u0438 \u043B\u043E\u043D\u0435 <em>(yoni\u1E25)</em> --\u0442.\u0435. \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u044B\u0435 \u0441\u0447\u0438\u0442\u0430\u044E\u0442\u0441\u044F yoni--. [\u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E,] \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435\u043C <em>(bhedatas)</em> \u043D\u0430 varga-s, \u0438\u043B\u0438 \u0433\u0440\u0443\u043F\u043F\u044B \u0431\u0443\u043A\u0432 <em>(varga)</em>, [\u041E\u043D\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0434\u0435\u0432\u044F\u0442\u044C\u044E \u043F\u0443\u0442\u044F\u043C\u0438 <em>(navadh\u0101)</em><sup>1</sup>.</p></blockquote><blockquote><p>\u0412 \u044D\u0442\u043E\u043C [\u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435] <em>(atra)</em>, b\u012Bja --\u0433\u043B\u0430\u0441\u043D\u0430\u044F-- <em>(b\u012Bjam)</em> [\u0438] yoni --\u0441\u043E\u0433\u043B\u0430\u0441\u043D\u0430\u044F-- <em>(yoni\u1E25)</em> \u043D\u0430\u0437\u044B\u0432\u0430\u044E\u0442\u0441\u044F <em>(iti abhidh\u012Byate)</em> \u015Aiva <em>(\u015Biva\u1E25)</em> [\u0438] \u015Aakti <em>(\u015Bakti\u1E25)</em>. \u041A\u0441\u0442\u0430\u0442\u0438 <em>(ca)</em>, \u043F\u0440\u0438 \u0434\u0435\u043B\u0435\u043D\u0438\u0438 <em>(vibhedena)</em> \u043D\u0430 \u0432\u043E\u0441\u0435\u043C\u044C <em>(a\u1E63\u1E6Daka)</em> \u0433\u0440\u0443\u043F\u043F \u0431\u0443\u043A\u0432 <em>(varga)</em> [\u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E] \u0433\u0440\u0443\u043F\u043F\u0430 \u0438\u0437 \u0432\u043E\u0441\u044C\u043C\u0438 [\u0431\u043E\u0436\u0435\u0441\u0442\u0432] <em>(a\u1E63\u1E6Dakam)</em>, [\u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A] M\u0101he\u015Bvar\u012B <em>(m\u0101he\u015Bvar\u012B)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em> .</p></blockquote><blockquote><p>[\u0418] \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435\u043C \u0431\u0443\u043A\u0432 <em>(prativar\u1E47a-vibhedena)</em>, \u041E\u043D\u0430 \u0441\u0438\u044F\u0435\u0442 <em>(ujjval\u0101)</em> \u043A\u0430\u043A \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442 <em>( \u015Bata-ardha)</em> \u043B\u0443\u0447\u0435\u0439 <em>(kira\u1E47a)</em> --\u0442.\u0435. \u041E\u043D\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442 \u0431\u0443\u043A\u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u0433\u043E \u0430\u043B\u0444\u0430\u0432\u0438\u0442\u0430--. \u042F\u0432\u043B\u044F\u044F\u0441\u044C \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u0435\u043C <em>(v\u0101cakatvena)</em> \u043D\u0430 Rudra-s <em>(rudr\u0101\u1E47\u0101m)</em>, \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u043A\u043E\u0442\u043E\u0440\u044B\u0445 <em>(sa\u1E45khy\u0101n\u0101m)</em> \u0442\u0430\u043A\u043E\u0435 \u0436\u0435 --\u0442.\u0435. \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442-- <em>(tad)</em>, \u041E\u043D\u0430 \u0443\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0430 [\u0432 \u044D\u0442\u043E\u043C \u0441\u0430\u043C\u043E\u043C \u0447\u0438\u0441\u043B\u0435] <em>(nive\u015Bit\u0101... iti)</em><sup>2</sup>&quot;||<br> [\u0421\u043C. M\u0101lin\u012Bvijayatantra III, 5-13]</p></blockquote><p>\u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u043C <em>(n\u012Bty\u0101)</em>, \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u043D\u044B\u043C \u0438 \u0443\u0434\u043E\u0441\u0442\u043E\u0432\u0435\u0440\u0435\u043D\u043D\u044B\u043C <em>(nir\u016Bpita)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C M\u0101lin\u012Bvijayatantra <em>(\u015Br\u012B-m\u0101lin\u012Bvijaya)</em>, \u0412\u044B\u0441\u0448\u0430\u044F \u0420\u0435\u0447\u044C <em>(par\u0101-v\u0101k)</em>, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0430\u044F\u0441\u044F \u043A \u0412\u044B\u0441\u0448\u0435\u043C\u0443 \u0413\u043E\u0441\u043F\u043E\u0434\u0443 <em>(p\u0101rame\u015Bvar\u012B)</em> --\u0442.\u0435. \u0415\u0433\u043E \u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u0435-- \u0440\u0430\u0437\u0432\u0435\u0440\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(prasarant\u012B)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0442\u043E\u0433\u043E <em>(\u015Britv\u0101)</em>, \u0447\u0442\u043E \u0441\u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u043E <em>(r\u016Bpat\u0101m)</em> \u0412\u043E\u043B\u0435\u0439 <em>(icch\u0101)</em>, \u0417\u043D\u0430\u043D\u0438\u0435\u043C <em>(j\xF1\u0101na)</em> [\u0438] \u0414\u0435\u0439\u0441\u0442\u0432\u0438\u0435\u043C <em>(kriy\u0101)</em>. [\u041F\u043E\u0437\u0436\u0435, \u041E\u043D\u0430 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442 \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435], \u043F\u0440\u0438\u043D\u044F\u0432 \u0444\u043E\u0440\u043C\u0443 <em>(r\u016Bp\u0101)</em> \u0433\u043B\u0430\u0441\u043D\u044B\u0445 <em>(b\u012Bja)</em>, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u044B\u0445 <em>(yoni)</em>, \u0433\u0440\u0443\u043F\u043F \u0431\u0443\u043A\u0432 <em>(varga)</em>, \u0431\u0443\u043A\u0432, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0449\u0438\u0445 \u043A \u044D\u0442\u0438\u043C \u0433\u0440\u0443\u043F\u043F\u0430\u043C <em>(varg\u012B)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em> \u043F\u043E\u0441\u043B\u0435 \u043F\u0440\u0438\u043D\u044F\u0442\u0438\u044F <em>(\u015Britv\u0101)</em> \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(\u0101tmat\u0101m)</em> M\u0101t\u1E5Bk\u0101 <em>(m\u0101t\u1E5Bk\u0101)</em>, \u0447\u044C\u044F \u0444\u043E\u0440\u043C\u0430 <em>(r\u016Bp\u0101m)</em> \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0441 &quot;a&quot; <em>(a-\u0101di)</em> \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0432 &quot;k\u1E63a&quot; <em>(k\u1E63a-anta)</em> --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0432\u0435\u0441\u044C \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0439 \u0430\u043B\u0444\u0430\u0432\u0438\u0442--, [\u0432\u0441\u0435 \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 --\u0442.\u0435. \u0432\u0441\u0435 \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442 \u0431\u0443\u043A\u0432--] \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0442 \u043D\u0430 <em>(v\u0101caka)</em> \u015Aiva <em>(\u015Biva)</em>, \u015Aakti <em>(\u015Bakti)</em>, M\u0101he\u015Bvar\u012B <em>(m\u0101he\u015Bvar\u012B)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em><sup>3</sup></p><p>. \u0412\u043E \u0432\u0441\u0435\u0445 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0445 <em>(sarva-pram\u0101t\u1E5B\u1E63u)</em><sup>4</sup>, \u043A\u043E\u0433\u0434\u0430 \u0438\u043C\u0435\u044E\u0442\u0441\u044F \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(tad-tad-da\u015B\u0101su)</em> \u0437\u043D\u0430\u043D\u0438\u044F <em>(sa\u1E41vedana)</em> \u0441 \u043C\u044B\u0441\u043B\u044F\u043C\u0438 <em>(savikalpaka)</em> [\u0438] \u0431\u0435\u0437 \u043C\u044B\u0441\u043B\u0435\u0439 <em>(avikalpaka)</em>, \u041E\u043D\u0430 \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442 <em>(vidadh\u0101n\u0101)</em>, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044F <em>(antar-par\u0101mar\u015Ba-\u0101tman\u0101)</em>, \u043F\u0440\u0438\u043C\u0435\u043D\u0435\u043D\u0438\u0435 --\u0442.\u0435. \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0441\u043B\u043E\u0432\u0430 \u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0442 \u0432\u043D\u0443\u0442\u0440\u044C-- <em>(anuvedhanam)</em> \u0433\u0440\u0443\u0431\u044B\u0445 <em>(sth\u016Bla)</em> [\u0438] \u0442\u043E\u043D\u043A\u0438\u0445 <em>(s\u016Bk\u1E63ma)</em> \u0441\u043B\u043E\u0432 <em>(\u015Babda)</em>. \u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C <em>(dv\u0101re\u1E47a)</em> \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F, \u0438\u043B\u0438 \u0441\u0438\u043B\u044B <em>(adhi\u1E63\u1E6Dh\u0101na)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em> \u0431\u043E\u0436\u0435\u0441\u0442\u0432 <em>(devat\u0101)</em> \u0433\u0440\u0443\u043F\u043F \u0431\u0443\u043A\u0432 <em>(varga)</em>, \u0431\u0443\u043A\u0432, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0449\u0438\u0445 \u043A \u0442\u0430\u043A\u0438\u043C \u0433\u0440\u0443\u043F\u043F\u0430\u043C <em>(varg\u012B)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u041E\u043D\u0430 \u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0438\u0440\u0443\u0435\u0442 <em>(prapa\xF1cayant\u012B)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(prapa\xF1cam)</em> \u0438\u0437\u0443\u043C\u043B\u0435\u043D\u0438\u044F <em>(smaya)</em>, \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F <em>(har\u1E63a)</em>, \u0441\u0442\u0440\u0430\u0445\u0430 <em>(bhaya)</em>, \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u0438 <em>(r\u0101ga)</em>, \u043E\u0442\u0432\u0440\u0430\u0449\u0435\u043D\u0438\u044F <em>(dve\u1E63a)</em> \u0438 \u0442\u043E\u043C\u0443 \u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0435 <em>(\u0101di)</em>. [\u0418] \u0447\u0435\u0440\u0435\u0437 \u0441\u043E\u043A\u0440\u044B\u0442\u0438\u0435 <em>(\u0101v\u1E5B\u1E47v\u0101n\u0101)</em> \u0441\u0432\u043E\u0435\u0439 <em>(sva)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-r\u016Bpam)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0435\u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u043D\u043E\u0439 --\u043D\u0435\u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u043E\u0439-- <em>(asa\u1E45kucita)</em> \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0439 <em>(svatantra)</em> \u043C\u0430\u0441\u0441\u043E\u0439 <em>(ghana)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em>, \u041E\u043D\u0430 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442 <em>(\u0101p\u0101dayati)</em> \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u0435 <em>(mayatvam)</em> \u0441\u043E \u0441\u0436\u0430\u0442\u044B\u043C --\u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u043C-- <em>(sa\u1E45kucita)</em> \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u044B\u043C <em>(paratantra)</em> \u0442\u0435\u043B\u043E\u043C <em>(deha)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>|</p><p>\u042D\u0442\u043E <em>(tad)</em> \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Timirodgh\u0101\u1E6Da <em>(\u015Br\u012B-timirodgh\u0101\u1E6De)</em> too <em>(api)</em>:</p><blockquote><p>&quot;Mah\u0101ghor\u0101-s --\u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E, &quot;\u043E\u0447\u0435\u043D\u044C \u0441\u0442\u0440\u0430\u0448\u043D\u044B\u0435&quot;-- <em>(mah\u0101ghor\u0101\u1E25)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C, \u015Bakti-s, \u0438\u043B\u0438 \u0441\u0438\u043B\u044B], \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442 <em>(sth\u0101\u1E25)</em> \u0432 \u0441\u0435\u0440\u0434\u0446\u0435\u0432\u0438\u043D\u0435 <em>(madhya)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(citi)</em> \u0432 Karandhra --\u0442.\u0435. \u0432 Brahmarandhra-- <em>(ka-randhra)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u043E\u0434\u0432\u0435\u0448\u0438\u0432\u0430\u044E\u0442 <em>(avalambik\u0101\u1E25)</em> \u0430\u0440\u043A\u0430\u043D\u043E\u043C \u0411\u0440\u0430\u0445\u043C\u044B <em>(brahma-p\u0101\u015Ba)</em> [\u0438] \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0412\u043B\u0430\u0434\u044B\u0447\u0438\u0446\u0430\u043C\u0438 <em>(\u012B\u015Bvarya\u1E25)</em> p\u012B\u1E6Dha-s, \u0438\u043B\u0438 \u043E\u043F\u043E\u0440/\u0441\u0438\u0434\u0435\u043D\u0438\u0439 --\u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432-- <em>(p\u012B\u1E6Dha)</em>, \u0432\u0432\u043E\u0434\u044F\u0442 \u0432 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435 <em>(mohayanti)</em> \u0432\u043D\u043E\u0432\u044C \u0438 \u0432\u043D\u043E\u0432\u044C <em>(muhur... muhur... iti)</em><sup>5</sup>&quot;||</p></blockquote><p>[\u0422\u043E, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043E \u0432\u044B\u0448\u0435] \u0431\u044B\u043B\u043E \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u043E <em>(sa\u1E41v\u0101ditam)</em> \u0440\u0430\u043D\u0435\u0435 <em>(p\u016Brvam)</em> \u0442\u0430\u043A\u0436\u0435 <em>(api)</em> --\u0432 I, 4--|</p><p>&quot;\u041E\u0441\u043D\u043E\u0432\u043E\u0439 <em>(adhi\u1E63\u1E6Dh\u0101nam)</em> [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0438 \u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u043D\u043E\u0433\u043E] \u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043D\u0435\u043F\u043E\u043D\u044F\u0442\u0430\u044F \u041C\u0430\u0442\u044C <em>(m\u0101t\u1E5Bk\u0101)</em>. (I, 4) [\u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F] <em>(1-4 iti)</em>&quot;. \u042D\u0442\u043E <em>(idam)</em> \u0431\u044B\u043B\u043E \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u043E \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u043E <em>(uktam... tu)</em> \u0432 \u043E\u0431\u0449\u0435\u043C \u0432\u0438\u0434\u0435 <em>(s\u0101m\u0101nyena)</em>. [\u0417\u0434\u0435\u0441\u044C, \u0432 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 --III, 19--, M\u0101t\u1E5Bk\u0101 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0431\u043E\u043B\u0435\u0435 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E], \u0441 \u043D\u0430\u043C\u0435\u0440\u0435\u043D\u0438\u0435\u043C <em>(\u0101\u015Bayena)</em> [\u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C, \u0447\u0442\u043E] &quot;[\u0435\u0441\u043B\u0438] \u0434\u0430\u0436\u0435 <em>(api)</em> \u0442\u043E\u0442, \u043A\u0442\u043E \u0434\u043E\u0441\u0442\u0438\u0433 [\u0412\u044B\u0441\u0448\u0435\u0433\u043E] \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0430 <em>(pr\u0101pta-tattva\u1E25)</em>, \u043D\u0435 \u043E\u0441\u0442\u043E\u0440\u043E\u0436\u0435\u043D \u0438 \u043D\u0435 \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u0435\u043D <em>(pram\u0101dyan)</em>, \u0442\u0430\u043A\u0436\u0435 \u0432\u0432\u043E\u0434\u0438\u0442\u0441\u044F \u0432 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435 <em>(api... mohyate)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C M\u0101he\u015B\u012B --\u0438\u043B\u0438 M\u0101he\u015Bvar\u012B--, \u0438 \u0442.\u0434. <em>(m\u0101he\u015B\u012B-\u0101dibhi\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F <em>(bh\u016Bt\u0101bhi\u1E25)</em> [\u0431\u043E\u0433\u0438\u043D\u044F\u043C\u0438], \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0438\u0440\u0443\u044E\u0449\u0438\u043C\u0438 <em>(adhi\u1E63\u1E6Dh\u0101t\u1E5B)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445 \u043B\u044E\u0434\u0435\u0439 <em>(pa\u015Bu-jana)</em> \u043F\u0443\u0442\u0435\u043C \u043F\u0440\u0438\u043C\u0435\u043D\u0435\u043D\u0438\u044F --\u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F-- <em>(anuvedha-dv\u0101re\u1E47a)</em> \u0441\u043B\u043E\u0432 <em>(\u015Babda... iti)</em>&quot;. \u0412 \u044D\u0442\u043E\u043C \u0440\u0430\u0437\u043D\u0438\u0446\u0430 <em>(iti vi\u015Be\u1E63a\u1E25)</em> [\u043C\u0435\u0436\u0434\u0443 \u0434\u0432\u0443\u043C\u044F \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F\u043C\u0438 --\u0430\u043D\u0430\u043B\u0438\u0437\u043E\u043C, \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u043D\u043E\u043C \u0432 I, 4 \u0438 \u0432 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435--]||19||</p><hr><ol><li>\u0421\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0439 \u0430\u043B\u0444\u0430\u0432\u0438\u0442 \u0432 \u0435\u0433\u043E \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u043E\u043D\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435 \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442 8 varga-s, \u0438\u043B\u0438 \u0433\u0440\u0443\u043F\u043F \u0431\u0443\u043A\u0432:</li></ol><ul><li><p>A-varga (\u0413\u043B\u0430\u0441\u043D\u044B\u0435), \u0433\u0434\u0435 \u043F\u0440\u0430\u0432\u044F\u0449\u0430\u044F \u0431\u043E\u0433\u0438\u043D\u044F \u2014 Yog\u012B\u015Bvar\u012B (\u0442\u0430\u043A\u0436\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u0430\u044F Mah\u0101lak\u1E63m\u012B)</p></li><li><p>Ka-varga (\u0413\u043E\u0440\u0442\u0430\u043D\u043D\u044B\u0435/\u0437\u0430\u0434\u043D\u0435\u044F\u0437\u044B\u0447\u043D\u044B\u0435), \u0433\u0434\u0435 \u043F\u0440\u0430\u0432\u044F\u0449\u0430\u044F \u0431\u043E\u0433\u0438\u043D\u044F \u2014 Br\u0101hm\u012B</p></li><li><p>Ca-varga (\u041F\u0430\u043B\u0430\u0442\u0430\u043B\u044C\u043D\u044B\u0435/\u041D\u0435\u0431\u043D\u044B\u0435), \u0433\u0434\u0435 \u043F\u0440\u0430\u0432\u044F\u0449\u0430\u044F \u0431\u043E\u0433\u0438\u043D\u044F \u2014 M\u0101he\u015Bvar\u012B</p></li><li><p>\u1E6Ca-varga (\u0426\u0435\u0440\u0435\u0431\u0440\u0430\u043B\u044C\u043D\u044B\u0435), \u0433\u0434\u0435 \u043F\u0440\u0430\u0432\u044F\u0449\u0430\u044F \u0431\u043E\u0433\u0438\u043D\u044F \u2014 Kaum\u0101r\u012B</p></li><li><p>Ta-varga (\u0417\u0443\u0431\u043D\u044B\u0435), \u0433\u0434\u0435 \u043F\u0440\u0430\u0432\u044F\u0449\u0430\u044F \u0431\u043E\u0433\u0438\u043D\u044F \u2014 Vai\u1E63\u1E47av\u012B</p></li><li><p>Pa-varga (\u0413\u0443\u0431\u043D\u044B\u0435), \u0433\u0434\u0435 \u043F\u0440\u0430\u0432\u044F\u0449\u0430\u044F \u0431\u043E\u0433\u0438\u043D\u044F \u2014 V\u0101rah\u012B</p></li><li><p>Ya-varga (\u041D\u0435\u043D\u043E\u0441\u043E\u0432\u044B\u0435 \u0441\u043E\u043D\u0430\u043D\u0442\u044B/\u043F\u043E\u043B\u0443\u0433\u043B\u0430\u0441\u043D\u044B\u0435), \u0433\u0434\u0435 \u043F\u0440\u0430\u0432\u044F\u0449\u0430\u044F \u0431\u043E\u0433\u0438\u043D\u044F \u2014 Aindr\u012B (\u0442\u0430\u043A\u0436\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u0430\u044F Indr\u0101\u1E47\u012B)</p></li><li><p>\u015Aa-varga (\u0428\u0438\u043F\u044F\u0449\u0438\u0435, \u043F\u0440\u0438\u0434\u044B\u0445\u0430\u0442\u0435\u043B\u044C\u043D\u0430\u044F \u0441\u043E\u043D\u0430\u043D\u0442\u0430 + K\u016B\u1E6Dab\u012Bja --\u043E\u0431\u044A\u0435\u0434\u0438\u043D\u0435\u043D\u043D\u0430\u044F k\u1E63a, \u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u043D\u0430\u044F \u0438\u0437 &quot;ka + sa&quot;, \u043D\u043E \u043E\u0447\u0435\u043D\u044C \u0447\u0430\u0441\u0442\u043E \u0441\u0447\u0438\u0442\u0430\u044E\u0449\u0430\u044F\u0441\u044F \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0439 \u0431\u0443\u043A\u0432\u043E\u0439--), \u0433\u0434\u0435 \u043F\u0440\u0430\u0432\u044F\u0449\u0430\u044F \u0431\u043E\u0433\u0438\u043D\u044F \u2014 C\u0101mu\u1E47\u1E0D\u0101</p><p>\u0412 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0432\u0440\u0435\u043C\u044F \u0430\u043B\u0444\u0430\u0432\u0438\u0442, \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u043D\u044B\u0439 \u0432 \u0435\u0433\u043E \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u043E\u043D\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435, \u043D\u0435 \u0432\u043A\u043B\u044E\u0447\u0430\u0435\u0442 K\u016B\u1E6Dab\u012Bja (\u0431\u0443\u043A\u0432\u0443 k\u1E63a), \u043D\u043E \u043A\u043E\u0433\u0434\u0430 \u044D\u0442\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442, K\u016B\u1E6Dab\u012Bja \u043E\u0431\u044B\u0447\u043D\u043E \u043F\u0440\u0438\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043A \u0432\u043E\u0441\u044C\u043C\u043E\u0439 varga, \u0438\u043B\u0438 \u0433\u0440\u0443\u043F\u043F\u0435 (\u015Aa-varga). \u0418\u0442\u0430\u043A, \u0432\u043E\u043F\u0440\u043E\u0441 \u043D\u0430 \u043C\u0438\u043B\u043B\u0438\u043E\u043D: &quot;\u0415\u0441\u043B\u0438 \u0438\u043C\u0435\u0435\u0442\u0441\u044F 8 varga-s, \u0438\u043B\u0438 \u0433\u0440\u0443\u043F\u043F, \u043F\u043E\u0447\u0435\u043C\u0443 \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0433\u043E\u0432\u043E\u0440\u0438\u043B \u043E\u0431 \u044D\u0442\u043E\u043C \u0432\u044B\u0448\u0435?: &quot; [\u0414\u0430 \u043F\u043E\u0442\u043E\u043C\u0443, \u0447\u0442\u043E] \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435\u043C varga-s, \u0438\u043B\u0438 \u0433\u0440\u0443\u043F\u043F \u0431\u0443\u043A\u0432, [\u041E\u043D\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0434\u0435\u0432\u044F\u0442\u044C\u044E \u043F\u0443\u0442\u044F\u043C\u0438. \u0423\u043F\u0440\u043E\u0449\u0435\u043D\u043D\u043E: \u0438\u043D\u043E\u0433\u0434\u0430 K\u016B\u1E6Dab\u012Bja \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0439 varga, \u0442.\u0435. K\u1E63a-varga. \u0412 \u044D\u0442\u043E\u043C \u043E\u0441\u043E\u0431\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u043E\u0431\u0449\u0435\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E varga-s \u0431\u0443\u0434\u0435\u0442 \u0440\u0430\u0432\u043D\u043E 9, \u0430 \u043D\u0435 8. \u0422\u0435\u043F\u0435\u0440\u044C, \u044D\u0442\u0430 \u0447\u0430\u0441\u0442\u044C \u0442\u0435\u043A\u0441\u0442\u0430 \u043F\u043E\u043D\u044F\u0442\u043D\u0430, \u0442\u0430\u043A \u0432\u0435\u0434\u044C?</p></li></ul><ol start="2"><li><p>\u0427\u0442\u043E\u0431\u044B \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u043E\u043D\u044F\u0442\u044C \u044D\u0442\u043E\u0442 \u0432\u043E\u043F\u0440\u043E\u0441, \u0438 \u0443\u0447\u0438\u0442\u0435\u043B\u044C, \u0438 \u0443\u0447\u0435\u043D\u0438\u043A \u0434\u043E\u043B\u0436\u043D\u044B \u0431\u044B\u0442\u044C \u043E\u0447\u0435\u043D\u044C \u0445\u043E\u0440\u043E\u0448\u043E \u0437\u043D\u0430\u043A\u043E\u043C\u044B \u0441\u043E \u0437\u043D\u0430\u043D\u0438\u044F\u043C\u0438, \u043E\u0442\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u043D\u044B\u043C\u0438 \u0432 M\u0101lin\u012Bvijayatantra. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u0437\u0434\u0435\u0441\u044C \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F: \u0418\u043D\u0434\u0438\u043A\u0430\u0442\u043E\u0440/\u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043E \u041E\u043D\u0430 \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u0438\u043B\u0438 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442 Rudra-s, \u0438\u043B\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432, \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u044E\u0449\u0438\u0445 \u043A\u0430\u0436\u0434\u0443\u044E \u0438\u0437 \u043F\u044F\u0442\u0438\u0434\u0435\u0441\u044F\u0442\u0438 \u0431\u0443\u043A\u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u0433\u043E \u0430\u043B\u0444\u0430\u0432\u0438\u0442\u0430. \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0441\u0434\u0435\u043B\u0430\u043B \u0415\u0435 \u0442\u0430\u043A\u043E\u0439, \u0442.\u0435. \u043F\u044F\u0442\u0438\u0434\u0435\u0441\u044F\u0442\u0438-\u043A\u0440\u0430\u0442\u043D\u043E\u0439, \u0438 \u0432\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 \u041E\u043D\u0430 \u0443\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0430 \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u0435. \u041F\u043E\u043C\u0438\u043C\u043E Rudra-s \u0438\u043C\u0435\u044E\u0442\u0441\u044F \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442 \u0441\u0443\u043F\u0440\u0443\u0433 \u0434\u043B\u044F \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0438\u0437 \u043D\u0438\u0445, \u0442.\u0435. \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442 Rudr\u0101\u1E47\u012B-s. \u0410\u0445, \u044D\u0442\u043E\u0442 \u043F\u0440\u0435\u0434\u043C\u0435\u0442 \u2014 \u043E\u0447\u0435\u043D\u044C \u0434\u043B\u0438\u043D\u043D\u044B\u0439 \u0438 \u0441\u043B\u043E\u0436\u043D\u044B\u0439. \u0414\u043B\u044F \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u044F \u0431\u043E\u043B\u0435\u0435 \u0434\u0435\u0442\u0430\u043B\u044C\u043D\u043E\u0439 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438, \u0432\u044B \u0432\u0441\u0435\u0433\u0434\u0430 \u043C\u043E\u0436\u0435\u0442\u0435 \u043E\u0431\u0440\u0430\u0442\u0438\u0442\u044C\u0441\u044F \u043A &quot;\u041F\u0438\u0441\u0430\u043D\u0438\u044F (\u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435)/\u015Aivas\u016Btravimar\u015Bin\u012B&quot; \u0432 \u0440\u0430\u0437\u0434\u0435\u043B\u0435 \u0422\u0440\u0438\u043A\u0430.</p></li><li><p>\u0427\u0442\u043E\u0431\u044B \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C \u0431\u043E\u043B\u044C\u0448\u0435 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 \u043E\u0431\u043E \u0432\u0441\u0435\u043C \u044D\u0442\u043E\u043C, \u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u043C\u043E\u0435 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0435 \u0432 II, 7 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F.</p></li><li><p>\u0418\u043C\u0435\u0435\u0442\u0441\u044F \u0441\u0435\u043C\u044C \u0442\u0438\u043F\u043E\u0432 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0445, \u0438\u043B\u0438 \u0441\u043A\u043E\u0440\u0435\u0435 \u0441\u0435\u043C\u044C \u044D\u0442\u0430\u043F\u043E\u0432 \u0434\u043B\u044F \u043E\u0434\u043D\u043E\u0433\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E:</p><ol><li>\u015Aiva (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u044D\u0442\u043E \u015Aiva \u0438 \u015Aakti \u0442\u0430\u0442\u0442\u0432\u044B, \u043F\u0435\u0440\u0432\u044B\u0435 \u0434\u0432\u0435 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438);</li><li>Mantramahe\u015Bvara (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u044D\u0442\u043E Sad\u0101\u015Biva-\u0442\u0430\u0442\u0442\u0432\u0430, \u0442\u0440\u0435\u0442\u044C\u044F \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F);</li><li>Mantre\u015Bvara (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u044D\u0442\u043E \u012A\u015Bvara-\u0442\u0430\u0442\u0442\u0432\u0430, \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0430\u044F \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F);</li><li>Mantra (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u044D\u0442\u043E Sadvidy\u0101, \u0438\u043B\u0438 \u015Auddhavidy\u0101 \u0442\u0430\u0442\u0442\u0432\u0430, \u043F\u044F\u0442\u0430\u044F \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F);</li><li>Vij\xF1\u0101n\u0101kala (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043C\u0435\u0436\u0434\u0443 Sadvidy\u0101 \u0438 M\u0101y\u0101 \u0442\u0430\u0442\u0442\u0432\u0430\u043C\u0438, \u0442.\u0435. \u043C\u0435\u0436\u0434\u0443 \u043F\u044F\u0442\u043E\u0439 \u0438 \u0448\u0435\u0441\u0442\u043E\u0439 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F\u043C\u0438);</li><li>Pralay\u0101kala (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u044D\u0442\u043E M\u0101y\u0101 \u0438 \u0435\u0435 \u043F\u044F\u0442\u044C Ka\xF1cuka-s, \u0441 \u0448\u0435\u0441\u0442\u043E\u0439 \u043F\u043E \u043E\u0434\u0438\u043D\u043D\u0430\u0434\u0446\u0430\u0442\u0443\u044E \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438);</li><li>Sakala (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 Puru\u1E63a --\u0434\u0432\u0435\u043D\u0430\u0434\u0446\u0430\u0442\u043E\u0439 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438-- \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0439).</li></ol></li><li><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u0430 \u0441\u0442\u0440\u043E\u0444\u0430, \u043A\u043E\u0442\u043E\u0440\u0443\u044E \u044F \u043F\u0435\u0440\u0435\u0432\u043E\u0436\u0443, \u0446\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u043B\u0430\u0441\u044C \u0440\u0430\u043D\u0435\u0435 K\u1E63emar\u0101ja \u0432 I, 4 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F, \u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u0442\u0430\u043C \u043F\u043E\u044F\u0441\u043D\u0435\u043D\u0438\u0435 2, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043D\u044F\u0442\u044C \u0435\u0435 \u0441\u043C\u044B\u0441\u043B.</p></li></ol></div><div class="stanza"><a href="#s3.20" id="s3.20" class="num">3.20</a><div class="sans"><p>\u092F\u0924 \u090F\u0935\u092E\u0924\u0903 \u0936\u0941\u0926\u094D\u0927\u0935\u093F\u0926\u094D\u092F\u093E\u0938\u094D\u0935\u0930\u0942\u092A\u092E\u0941\u0915\u094D\u0924\u092F\u0941\u0915\u094D\u0924\u093F\u092D\u093F\u0930\u093E\u0938\u093E\u0926\u093F\u0924\u092E\u092A\u093F \u092F\u0925\u093E \u0928 \u0928\u0936\u094D\u092F\u0924\u093F \u0924\u0925\u093E \u0938\u0930\u094D\u0935\u0926\u0936\u093E\u0938\u0941 \u092F\u094B\u0917\u093F\u0928\u093E \u0938\u093E\u0935\u0927\u093E\u0928\u0947\u0928 \u092D\u0935\u093F\u0924\u0935\u094D\u092F\u092E\u093F\u0924\u094D\u092F\u093E\u0939\u2014</p><blockquote><p><strong>\u0924\u094D\u0930\u093F\u0937\u0941 \u091A\u0924\u0941\u0930\u094D\u0925\u0902 \u0924\u0948\u0932\u0935\u0926\u093E\u0938\u0947\u091A\u094D\u092F\u092E\u094D\u0965\u0968\u0966\u0965</strong></p></blockquote><p>\u0924\u094D\u0930\u093F\u0937\u0941 \u091C\u093E\u0917\u0930\u093E\u0926\u093F\u0937\u0941 \u092A\u0926\u0947\u0937\u0941 \u091A\u0924\u0941\u0930\u094D\u0925\u0902 \u0936\u0941\u0926\u094D\u0927\u0935\u093F\u0926\u094D\u092F\u093E\u092A\u094D\u0930\u0915\u093E\u0936\u0930\u0942\u092A\u0902 \u0924\u0941\u0930\u094D\u092F\u093E\u0928\u0928\u094D\u0926\u0930\u0938\u093E\u0924\u094D\u092E\u0915\u0902 \u0927\u093E\u092E \u0924\u0948\u0932\u0935\u0926\u093F\u0924\u093F \u092F\u0925\u093E \u0924\u0948\u0932\u0902 \u0915\u094D\u0930\u092E\u0947\u0923\u093E\u0927\u093F\u0915\u092E\u0927\u093F\u0915\u0902 \u092A\u094D\u0930\u0938\u0930\u0926\u093E\u0936\u094D\u0930\u092F\u0902 \u0935\u094D\u092F\u093E\u092A\u094D\u0928\u094B\u0924\u093F \u0924\u0925\u093E\u0938\u0947\u091A\u094D\u092F\u092E\u094D\u0964 \u0924\u094D\u0930\u093F\u0937\u094D\u0935\u092A\u093F \u092A\u0926\u0947\u0937\u0942\u0928\u094D\u092E\u0947\u0937\u094B\u092A\u0936\u093E\u0928\u094D\u0924\u094D\u092F\u093E\u0924\u094D\u092E\u0915\u093E\u0926\u094D\u092F\u0928\u094D\u0924\u0915\u094B\u091F\u094D\u092F\u094B\u0903 \u092A\u0930\u093F\u0938\u094D\u092B\u0941\u0930\u0924\u093E \u0924\u0941\u0930\u094D\u092F\u0930\u0938\u0947\u0928 \u092E\u0927\u094D\u092F\u0926\u0936\u093E\u092E\u092A\u094D\u092F\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E \u0935\u094D\u092F\u093E\u092A\u094D\u0928\u0941\u092F\u093E\u0926\u094D\u092F\u0947\u0928 \u0924\u0928\u094D\u092E\u092F\u0940\u092D\u093E\u0935\u092E\u093E\u092A\u094D\u0928\u0941\u092F\u093E\u0924\u094D\u0964 \u091C\u093E\u0917\u094D\u0930\u0924\u094D\u0938\u094D\u0935\u092A\u094D\u0928\u0938\u0941\u0937\u0941\u092A\u094D\u0924\u0947\u0937\u0941 \u0924\u0941\u0930\u094D\u092F\u093E\u092D\u094B\u0917\u0938\u092E\u094D\u092D\u0935\u0903 (\u0967-\u096D) \u0907\u0924\u094D\u092F\u0928\u0947\u0928\u094B\u0926\u094D\u092F\u092E\u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u093E\u0928\u0941\u0938\u0928\u094D\u0927\u094D\u092F\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u092D\u093E\u091C\u0903 \u0938\u094D\u0935\u0930\u0938\u092A\u094D\u0930\u0938\u0930\u091C\u094D\u091C\u093E\u0917\u0930\u093E\u0926\u093F\u092A\u0926\u0947\u0937\u0941 \u0938\u0924\u094D\u0924\u093E\u092E\u093E\u0924\u094D\u0930\u0902 \u0924\u0941\u0930\u094D\u092F\u0938\u094D\u092F\u094B\u0915\u094D\u0924\u092E\u094D\u0964 \u0924\u094D\u0930\u093F\u0924\u092F\u092D\u094B\u0915\u094D\u0924\u093E \u0935\u0940\u0930\u0947\u0936\u0903 (\u0967-\u0967\u0967) \u0907\u0924\u093F \u0936\u093E\u092E\u094D\u092D\u0935\u094B\u092A\u093E\u092F\u093E\u0928\u0941\u0917\u0941\u0923\u0939\u0920\u092A\u093E\u0915\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E \u091C\u093E\u0917\u0930\u093E\u0926\u093F\u0938\u0902\u0939\u093E\u0930\u094B \u0926\u0930\u094D\u0936\u093F\u0924\u0903\u0964 \u0905\u0928\u0947\u0928 \u0924\u0941 \u0938\u0942\u0924\u094D\u0930\u0947\u0923\u093E\u0923\u0935\u094B\u091A\u093F\u0924\u093E\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E \u0926\u0932\u0915\u0932\u094D\u092A\u0902 \u091C\u093E\u0917\u0930\u093E\u0926\u093F\u0924\u094D\u0930\u092F\u0902 \u0924\u0941\u0930\u094D\u092F\u0930\u0938\u093E\u0938\u093F\u0915\u094D\u0924\u0902 \u0915\u093E\u0930\u094D\u092F\u092E\u093F\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u092E\u093F\u0924\u093F \u0935\u093F\u0936\u0947\u0937\u0903\u0965\u0968\u0966\u0965</p></div><hr><div class="trans"><p>Yata evamata\u1E25 \u015Buddhavidy\u0101svar\u016Bpamuktayuktibhir\u0101s\u0101ditamapi yath\u0101 na na\u015Byati tath\u0101 sarvada\u015B\u0101su yogin\u0101 s\u0101vadh\u0101nena bhavitavyamity\u0101ha\u2014</p><blockquote><p><strong>Tri\u1E63u caturtha\u1E41 tailavad\u0101secyam||20||</strong></p></blockquote><p>Tri\u1E63u j\u0101gar\u0101di\u1E63u pade\u1E63u caturtha\u1E41 \u015Buddhavidy\u0101prak\u0101\u015Bar\u016Bpa\u1E41 tury\u0101nandaras\u0101tmaka\u1E41 dh\u0101ma tailavaditi yath\u0101 taila\u1E41 krame\u1E47\u0101dhikamadhika\u1E41 prasarad\u0101\u015Braya\u1E41 vy\u0101pnoti tath\u0101secyam| Tri\u1E63vapi pade\u1E63\u016Bnme\u1E63opa\u015B\u0101nty\u0101tmak\u0101dyantako\u1E6Dyo\u1E25 parisphurat\u0101 turyarasena madhyada\u015B\u0101mapyava\u1E63\u1E6Dambhayukty\u0101 vy\u0101pnuy\u0101dyena tanmay\u012Bbh\u0101vam\u0101pnuy\u0101t| J\u0101gratsvapnasu\u1E63upte\u1E63u tury\u0101bhogasambhava\u1E25 (1-7) ityanenodyama\u015Bakticakr\u0101nusandhyava\u1E63\u1E6Dambhabh\u0101ja\u1E25 svarasaprasarajj\u0101gar\u0101dipade\u1E63u satt\u0101m\u0101tra\u1E41 turyasyoktam| Tritayabhokt\u0101 v\u012Bre\u015Ba\u1E25 (1-11) iti \u015B\u0101mbhavop\u0101y\u0101nugu\u1E47aha\u1E6Dhap\u0101kayukty\u0101 j\u0101gar\u0101disa\u1E41h\u0101ro dar\u015Bita\u1E25| Anena tu s\u016Btre\u1E47\u0101\u1E47avocit\u0101va\u1E63\u1E6Dambhayukty\u0101 dalakalpa\u1E41 j\u0101gar\u0101ditraya\u1E41 turyaras\u0101sikta\u1E41 k\u0101ryamityuktamiti vi\u015Be\u1E63a\u1E25||20||</p></div><hr><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yatas)</em> [\u044D\u0442\u043E \u043E\u0431\u0441\u0442\u043E\u0438\u0442] \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em> --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0434\u0430\u0436\u0435 \u0442\u043E\u0442, \u043A\u0442\u043E \u0434\u043E\u0441\u0442\u0438\u0433 \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0430, \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0432\u0441\u0435 \u0435\u0449\u0435 \u043E\u0431\u043C\u0430\u043D\u0443\u0442 \u0442\u0430\u043A\u0438\u043C\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0430\u043C\u0438--, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(atas)</em> Yog\u012B \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u0435\u043D \u0438 \u043E\u0441\u0442\u043E\u0440\u043E\u0436\u0435\u043D <em>(tath\u0101... yogin\u0101 s\u0101vadh\u0101nena bhavitavyam)</em> \u043F\u0440\u0438 \u0432\u0441\u0435\u0445 \u043E\u0431\u0441\u0442\u043E\u044F\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u0430\u0445 <em>(sarva-da\u015B\u0101su)</em>, \u0447\u0442\u043E\u0431\u044B <em>(yath\u0101)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(sva-r\u016Bpam)</em> \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F <em>(\u015Buddha-vidy\u0101)</em>, \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u043D\u043E\u0433\u043E [\u0438\u043C] <em>(\u0101s\u0101ditam api)</em>, \u043D\u0435 \u0438\u0441\u0447\u0435\u0437\u043B\u0430 <em>(na na\u015Byati)</em>. [\u015Aiva, \u0430\u0432\u0442\u043E\u0440 \u015Aivas\u016Btra-s,] \u0441\u043A\u0430\u0437\u0430\u043B \u0442\u0430\u043A <em>(iti \u0101ha)</em>\u2014</p><blockquote><p><strong>\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, [\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0435\u043C] <em>(caturtham)</em>, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u043B\u0438\u0432\u0430\u0442\u044C <em>(\u0101secyam)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u043E <em>(vat)</em> [\u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u043C\u0443 \u043F\u043E\u0442\u043E\u043A\u0443] \u043C\u0430\u0441\u043B\u0430 <em>(taila)</em> \u0432 [\u0434\u0440\u0443\u0433\u0438\u0435] \u0442\u0440\u0438 <em>(tri\u1E63u)</em>, [\u0442.\u0435. \u0432 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0441\u043E\u043D \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D]||20||</strong></p></blockquote><p>[\u0422\u0435\u0440\u043C\u0438\u043D] tri\u1E63u <em>(tri\u1E63u)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0432 [\u0434\u0440\u0443\u0433\u0438\u0435 \u0442\u0440\u0438] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(pade\u1E63u)</em> \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u043F\u0440.<em>(j\u0101gar\u0101-\u0101di\u1E63u)</em>. [\u0421\u043B\u043E\u0432\u043E] caturtha --\u0442.\u0435. \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435-- <em>(caturtham)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(dh\u0101ma)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0438\u0437 <em>(\u0101tmakam)</em> \u044D\u043B\u0438\u043A\u0441\u0438\u0440\u0430 <em>(rasa)</em> \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 \u0422\u0443\u0440\u044C\u0438 --\u0442.\u0435. \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(turya-\u0101nanda)</em>, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(r\u016Bpam)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0421\u0432\u0435\u0442 <em>(prak\u0101\u015Ba)</em> \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F <em>(\u015Buddha-vidy\u0101)</em>. [\u0412\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435] &quot;tailavat&quot; <em>(taila-vat iti)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043E] \u0442\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435, \u043A\u0430\u043A <em>(yath\u0101)</em> [\u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u044B\u0439 \u043F\u043E\u0442\u043E\u043A] \u043C\u0430\u0441\u043B\u0430 <em>(tailam)</em>, \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u044F\u044F\u0441\u044C <em>(krame\u1E47a... prasarat)</em> \u0431\u043E\u043B\u044C\u0448\u0435 \u0438 \u0431\u043E\u043B\u044C\u0448\u0435 <em>(adhikam adhikam)</em>, \u0437\u0430\u043F\u043E\u043B\u043D\u044F\u0435\u0442 <em>(vy\u0101pnoti)</em> \u043F\u043E\u043B\u0443\u0447\u0430\u0442\u0435\u043B\u044F <em>(\u0101\u015Brayam)</em>, \u0442\u0430\u043A\u0436\u0435 <em>(tath\u0101)</em> \u0438 [\u0447\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F] \u0434\u043E\u043B\u0436\u043D\u043E \u0432\u043B\u0438\u0432\u0430\u0442\u044C\u0441\u044F <em>(\u0101secyam)</em> [\u0432 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0441\u043E\u043D \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D]|</p><p>\u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043C\u0435\u0442\u043E\u0434\u0430 <em>(yukty\u0101)</em> \u043D\u0435\u043F\u043E\u043A\u043E\u043B\u0435\u0431\u0438\u043C\u043E\u0433\u043E \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043D\u0438\u044F --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0433\u043E \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u044F \u043A \u0421\u0430\u043C\u043E\u0441\u0442\u0438, \u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0439\u0441\u044F \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0435\u043C-- <em>(ava\u1E63\u1E6Dambha)</em>, [Yog\u012B] \u0434\u043E\u043B\u0436\u0435\u043D \u0442\u0430\u043A\u0436\u0435 \u043F\u0440\u043E\u043F\u0438\u0442\u044B\u0432\u0430\u0442\u044C <em>(api... vy\u0101pnuy\u0101t)</em> \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u0447\u043D\u043E\u0435 <em>(madhya)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(da\u015B\u0101m)</em> \u044D\u043B\u0438\u043A\u0441\u0438\u0440\u043E\u043C <em>(rasena)</em> \u0422\u0443\u0440\u044C\u0438 (Turya) --\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F-- <em>(uktam)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(parisphurat\u0101)</em> \u043D\u0430 \u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0438 \u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0439 \u0442\u043E\u0447\u043A\u0430\u0445 <em>(\u0101di-anta-ko\u1E6Dyo\u1E25)</em> \u2014\u0433\u0434\u0435 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435 <em>(upa\u015B\u0101nti-\u0101tmaka)</em> unme\u1E63a --\u0442.\u0435. \u043E\u0442\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u043E\u0431\u044A\u0435\u043C\u043B\u044E\u0449\u0435\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F-- <em>(unme\u1E63a)</em>\u2014 \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0442\u0440\u0435\u0445 <em>(tri\u1E63u api)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 [\u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430] <em>(pade\u1E63u)</em>. \u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u044D\u0442\u043E\u0433\u043E --\u0442.\u0435. \u0434\u0435\u043B\u0430\u044F \u0442\u0430\u043A-- <em>(yena)</em>, [\u0433\u0440\u0443\u043F\u043F\u0430 \u0442\u0440\u0435\u0445 \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F] \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(\u0101pnuy\u0101t)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(bh\u0101vam)</em> \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u044F <em>(may\u012B)</em> \u0441 \u042D\u0442\u0438\u043C --\u0441 \u0422\u0443\u0440\u044C\u0435\u0439, \u0438\u043B\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u044B\u043C \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C-- <em>(tad)</em><sup>1</sup>|</p><p>&quot;[\u0414\u0430\u0436\u0435] \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u044D\u0442\u0438\u0445 \u0440\u0430\u0437\u043D\u044B\u0445 [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(bhede)</em>, \u043A\u0430\u043A \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 <em>(j\u0101grat)</em>, \u0441\u043E\u043D \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 <em>(svapna)</em> \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D <em>(su\u1E63upta)</em>, \u0438\u043C\u0435\u044E\u0442 \u043C\u0435\u0441\u0442\u043E <em>(sambhava\u1E25)</em> \u0432\u043E\u0441\u0442\u043E\u0440\u0433 \u0438 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 <em>(\u0101bhoga)</em> \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(turya)</em>. (I, 7) [\u0434\u0430\u043D\u043D\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F] <em>(1-7 iti)</em>&quot;. \u042D\u0442\u0438\u043C [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u043C] <em>(anena)</em>, \u0431\u044B\u043B\u043E \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u043E <em>(uktam)</em> \u0442\u043E\u043B\u044C\u043A\u043E <em>(m\u0101tra)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 <em>(satt\u0101)</em> \u0422\u0443\u0440\u044C\u0438 <em>(turyasya)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u044F\u0435\u0442 <em>(prasarat)</em> \u0441\u0432\u043E\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 <em>(sva)</em> \u044D\u043B\u0438\u043A\u0441\u0438\u0440 <em>(rasa)</em> \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(pade\u1E63u)</em> \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(j\u0101gar\u0101)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, [\u0432 \u0441\u043B\u0443\u0447\u0430\u0435] \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u043F\u0440\u0435\u0434\u0430\u043D <em>(bh\u0101ja\u1E25)</em> \u043D\u0435\u043F\u043E\u043A\u043E\u043B\u0435\u0431\u0438\u043C\u043E\u043C\u0443 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043D\u0438\u044E <em>(ava\u1E63\u1E6Dambha)</em> \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u0433\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(anusandhi)</em> \u0433\u0440\u0443\u043F\u043F\u044B <em>(cakra)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em> [\u0438\u043B\u0438 \u043F\u0440\u043E\u0449\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u0442\u043E\u0433\u043E, \u0432 \u043A\u043E\u043C \u0438\u043C\u0435\u0435\u0442\u0441\u044F] udyama, \u0438\u043B\u0438 \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E\u0435 \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F [\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F] <em>(udyama)</em>|</p><p>&quot;\u041E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u0435\u043C <em>(\u012B\u015Ba\u1E25)</em> [\u0441\u0432\u043E\u0438\u0445] \u0447\u0443\u0432\u0441\u0442\u0432 <em>(v\u012Bra)</em>, \u0442\u0435\u043C, \u043A\u0442\u043E \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u0435\u0442\u0441\u044F [\u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u043C &quot;\u0101bhoga&quot;, \u0438\u043B\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0432\u043E\u0441\u0442\u043E\u0440\u0433\u043E\u043C] <em>(bhokt\u0101)</em> \u0432 \u0442\u0440\u0438\u0430\u0434\u0435 [\u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430] <em>(tritaya)</em>. (I, 11) [\u0434\u0430\u043D\u043D\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F] <em>(1-11 iti)</em>&quot;. [\u0412 \u044D\u0442\u043E\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435,] \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(sa\u1E41h\u0101ra\u1E25)</em> \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(j\u0101gar\u0101)</em>, \u0438 \u043F\u0440. <em>(\u0101di)</em> \u0431\u044B\u043B\u043E \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u043E <em>(dar\u015Bita\u1E25)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043C\u0435\u0442\u043E\u0434\u0430 <em>(yukty\u0101)</em> ha\u1E6Dhap\u0101ka --\u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E, \u0430\u0441\u0441\u0438\u043C\u0438\u043B\u044F\u0446\u0438\u0435\u0439 \u0441\u0438\u043B\u044B \u0438 \u0443\u043F\u043E\u0440\u0441\u0442\u0432\u0430-- <em>(ha\u1E6Dha-p\u0101ka)</em> \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 <em>(anugu\u1E47a)</em> \u015A\u0101mbhavop\u0101ya --\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430\u043C\u0438, \u0438\u043B\u0438 \u043C\u0435\u0442\u043E\u0434\u0430\u043C\u0438, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u043C\u0438\u0441\u044F \u043A \u015Aiva-- <em>(\u015B\u0101mbhava-up\u0101ya)</em><sup>2</sup></p><p>. \u041E\u0434\u043D\u0430\u043A\u043E <em>(tu)</em>, \u0432 \u044D\u0442\u043E\u043C <em>(anena)</em> \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 --\u0442.\u0435. \u0432 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u043C\u043E\u043C-- <em>(s\u016Btre\u1E47a)</em> \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F, \u0447\u0442\u043E <em>(iti uktam)</em> \u0442\u0440\u0438\u0430\u0434\u0430 <em>(trayam)</em> \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 <em>(j\u0101gar\u0101)</em>, \u0438 \u043F\u0440. <em>(\u0101di)</em>, \u043F\u043E\u0434\u043E\u0431\u043D\u0430\u044F <em>(kalpam)</em> \u043D\u043E\u0436\u043D\u0430\u043C \u043C\u0435\u0447\u0430 <em>(dala)</em><sup>3</sup>, \u0434\u043E\u043B\u0436\u043D\u0430 \u0431\u044B\u0442\u044C \u043F\u0440\u043E\u043F\u0438\u0442\u0430\u043D\u0430 <em>(\u0101siktam k\u0101ryam)</em> \u044D\u043B\u0438\u043A\u0441\u0438\u0440\u043E\u043C <em>(rasa)</em> \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(turya)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043C\u0435\u0442\u043E\u0434\u0430 <em>(yukty\u0101)</em> [\u0432\u044B\u0448\u0435\u0443\u043A\u0430\u0437\u0430\u043D\u043D\u043E\u0433\u043E] \u043D\u0435\u043F\u043E\u043A\u043E\u043B\u0435\u0431\u0438\u043C\u043E\u0433\u043E \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043D\u0438\u044F <em>(ava\u1E63\u1E6Dambha)</em>, \u0441\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(ucita)</em> \u0100\u1E47avop\u0101ya --\u0441\u0440\u0435\u0434\u0441\u0442\u0432, \u0438\u043B\u0438 \u043C\u0435\u0442\u043E\u0434\u043E\u0432, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u0445\u0441\u044F \u043A a\u1E47u, \u0438\u043B\u0438 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0439 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438-- <em>(\u0101\u1E47ava)</em>. \u0412 \u044D\u0442\u043E\u043C \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435 <em>(iti vi\u015Be\u1E63a\u1E25)</em> [\u043C\u0435\u0436\u0434\u0443 \u044D\u0442\u0438\u043C\u0438 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430\u043C\u0438, \u0442.\u0435. \u043C\u0435\u0436\u0434\u0443 I, 7, I, 11 \u0438 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0438\u043C --III, 20--]||20||</p><hr><ol><li>\u0427\u0442\u043E\u0431\u044B \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u043E\u043D\u044F\u0442\u044C, \u0447\u0442\u043E \u043C\u0443\u0434\u0440\u0435\u0446 \u0445\u043E\u0442\u0435\u043B \u0432\u044B\u0440\u0430\u0437\u0438\u0442\u044C \u0432 \u044D\u0442\u043E\u043C \u0430\u0431\u0437\u0430\u0446\u0435, \u0432\u0430\u043C \u043D\u0430\u0434\u043E \u0431\u044B\u0442\u044C Yog\u012B, \u0445\u043E\u0440\u043E\u0448\u043E \u0437\u043D\u0430\u043A\u043E\u043C\u044B\u043C \u0441 \u044D\u0442\u0438\u043C\u0438 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430\u043C\u0438. \u0412 \u043B\u044E\u0431\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u0435\u0441\u043B\u0438 \u0432\u044B \u0435\u0449\u0435 \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0435\u0441\u044C Yog\u012B, \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u043F\u043E\u043F\u044B\u0442\u0430\u0442\u044C\u0441\u044F \u043F\u043E\u043D\u044F\u0442\u044C \u044D\u0442\u043E \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0443\u0430\u043B\u044C\u043D\u043E. \u0421\u043B\u0443\u0448\u0430\u0439\u0442\u0435: \u0411\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u043B\u044E\u0434\u0435\u0439 \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u044E\u0442 \u0441\u0432\u043E\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0412\u044B\u0441\u0448\u0435\u0435 \u042F \u0442\u043E\u043B\u044C\u043A\u043E \u0432 \u043D\u0430\u0447\u0430\u043B\u0435 \u0438 \u0432 \u043A\u043E\u043D\u0446\u0435 \u0442\u0440\u0435\u0445 \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F (\u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430). \u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u043D\u0430 \u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u043C \u044D\u0442\u0430\u043F\u0435 \u0441\u0432\u043E\u0435\u0439 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u2014 \u0442\u0430\u043A\u043E\u0439 \u0436\u0435 \u043A\u0430\u043A \u0438 \u0432\u0441\u0435 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u0435\u0433\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 \u0421\u0430\u043C\u043E\u0441\u0442\u0438, \u043A\u0430\u043A \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u044F, \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u0432 \u043D\u0430\u0447\u0430\u043B\u044C\u043D\u044B\u0445 \u0438 \u043A\u043E\u043D\u0435\u0447\u043D\u044B\u0445 \u0442\u043E\u0447\u043A\u0430\u0445 \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439. \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u042F, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E \u043A\u0430\u043A Turya, \u0438\u043B\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u043E \u043E\u0442\u043B\u0438\u0447\u0430\u0435\u0442\u0441\u044F \u043E\u0442 \u0442\u0440\u0435\u0445 \u0434\u0440\u0443\u0433\u0438\u0445. \u041A\u043E\u0433\u0434\u0430 \u043E\u0431\u044B\u0447\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F (\u0431\u0443\u0434\u044C \u0442\u043E \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0441\u043E\u043D \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438\u043B\u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D) \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0438\u043B\u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F, \u0432 \u044D\u0442\u043E\u0442 \u043C\u043E\u043C\u0435\u043D\u0442 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435 \u0443\u043D\u043C\u0435\u0448\u0438 (unme\u1E63a), \u0438\u043B\u0438 \u043E\u0442\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u043E\u0431\u044A\u0435\u043C\u043B\u044E\u0449\u0435\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F. \u041F\u043E\u0434 unme\u1E63a \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442\u0441\u044F \u043B\u044E\u0431\u043E\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0434\u0435\u0440\u0435\u0432\u043E), \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0441\u0442\u0440\u0430\u043D\u043D\u044B\u0435 \u0446\u0432\u0435\u0442\u0430) \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u043F\u0443\u0441\u0442\u043E\u0442\u0430). Unme\u1E63a \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0442\u043E\u043B\u044C\u043A\u043E &quot;\u043F\u043E\u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435&quot; \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F. \u0412 \u0438\u0445 \u043D\u0430\u0447\u0430\u043B\u0435 \u0438 \u0432 \u043A\u043E\u043D\u0446\u0435 unme\u1E63a \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442.</li></ol><p>\u0421 \u0434\u0440\u0443\u0433\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B, Turya, \u0438\u043B\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u043E\u0442\u0445\u043E\u0434\u0438\u0442 \u043E\u0442 \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B, \u0442.\u043A. \u0434\u043B\u0438\u0442\u0441\u044F \u0432\u0435\u0447\u043D\u043E. \u042D\u0442\u043E \u043D\u0435 \u043F\u043E\u0445\u043E\u0436\u0435 \u043D\u0430 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u0442\u0440\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043F\u0440\u0435\u0445\u043E\u0434\u044F\u0449\u0438\u043C\u0438. Turya \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u0447\u0435\u0432\u0438\u0434\u043D\u043E\u0439 \u0434\u043B\u044F \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u0430 \u043B\u044E\u0434\u0435\u0439, \u0442\u043E\u043B\u044C\u043A\u043E \u043A\u043E\u0433\u0434\u0430 unme\u1E63a \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442, \u043D\u043E \u043A\u043E\u0433\u0434\u0430 \u043E\u043D\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F, \u044D\u0442\u0438 \u043B\u044E\u0434\u0438 \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u044E\u0442 \u0441\u0432\u043E\u0435 \u0412\u044B\u0441\u0448\u0435\u0435 \u042F. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 Yog\u012B \u043F\u0440\u043E\u0434\u0432\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0432 \u0441\u0432\u043E\u0435\u0439 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0435, \u043E\u0434\u043D\u0430\u0436\u0434\u044B \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0427\u0438\u0441\u0442\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435 (\u015Auddhavidy\u0101), \u0438 \u043E\u043D \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 \u0441\u0432\u043E\u044E \u0421\u0430\u043C\u043E\u0441\u0442\u044C, \u043A\u0430\u043A \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u044F \u0432\u0441\u0435\u0445 \u0441\u0432\u043E\u0438\u0445 \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u0439, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0445 \u0441 \u043D\u0438\u043C \u0432 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0438, \u0432\u043E \u0441\u043D\u0435 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u043C \u0441\u043D\u0435. \u042D\u0442\u043E \u0437\u043D\u0430\u043C\u0435\u043D\u0443\u0435\u0442 \u0441\u043E\u0431\u043E\u0439 \u0435\u0433\u043E \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 \u0422\u0443\u0440\u044C\u0438. \u0421 \u044D\u0442\u043E\u0433\u043E \u043C\u043E\u043C\u0435\u043D\u0442\u0430 \u0435\u043C\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0437\u0430\u0441\u0442\u0430\u0432\u0438\u0442\u044C Turya \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E \u043F\u0440\u043E\u043F\u0438\u0442\u044B\u0432\u0430\u0442\u044C \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u0442\u0440\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u043C\u0443 \u043F\u043E\u0442\u043E\u043A\u0443 \u043C\u0430\u0441\u043B\u0430, \u043D\u0430\u043F\u043E\u043B\u043D\u044F\u044E\u0449\u0435\u043C\u0443 \u043F\u043E\u043B\u0443\u0447\u0430\u0442\u0435\u043B\u044F. \u0412 \u043A\u043E\u043D\u0446\u0435 \u043A\u043E\u043D\u0446\u043E\u0432, \u0432\u0441\u0435 \u044D\u0442\u0438 \u0442\u0440\u0438 \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F (\u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0441\u043E\u043D \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D) \u0441\u0442\u0430\u043D\u0443\u0442 \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B \u0441 Turya \u0438 \u043E\u0441\u0442\u0430\u043D\u0435\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E &quot;\u043E\u0434\u043D\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435&quot;, \u0442.\u0435. Yog\u012B \u0431\u0443\u0434\u0435\u0442 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D \u0432 \u0441\u0432\u043E\u0435\u043C \u0412\u044B\u0441\u0448\u0435\u043C \u042F \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E. \u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, \u0442\u043E\u043B\u044C\u043A\u043E \u044D\u0442\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0432\u0435\u0447\u043D\u043E. \u0414\u0440\u0443\u0433\u0438\u0435 \u0442\u0440\u0438 \u2014 \u044D\u0442\u043E \u043F\u0440\u043E\u0441\u0442\u043E \u0431\u043B\u0430\u0436\u0435\u043D\u043D\u0430\u044F \u0438\u0433\u0440\u0430 \u015Aakti. \u041E\u043D\u0438 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0442, \u043A\u043E\u0433\u0434\u0430 \u041E\u043D\u0430 (\u043F\u043E \u0432\u0441\u0435\u0439 \u0432\u0438\u0434\u0438\u043C\u043E\u0441\u0442\u0438) \u043C\u0430\u0441\u043A\u0438\u0440\u0443\u0435\u0442 Turya \u0438 \u044D\u043A\u0441\u043F\u043E\u043D\u0438\u0440\u0443\u0435\u0442 unme\u1E63a, \u0438\u043B\u0438 \u043E\u0442\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u043E\u0431\u044A\u0435\u043C\u043B\u044E\u0449\u0435\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F. \u041F\u043E\u043C\u0438\u043C\u043E \u043C\u043E\u0438\u0445 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0439, \u0432\u0441\u0435 \u044D\u0442\u043E \u2014 \u0432\u043E\u043F\u0440\u043E\u0441 \u043B\u0438\u0447\u043D\u043E\u0433\u043E \u043E\u043F\u044B\u0442\u0430. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0435\u0441\u044C \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0438\u043C Yog\u012B \u0438 \u0438\u0441\u043F\u044B\u0442\u0430\u0439\u0442\u0435 \u0432\u0430\u0448\u0443 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0431\u0435\u0437\u0433\u0440\u0430\u043D\u0438\u0447\u043D\u043E\u0441\u0442\u044C. OK, \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E.</p><ol start="2"><li><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u043E\u0442 \u0430\u0444\u043E\u0440\u0438\u0437\u043C (I, 11) \u2014 \u0438\u0437 \u043F\u0435\u0440\u0432\u043E\u0439 \u0433\u043B\u0430\u0432\u044B, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0435\u0439\u0441\u044F \u043A \u015A\u0101mbhavop\u0101ya, \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F (\u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438, \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430) \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u043E \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043C\u0435\u0442\u043E\u0434\u0430 ha\u1E6Dhap\u0101ka, \u0438\u043B\u0438 \u0430\u0441\u0441\u0438\u043C\u0438\u043B\u044F\u0446\u0438\u0438 \u043E\u043F\u044B\u0442\u0430 \u0441\u0438\u043B\u043E\u0439 \u0438 \u043D\u0430\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u044C\u044E, (\u0432\u044B\u0440\u0430\u0436\u0430\u044F\u0441\u044C \u0444\u0438\u0433\u0443\u0440\u0430\u043B\u044C\u043D\u043E), &quot;\u043E\u0434\u043D\u0438\u043C \u043C\u0430\u0445\u043E\u043C&quot;. \u042D\u0442\u043E\u0442 \u043C\u0435\u0442\u043E\u0434 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A kram\u0101tikrama, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D \u0432\u044B\u0445\u043E\u0434\u0438\u0442 \u0437\u0430 \u0440\u0430\u043C\u043A\u0438 krama, \u0438\u043B\u0438 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u0442.\u043A. Yog\u012B \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0437\u0430 \u043E\u0434\u0438\u043D \u0448\u0430\u0433. \u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u044D\u0442\u043E \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u043D\u0435\u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E\u0439 \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0439 \u0441\u0438\u043B\u044B, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0443 \u043F\u043E\u0434\u0430\u0432\u043B\u044F\u044E\u0449\u0435\u0433\u043E \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u0430 \u0443\u0447\u0435\u043D\u0438\u043A\u043E\u0432. \u0411\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u043B\u044E\u0434\u0435\u0439 \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0442 \u0441\u0432\u043E\u0439 \u0434\u0443\u0445\u043E\u0432\u043D\u044B\u0439 \u043F\u0443\u0442\u044C \u0441 \u0100\u1E47avop\u0101ya \u0438 \u0441\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0435\u043C \u043E\u043D\u0438 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442 \u015A\u0101ktop\u0101ya \u0438 \u015A\u0101mbhavop\u0101ya (\u043E\u0431\u044B\u0447\u043D\u043E \u044D\u0442\u043E \u0437\u0430\u043D\u0438\u043C\u0430\u0435\u0442 \u043C\u043D\u043E\u0433\u043E \u043B\u0435\u0442, \u0434\u0435\u0441\u044F\u0442\u0438\u043B\u0435\u0442\u0438\u0439 \u0438\u043B\u0438 \u0434\u0430\u0436\u0435 \u0432\u0441\u044E \u0436\u0438\u0437\u043D\u044C). \u0422\u043E\u043B\u044C\u043A\u043E \u0435\u0434\u0438\u043D\u0438\u0446\u044B \u043D\u0430\u0447\u043D\u0443\u0442 \u0441 \u015A\u0101ktop\u0101ya, \u0438 \u0442\u043E\u043B\u044C\u043A\u043E \u0441\u0430\u043C\u044B\u0435 \u0434\u043E\u0441\u0442\u043E\u0439\u043D\u044B\u0435 \u043D\u0430\u0447\u043D\u0443\u0442 \u0441\u0432\u043E\u0435 \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0435 \u043F\u0443\u0442\u0435\u0448\u0435\u0441\u0442\u0432\u0438\u0435 \u0441 \u015A\u0101mbhavop\u0101ya. \u041E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u0447\u0435\u043C \u043C\u0435\u043D\u0435\u0435 \u0434\u043E\u0441\u0442\u043E\u0435\u043D \u0443\u0447\u0435\u043D\u0438\u043A, \u0442\u0435\u043C \u0441 \u0431\u043E\u043B\u0435\u0435 \u0432\u044B\u0441\u043E\u043A\u043E\u0439 up\u0101ya (\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430, \u0438\u043B\u0438 \u043C\u0435\u0442\u043E\u0434\u0430) \u043E\u043D \u0445\u043E\u0447\u0435\u0442 \u043D\u0430\u0447\u0430\u0442\u044C, \u0445\u0430-\u0445\u0430! \u0412 \u0446\u0435\u043B\u043E\u043C, \u044D\u0442\u043E \u043E\u0431\u044B\u0447\u043D\u0430\u044F \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u0430 \u0441 \u043B\u044E\u0434\u044C\u043C\u0438: \u043E\u043D\u0438 \u043F\u0435\u0440\u0435\u043E\u0446\u0435\u043D\u0438\u0432\u0430\u044E\u0442 \u0441\u0432\u043E\u0438 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u0438, \u0438\u043C\u0435\u044F \u0434\u0435\u043B\u043E \u0441 \u0434\u0443\u0445\u043E\u0432\u043D\u044B\u043C\u0438 \u0432\u043E\u043F\u0440\u043E\u0441\u0430\u043C\u0438. \u0412 \u043A\u043B\u0430\u0441\u0441\u0435 \u043F\u043E \u043A\u0432\u0430\u043D\u0442\u043E\u0432\u043E\u0439 \u0444\u0438\u0437\u0438\u043A\u0435 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0438\u0437 \u043D\u0438\u0445 \u043D\u0430\u0432\u0435\u0440\u043D\u044F\u043A\u0430 \u0431\u0443\u0434\u0443\u0442 \u043E\u0441\u0442\u0430\u0432\u0430\u0442\u044C\u0441\u044F \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u0431\u0435\u0437\u043C\u043E\u043B\u0432\u043D\u044B\u043C\u0438, \u043D\u043E \u0432 \u043A\u043B\u0430\u0441\u0441\u0435 \u0419\u043E\u0433\u0438 \u043E\u043D\u0438 \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F \u0432\u044B\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0442 \u0441\u0432\u043E\u0435 \u043C\u043D\u0435\u043D\u0438\u0435 \u043F\u043E\u0447\u0442\u0438 \u043E\u0431\u043E \u0432\u0441\u0435\u043C. \u041F\u043E\u0447\u0435\u043C\u0443? \u0418\u0437-\u0437\u0430 \u0438\u0445 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0430, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0433\u043E\u0441\u044F \u0432 \u0432\u0438\u0434\u0435 \u0432\u044B\u0441\u043E\u043A\u043E\u043C\u0435\u0440\u0438\u044F. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0419\u043E\u0433\u0430 \u2014 \u043E\u0447\u0435\u043D\u044C \u0441\u043B\u043E\u0436\u043D\u0430\u044F/\u0433\u043B\u0443\u0431\u043E\u043A\u0430\u044F \u043D\u0430\u0443\u043A\u0430, \u0442\u043E\u043B\u044C\u043A\u043E \u044D\u043A\u0441\u043F\u0435\u0440\u0442\u044B \u0419\u043E\u0433\u0438 \u0438 \u0443\u0447\u0435\u043D\u044B\u0435 \u043C\u043E\u0433\u0443\u0442 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C \u0447\u0442\u043E-\u0442\u043E, \u0447\u0442\u043E \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0441\u0442\u043E\u0438\u0442 \u0443\u0441\u043B\u044B\u0448\u0430\u0442\u044C.</p></li><li><p>\u0417\u0434\u0435\u0441\u044C \u0442\u0435\u0440\u043C\u0438\u043D &quot;dala&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0916\u0921\u094D\u0917\u0915\u094B\u0936&quot; - &quot;kha\u1E0Dgako\u015Ba&quot;, \u0438\u043B\u0438 \u043D\u043E\u0436\u043D\u044B \u043C\u0435\u0447\u0430. \u041F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u043A\u0430\u043A \u043D\u043E\u0436\u043D\u044B \u043C\u0435\u0447\u0430 \u043E\u0442\u043B\u0438\u0447\u0430\u044E\u0442\u0441\u044F \u043E\u0442 \u043C\u0435\u0447\u0430, \u043D\u043E \u043E\u043D\u0438 \u043C\u043E\u0433\u0443\u0442 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044C \u0435\u0433\u043E, \u0442\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435 \u0442\u0440\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u043E\u0442\u043B\u0438\u0447\u0430\u044E\u0442\u0441\u044F \u043E\u0442 Turya (\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F), \u043D\u043E \u043E\u043D\u0438 \u043C\u043E\u0433\u0443\u0442 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044C \u0438 \u043D\u0430\u043F\u043E\u043B\u043D\u044F\u0442\u044C\u0441\u044F \u0438\u043C.</p></li></ol></div><div class="stanza"><a href="#s3.21" id="s3.21" class="num">3.21</a><div class="sans"><p>\u0905\u0924\u094D\u0930\u094B\u092A\u093E\u092F\u092E\u093E\u0939\u2014</p><blockquote><p><strong>\u092E\u0917\u094D\u0928\u0903 \u0938\u094D\u0935\u091A\u093F\u0924\u094D\u0924\u0947\u0928 \u092A\u094D\u0930\u0935\u093F\u0936\u0947\u0924\u094D\u0965\u0968\u0967\u0965</strong></p></blockquote><blockquote><p>\u092A\u094D\u0930\u093E\u0923\u093E\u0926\u093F\u0938\u094D\u0925\u0942\u0932\u092D\u093E\u0935\u0902 \u0924\u0941 \u0924\u094D\u092F\u0915\u094D\u0924\u094D\u0935\u093E \u0938\u0942\u0915\u094D\u0937\u094D\u092E\u092E\u0925\u093E\u0928\u094D\u0924\u0930\u092E\u094D\u0964<br> \u0938\u0942\u0915\u094D\u0937\u094D\u092E\u093E\u0924\u0940\u0924\u0902 \u0924\u0941 \u092A\u0930\u092E\u0902 \u0938\u094D\u092A\u0928\u094D\u0926\u0928\u0902 \u0932\u092D\u094D\u092F\u0924\u0947 \u092F\u0924\u0903\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u092A\u0915\u094D\u0930\u092E\u094D\u092F</p><blockquote><p>... \u092A\u094D\u0930\u0935\u093F\u0936\u0947\u0924\u094D\u0924\u0924\u094D\u0938\u094D\u0935\u091A\u0947\u0924\u0938\u093E\u0965</p></blockquote><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u092E\u0943\u0924\u094D\u092F\u0941\u091C\u093F\u0926\u094D\u092D\u091F\u094D\u091F\u093E\u0930\u0915\u0928\u093F\u0930\u0942\u092A\u093F\u0924\u0928\u0940\u0924\u094D\u092F\u093E \u092A\u094D\u0930\u093E\u0923\u093E\u092F\u093E\u092E\u0927\u094D\u092F\u093E\u0928\u0927\u093E\u0930\u0923\u093E\u0926\u093F\u0938\u094D\u0925\u0942\u0932\u094B\u092A\u093E\u092F\u093E\u0928\u094D\u092A\u0930\u093F\u0924\u094D\u092F\u091C\u094D\u092F \u0938\u094D\u0935\u091A\u093F\u0924\u094D\u0924\u0947\u0928\u093E\u0935\u093F\u0915\u0932\u094D\u092A\u0915\u0930\u0942\u092A\u0947\u0923\u093E\u0928\u094D\u0924\u0930\u094D\u092E\u0941\u0916\u093E\u0928\u094D\u0924\u0930\u0935\u093F\u092E\u0930\u094D\u0936\u091A\u092E\u0924\u094D\u0915\u093E\u0930\u093E\u0924\u094D\u092E\u0928\u093E \u0938\u0902\u0935\u0947\u0926\u0928\u0947\u0928 \u092A\u094D\u0930\u0935\u093F\u0936\u0947\u0924\u094D\u0938\u092E\u093E\u0935\u093F\u0936\u0947\u0924\u094D\u0964 \u0915\u0940\u0926\u0943\u0915\u094D\u0938\u0928\u094D \u092E\u0917\u094D\u0928\u0903 \u0936\u0930\u0940\u0930\u092A\u094D\u0930\u093E\u0923\u093E\u0926\u093F\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u0924\u093E\u0902 \u0924\u0924\u094D\u0930\u0948\u0935 \u091A\u093F\u091A\u094D\u091A\u092E\u0924\u094D\u0915\u093E\u0930\u0930\u0938\u0947 \u092E\u091C\u094D\u091C\u0928\u0947\u0928 \u092A\u094D\u0930\u0936\u092E\u092F\u0928\u094D\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u092E\u094D \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947</p><blockquote><p>\u0935\u094D\u092F\u093E\u092A\u093E\u0930\u0902 \u092E\u093E\u0928\u0938\u0902 \u0924\u094D\u092F\u0915\u094D\u0924\u094D\u0935\u093E \u092C\u094B\u0927\u0930\u0942\u092A\u0947\u0923 \u092F\u094B\u091C\u092F\u0947\u0924\u094D\u0964<br> \u0924\u0926\u093E \u0936\u093F\u0935\u0924\u094D\u0935\u092E\u093E\u092F\u093E\u0924\u093F \u092A\u0936\u0941\u0930\u094D\u092E\u0941\u0915\u094D\u0924\u094B \u092D\u0935\u093E\u0930\u094D\u0923\u0935\u093E\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092D\u091F\u094D\u091F\u093E\u0930\u0915\u0947\u093D\u092A\u093F</p><blockquote><p>\u092E\u093E\u0928\u0938\u0902 \u091A\u0947\u0924\u0928\u093E \u0936\u0915\u094D\u0924\u093F\u0930\u093E\u0924\u094D\u092E\u093E \u091A\u0947\u0924\u093F \u091A\u0924\u0941\u0937\u094D\u091F\u092F\u092E\u094D\u0964<br> \u092F\u0926\u093E \u092A\u094D\u0930\u093F\u092F\u0947 \u092A\u0930\u093F\u0915\u094D\u0937\u0940\u0923\u0902 \u0924\u0926\u093E \u0924\u0926\u094D\u092D\u0948\u0930\u0935\u0902 \u0935\u092A\u0941\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u090F\u0924\u0926\u0947\u0935 \u091C\u094D\u091E\u093E\u0928\u0917\u0930\u094D\u092D\u0947 \u0938\u094D\u0924\u094B\u0924\u094D\u0930\u0947</p><blockquote><p>\u0935\u093F\u0939\u093E\u092F \u0938\u0915\u0932\u093E\u0903 \u0915\u094D\u0930\u093F\u092F\u093E \u091C\u0928\u0928\u093F \u092E\u093E\u0928\u0938\u0940\u0903 \u0938\u0930\u094D\u0935\u0924\u094B \u0935\u093F\u092E\u0941\u0915\u094D\u0924\u0915\u0930\u0923\u0915\u094D\u0930\u093F\u092F\u093E\u0928\u0941\u0938\u0943\u0924\u093F\u092A\u093E\u0930\u0924\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u094B\u091C\u094D\u091C\u094D\u0935\u0932\u092E\u094D\u0964<br> \u0938\u094D\u0925\u093F\u0924\u0948\u0938\u094D\u0924\u094D\u0935\u0926\u0928\u0941\u092D\u093E\u0935\u0924\u0903 \u0938\u092A\u0926\u093F \u0935\u0947\u0926\u094D\u092F\u0924\u0947 \u0938\u093E \u092A\u0930\u093E \u0926\u0936\u093E \u0928\u0943\u092D\u093F\u0930\u0924\u0928\u094D\u0926\u094D\u0930\u093F\u0924\u093E\u0938\u092E\u0938\u0941\u0916\u093E\u092E\u0943\u0924\u0938\u094D\u092F\u0928\u094D\u0926\u093F\u0928\u0940\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928 \u092E\u0939\u093E\u0917\u0941\u0930\u0941\u092D\u093F\u0930\u094D\u0928\u093F\u092C\u0926\u094D\u0927\u092E\u094D\u0965\u0968\u0967\u0965</p></div><hr><div class="trans"><p>Atrop\u0101yam\u0101ha\u2014</p><blockquote><p><strong>Magna\u1E25 svacittena pravi\u015Bet||21||</strong></p></blockquote><blockquote><p>Pr\u0101\u1E47\u0101disth\u016Blabh\u0101va\u1E41 tu tyaktv\u0101 s\u016Bk\u1E63mamath\u0101ntaram|<br> S\u016Bk\u1E63m\u0101t\u012Bta\u1E41 tu parama\u1E41 spandana\u1E41 labhyate yata\u1E25||</p></blockquote><p>ityupakramya</p><blockquote><p>... pravi\u015Bettatsvacetas\u0101||</p></blockquote><p>iti \u015Br\u012Bm\u1E5Btyujidbha\u1E6D\u1E6D\u0101rakanir\u016Bpitan\u012Bty\u0101 pr\u0101\u1E47\u0101y\u0101madhy\u0101nadh\u0101ra\u1E47\u0101disth\u016Blop\u0101y\u0101nparityajya svacitten\u0101vikalpakar\u016Bpe\u1E47\u0101ntarmukh\u0101ntaravimar\u015Bacamatk\u0101r\u0101tman\u0101 sa\u1E41vedanena pravi\u015Betsam\u0101vi\u015Bet| K\u012Bd\u1E5Bksan magna\u1E25 \u015Bar\u012Brapr\u0101\u1E47\u0101dipram\u0101t\u1E5Bt\u0101\u1E41 tatraiva ciccamatk\u0101rarase majjanena pra\u015Bamayan| Taduktam \u015Br\u012Bsvacchande</p><blockquote><p>Vy\u0101p\u0101ra\u1E41 m\u0101nasa\u1E41 tyaktv\u0101 bodhar\u016Bpe\u1E47a yojayet|<br> Tad\u0101 \u015Bivatvam\u0101y\u0101ti pa\u015Burmukto bhav\u0101r\u1E47av\u0101t||</p></blockquote><p>iti| \u015Ar\u012Bvij\xF1\u0101nabha\u1E6D\u1E6D\u0101rake&#39;pi</p><blockquote><p>M\u0101nasa\u1E41 cetan\u0101 \u015Baktir\u0101tm\u0101 ceti catu\u1E63\u1E6Dayam|<br> Yad\u0101 priye parik\u1E63\u012B\u1E47a\u1E41 tad\u0101 tadbhairava\u1E41 vapu\u1E25||</p></blockquote><p>iti| Etadeva j\xF1\u0101nagarbhe stotre</p><blockquote><p>Vih\u0101ya sakal\u0101\u1E25 kriy\u0101 janani m\u0101nas\u012B\u1E25 sarvato vimuktakara\u1E47akriy\u0101nus\u1E5Btip\u0101ratantryojjvalam|<br> Sthitaistvadanubh\u0101vata\u1E25 sapadi vedyate s\u0101 par\u0101 da\u015B\u0101 n\u1E5Bbhiratandrit\u0101samasukh\u0101m\u1E5Btasyandin\u012B||</p></blockquote><p>ityanena mah\u0101gurubhirnibaddham||21||</p></div><hr><p>\u041A\u0430\u0441\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u044D\u0442\u043E\u0433\u043E --\u0442.\u0435. \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u043F\u0440\u043E\u043F\u0438\u0442\u044B\u0432\u0430\u043D\u0438\u044F \u0442\u0440\u0435\u0445 \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0422\u0443\u0440\u044C\u0435\u0439 (Turya)-- <em>(atra)</em>, [\u015Aiva] \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u043B <em>(\u0101ha)</em> \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430 <em>(up\u0101yam)</em>\u2014</p><blockquote><p><strong>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0445\u043E\u0434\u0438\u0442\u044C \u0432 [\u044D\u0442\u043E \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F --\u0441\u043C. \u0430\u0444\u043E\u0440\u0438\u0437\u043C 20--] <em>(pravi\u015Bet)</em>, \u043F\u043E\u0433\u0440\u0443\u0436\u0430\u044F\u0441\u044C [\u0432 \u043D\u0435\u0433\u043E] <em>(magna\u1E25)</em> \u0441\u0432\u043E\u0438\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C <em>(sva)</em> \u0443\u043C\u043E\u043C <em>(cittena)</em>, [\u043A\u043E\u0442\u043E\u0440\u044B\u0439, \u043E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u043B\u0438\u0448\u0435\u043D \u0432\u0441\u044F\u043A\u043E\u0439 \u043C\u044B\u0441\u043B\u0438]||21||</strong></p></blockquote><p>[\u0412 M\u1E5Btyujit \u2014\u0442\u0430\u043A\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u0439 \u043A\u0430\u043A Netratantra\u2014 \u0431\u044B\u043B\u043E \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E,] \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>(upakramya)</em>:</p><blockquote><p>&quot;\u041E\u0441\u0442\u0430\u0432\u043B\u044F\u044F <em>(tu tyaktv\u0101)</em> \u0433\u0440\u0443\u0431\u043E\u0435 <em>(sth\u016Bla)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(bh\u0101vam)</em> \u043F\u0440\u0430\u043D\u044B <em>(pr\u0101\u1E47a)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em>, \u0438 \u0437\u0430\u0442\u0435\u043C <em>(atha)</em> [\u043E\u0442\u043A\u0430\u0437\u044B\u0432\u0430\u044F\u0441\u044C \u0434\u0430\u0436\u0435 \u043E\u0442] \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 <em>(\u0101ntaram)</em> \u0442\u043E\u043D\u043A\u043E\u0439 <em>(s\u016Bk\u1E63mam)</em> [pr\u0101\u1E47\u0101y\u0101ma], \u0412\u044B\u0441\u0448\u0430\u044F <em>(paramam)</em> \u0412\u0438\u0431\u0440\u0430\u0446\u0438\u044F <em>(spandanam)</em>, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0430\u044F \u0432\u043D\u0435 <em>(\u0101t\u012Btam tu)</em> \u0442\u043E\u043D\u043A\u043E\u0439 [pr\u0101\u1E47\u0101y\u0101ma] <em>(s\u016Bk\u1E63ma)</em>, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F <em>(labhyate)</em> \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443 --\u0438\u0437-\u0437\u0430 \u043E\u0442\u043A\u0430\u0437\u0430 \u043E\u0442 \u0433\u0440\u0443\u0431\u043E\u0439 \u0438 \u0442\u043E\u043D\u043A\u043E\u0439 pr\u0101\u1E47\u0101y\u0101ma-s-- <em>(yatas... iti)</em><sup>1</sup>&quot;||<br> [\u0421\u043C. VIII, 12 \u0432 Netratantra]</p></blockquote><p>[\u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u043D\u0430:]</p><blockquote><p>&quot;... \u043E\u043D \u0432\u0445\u043E\u0434\u0438\u0442 \u0432 <em>(pravi\u015Bet)</em> [\u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435] \u0441\u0432\u043E\u0438\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0443\u043C\u043E\u043C <em>(sva-cetas\u0101)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u044D\u0442\u043E\u043C\u0443 --\u0442.\u0435. \u043A\u0430\u043A \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439-- <em>(tad.. iti)</em><sup>2</sup>&quot;|<br> [\u0421\u043C. \u043F\u0435\u0440\u0432\u0443\u044E \u0447\u0430\u0441\u0442\u044C \u0441\u0442\u0440\u043E\u0444\u044B VIII, 14 \u0432 Netratantra]</p></blockquote><p>\u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u043C <em>(n\u012Bty\u0101)</em>, \u0432\u044B\u0441\u043A\u0430\u0437\u0430\u043D\u043D\u044B\u043C <em>(nir\u016Bpita)</em> \u0432 \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C <em>(\u015Br\u012B... bha\u1E6D\u1E6D\u0101raka)</em> M\u1E5Btyujit --Netratantra-- <em>(m\u1E5Btyujit)</em>, \u043F\u043E\u0441\u043B\u0435 \u043F\u043E\u043B\u043D\u043E\u0433\u043E \u043E\u0442\u043A\u0430\u0437\u0430 \u043E\u0442 <em>(parityajya)</em> \u0433\u0440\u0443\u0431\u044B\u0445 <em>(sth\u016Bla)</em> \u043C\u0435\u0442\u043E\u0434\u043E\u0432 <em>(up\u0101y\u0101n)</em>, [\u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A] pr\u0101\u1E47\u0101y\u0101ma <em>(pr\u0101\u1E47\u0101y\u0101ma)</em>, \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u044F <em>(dhy\u0101na)</em>, \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044F <em>(dh\u0101ra\u1E47\u0101)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em>, \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u0432\u043E\u0439\u0442\u0438 <em>(pravi\u015Bet)</em> [\u0438\u043B\u0438] \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u0443\u0442\u044C <em>(sam\u0101vi\u015Bet)</em> [\u0432 \u0422\u0443\u0440\u044C\u044E, \u0438\u043B\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435] \u0441\u0432\u043E\u0438\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0443\u043C\u043E\u043C <em>(svacittena)</em>, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0441 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(sa\u1E41vedanena)</em>, \u043B\u0438\u0448\u0435\u043D\u043D\u044B\u043C \u043C\u044B\u0441\u043B\u0435\u0439 <em>(avikalpaka-r\u016Bpe\u1E47a)</em>, \u0438 \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(\u0101tman\u0101)</em> \u2014 \u0438\u043D\u0442\u0440\u043E\u0432\u0435\u0440\u0442\u043D\u0430\u044F <em>(antarmukha)</em> camatk\u0101ra --\u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E, \u043F\u043E\u043B\u043D\u043E\u0435 \u0438\u0437\u0443\u043C\u043B\u0435\u043D\u0438\u044F-- <em>(bh\u016Btebhya\u1E25)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E <em>(\u0101ntara)</em> \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(vimar\u015Ba)</em> --\u0442.\u0435. \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F--|</p><p>\u041A\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(k\u012Bd\u1E5Bk san)</em>? \u041F\u043E\u0433\u0440\u0443\u0436\u0430\u044F\u0441\u044C [\u0432 \u044D\u0442\u043E] <em>(magna\u1E25)</em>, [\u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438,] \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0430\u044F <em>(pra\u015Bamayan)</em> [\u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435], \u0447\u0442\u043E \u044D\u0442\u043E \u0442\u0435\u043B\u043E <em>(\u015Bar\u012Bra)</em>, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F <em>(pr\u0101\u1E47a)</em> \u0438 \u0442.\u0434. <em>(\u0101di)</em> \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F Pram\u0101t\u0101, \u0438\u043B\u0438 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u043C --\u0432\u0430\u0448\u0438\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u042F, \u043A\u0430\u043A \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0435\u043C-- <em>(pram\u0101t\u1E5Bt\u0101m)</em>, \u0447\u0435\u0440\u0435\u0437 \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u0435 <em>(majjanena)</em> \u0432 \u044D\u0442\u043E \u0441\u0430\u043C\u043E\u0435 <em>(tatra eva)</em>, \u0442.\u0435 \u0432 \u044D\u043B\u0438\u043A\u0441\u0438\u0440 <em>(rase)</em> \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 <em>(camatk\u0101ra)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em> --\u043A\u043E\u0440\u043E\u0447\u0435, &quot;\u0432 \u0422\u0443\u0440\u044C\u044E (Turya), \u0438\u043B\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435&quot;--|</p><p>\u0422\u043E \u0436\u0435 <em>(tad)</em> \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C Svacchandatantra <em>(\u015Br\u012B-svacchande)</em>:</p><blockquote><p>&quot;\u041E\u0442\u0431\u0440\u043E\u0441\u0438\u0432 <em>(tyaktv\u0101)</em> [\u0432\u0441\u044F\u043A\u0443\u044E] \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u0443\u044E <em>(m\u0101nasam)</em> \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u044C <em>(vy\u0101p\u0101ram)</em>, [Yog\u012B] \u0434\u043E\u043B\u0436\u0435\u043D \u0441\u0442\u0430\u0442\u044C \u0435\u0434\u0438\u043D\u044B\u043C <em>(yojayet)</em> [\u0441 \u015Aiva] \u043F\u0440\u0438 [\u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0438] \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u0438 \u0431\u0435\u0437 \u043A\u0430\u043A\u0438\u0445-\u043B\u0438\u0431\u043E \u043C\u044B\u0441\u043B\u0435\u0439 <em>(bodhar\u016Bpe\u1E47a)</em>. \u0422\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u0430\u044F \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C <em>(pa\u015Bu\u1E25)</em>, \u0431\u0443\u0434\u0443\u0447\u0438 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0439 <em>(mukta\u1E25)</em> \u043E\u0442 \u043E\u043A\u0435\u0430\u043D\u0430 <em>(ar\u1E47av\u0101t)</em> \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F --\u0442.\u0435. \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u0439-- <em>(bhava)</em>, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(\u0101y\u0101ti)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u015Aiva <em>(\u015Bivatvam... iti)</em><sup>3</sup>&quot;||<br> [\u0421\u043C. IV, 437 \u0432 Svacchandatantra]</p></blockquote><p>[\u0418] \u0432 \u0441\u0430\u043C\u043E\u043C \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C Vij\xF1\u0101nabhairava <em>(\u015Br\u012B-vij\xF1\u0101na-bha\u1E6D\u1E6D\u0101rake)</em> [\u0431\u044B\u043B\u043E] \u0442\u0430\u043A\u0436\u0435 [\u0432\u044B\u0441\u043A\u0430\u0437\u0430\u043D\u043E \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435] <em>(api)</em>:</p><blockquote><p>&quot;\u041E, \u0414\u043E\u0440\u043E\u0433\u0430\u044F <em>(priye)</em>!, \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u0433\u0440\u0443\u043F\u043F\u0430 \u0447\u0435\u0442\u044B\u0440\u0435\u0445 <em>(catu\u1E63\u1E6Dayam)</em>, [\u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0430\u044F \u0438\u0437] &#39;\u0443\u043C\u0430, \u043F\u043E\u043B\u043D\u043E\u0433\u043E \u0438\u0434\u0435\u0439 \u0438 \u0436\u0435\u043B\u0430\u043D\u0438\u0439 <em>(m\u0101nasam)</em>, \u0443\u0431\u0435\u0436\u0434\u0435\u043D\u043D\u043E\u0433\u043E \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430 <em>(cetan\u0101)</em>, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(\u015Bakti\u1E25)</em> \u0438 <em>(ca)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u043E\u043F\u044B\u0442\u0430 <em>(\u0101tm\u0101)</em>&#39; \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0430 <em>(parik\u1E63\u012B\u1E47am)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em> [\u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u044D\u0442\u0430 [\u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u0430\u044F] <em>(tad)</em> vapus, \u0438\u043B\u0438 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(vapus)</em>, [\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430\u044F \u043A\u0430\u043A] Bhairava --\u0413\u043E\u0441\u043F\u043E\u0434\u044C-- <em>(bhairavam... iti)</em>&quot;||</p></blockquote><p>\u042D\u0442\u0430 <em>(etad)</em> \u0436\u0435 \u0441\u0430\u043C\u0430\u044F [\u0438\u0441\u0442\u0438\u043D\u0430] <em>(eva)</em> [\u0431\u044B\u043B\u0430 \u0432\u044B\u0441\u043A\u0430\u0437\u0430\u043D\u0430] \u0432 \u0433\u0438\u043C\u043D\u0435 J\xF1\u0101nagarbha <em>(j\xF1\u0101nagarbhe stotre)</em> \u044D\u0442\u043E\u0439 [\u0441\u0442\u0440\u043E\u0444\u043E\u0439] <em>(anena)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0431\u044B\u043B\u0430 \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0430 <em>(nibaddham)</em> \u0432\u0435\u043B\u0438\u043A\u0438\u043C \u0434\u0443\u0445\u043E\u0432\u043D\u044B\u043C \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A\u043E\u043C <em>(mah\u0101-gurubhi\u1E25)</em> --\u044D\u0442\u043E \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A Pradyumnabha\u1E6D\u1E6Da, \u043E\u0434\u043D\u043E\u043C\u0443 \u0438\u0437 \u0433\u043B\u0430\u0432\u043D\u044B\u0445 \u0443\u0447\u0435\u043D\u0438\u043A\u043E\u0432 Kalla\u1E6Da, \u0432\u044B\u0434\u0430\u044E\u0449\u0435\u043C\u0443\u0441\u044F \u0443\u0447\u0435\u043D\u0438\u043A\u0443 \u0441\u0430\u043C\u043E\u0433\u043E Vasugupta--:</p><blockquote><p>&quot;\u041E, \u041C\u0430\u0442\u044C <em>(janani)</em>!, \u043F\u043E\u0441\u043B\u0435 \u043F\u043E\u043B\u043D\u043E\u0433\u043E <em>(sarvatas)</em> \u043E\u0442\u043A\u0430\u0437\u0430 \u043E\u0442 <em>(vih\u0101ya)</em> \u0432\u0441\u044F\u043A\u043E\u0439 <em>(sakal\u0101\u1E25)</em> \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0439 <em>(m\u0101nas\u012B\u1E25)</em> \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u0438 <em>(kriy\u0101\u1E25)</em>, [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435] \u0432\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u043D\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(ujjvalam)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E <em>(vimukta)</em> \u043E\u0442 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 <em>(p\u0101ratantrya)</em> \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u0437\u0430 <em>(anus\u1E5Bti)</em> \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E <em>(kriy\u0101)</em> \u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432 <em>(kara\u1E47a)</em>. \u042D\u0442\u043E <em>(s\u0101)</em> \u0412\u044B\u0441\u0448\u0435\u0435 <em>(par\u0101)</em> \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(da\u015B\u0101)</em>, \u0438\u0441\u0442\u043E\u0447\u0430\u044E\u0449\u0435\u0435 <em>(syandin\u012B)</em> \u043D\u0435\u043A\u0442\u0430\u0440 <em>(am\u1E5Bta)</em> \u0431\u0435\u0441\u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0433\u043E <em>(asama)</em> \u0441\u0447\u0430\u0441\u0442\u044C\u044F <em>(sukha)</em> \u0431\u0435\u0437 \u043A\u0430\u043A\u043E\u0433\u043E \u0431\u044B \u0442\u043E \u043D\u0438 \u0431\u044B\u043B\u043E \u043E\u0448\u0435\u043B\u043E\u043C\u043B\u0435\u043D\u0438\u044F \u0438\u043B\u0438 \u043D\u0435\u0434\u043E\u0443\u043C\u0435\u043D\u0438\u044F <em>(atandrita)</em>, \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442\u0441\u044F <em>(vedyate)</em> \u043D\u0435\u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E <em>(sapadi)</em>, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0422\u0432\u043E\u0435\u0439 \u041C\u0438\u043B\u043E\u0441\u0442\u0438 <em>(tvat-anubh\u0101vata\u1E25)</em>, \u043B\u044E\u0434\u044C\u043C\u0438 <em>(n\u1E5Bbhi\u1E25)</em>, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u043C\u0438 [\u0432 \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u043C \u0432\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u043D\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438] <em>(sthitai\u1E25... iti)</em>&quot;||</p></blockquote><p>||21||</p><hr><ol><li>\u0427\u0442\u043E\u0431\u044B \u0432\u044B \u043F\u043E\u043D\u044F\u043B\u0438, \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u0441\u0442\u0440\u043E\u0444\u0443 \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043C\u043D\u0435 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C \u0432\u0430\u043C, \u043A\u0430\u043A K\u1E63emar\u0101ja \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 \u044D\u0442\u0443 \u0441\u0442\u0440\u043E\u0444\u0443 \u0432 \u0441\u0432\u043E\u0435\u0439 Netroddyota: &quot; \u092A\u094D\u0930\u093E\u0923\u093E\u0926\u094C \u092A\u094D\u0930\u093E\u0923\u093E\u092A\u093E\u0928\u0938\u092E\u093E\u0928\u0947\u0937\u0941 \u092F\u0903 \u0938\u094D\u0925\u0942\u0932\u094B \u0930\u0947\u091A\u0915\u092A\u0942\u0930\u0915\u093E\u0926\u093F\u0930\u094D\u092D\u093E\u0935\u0903 \u0938\u094D\u0935\u092D\u093E\u0935\u0938\u094D\u0924\u0902 \u0924\u094D\u092F\u0915\u094D\u0924\u094D\u0935\u093E \u0909\u091C\u094D\u091D\u093F\u0924\u094D\u0935\u093E \u0905\u0925\u0947\u0924\u093F \u090F\u0924\u0924\u094D\u0938\u094D\u0925\u0942\u0932\u092A\u094D\u0930\u093E\u0923\u093E\u092F\u093E\u092E\u093E\u0928\u0928\u094D\u0924\u0930\u092D\u093E\u0935\u093F \u0938\u0942\u0915\u094D\u0937\u094D\u092E\u092E\u093E\u0928\u094D\u0924\u0930\u092E\u093F\u0924\u093F \u092E\u0927\u094D\u092F\u092A\u0925\u0947\u0928 \u0930\u0947\u091A\u0928\u093E\u091A\u092E\u0928\u093E\u0926\u093F\u0930\u0942\u092A\u0902 \u091A \u0924\u0902 \u0924\u094D\u092F\u0915\u094D\u0924\u094D\u0935\u093E \u092F\u0924\u094B \u092F\u0938\u094D\u092E\u093E\u0924\u094D\u0938\u0942\u0915\u094D\u0937\u094D\u092E\u092E\u092A\u094D\u092F\u0924\u0940\u0924\u0902 \u092A\u0930\u092E\u092E\u093F\u0924\u093F \u092A\u094D\u0930\u093E\u0923\u093E\u0926\u094D\u092F\u091A\u093F\u0924\u094D\u0938\u094D\u092B\u0941\u0930\u0924\u094D\u0924\u093E\u0924\u094D\u092E \u0938\u094D\u092A\u0928\u094D\u0926\u0928\u0902 \u0932\u092D\u094D\u092F\u0924\u0947...&quot; - &quot;Pr\u0101\u1E47\u0101dau pr\u0101\u1E47\u0101p\u0101nasam\u0101ne\u1E63u ya\u1E25 sth\u016Blo recakap\u016Brak\u0101dirbh\u0101va\u1E25 svabh\u0101vasta\u1E41 tyaktv\u0101 ujjhitv\u0101 atheti etatsth\u016Blapr\u0101\u1E47\u0101y\u0101m\u0101nantarabh\u0101vi s\u016Bk\u1E63mam\u0101ntaramiti madhyapathena recan\u0101caman\u0101dir\u016Bpa\u1E41 ca ta\u1E41 tyaktv\u0101 yato yasm\u0101ts\u016Bk\u1E63mamapyat\u012Bta\u1E41 paramamiti pr\u0101\u1E47\u0101dyacitsphuratt\u0101tma spandana\u1E41 labhyate...&quot; - &quot;[\u0412\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435 &#39;Pr\u0101\u1E47\u0101disth\u016Blabh\u0101va\u1E41 tu tyaktv\u0101&#39; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &#39;\u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435, \u0438\u043B\u0438 \u043E\u0442\u043A\u0430\u0437 \u043E\u0442 \u0433\u0440\u0443\u0431\u043E\u0433\u043E bh\u0101va \u2014\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u2014 \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 \u0432\u044B\u0434\u043E\u0445\u0430, \u0432\u0434\u043E\u0445\u0430 \u0438 \u0442.\u0434. \u0438 [\u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u043E] \u043D\u0430 pr\u0101\u1E47a, \u0438 \u0442.\u0434., \u0442.\u0435. \u043D\u0430 pr\u0101\u1E47a, ap\u0101na \u0438 sam\u0101na&#39;. [\u0424\u0440\u0430\u0437\u0430 &#39;s\u016Bk\u1E63mamath\u0101ntaram&#39; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &#39;\u0438 \u0437\u0430\u0442\u0435\u043C \u043E\u0442\u043A\u0430\u0437\u0430\u0432\u0448\u0438\u0441\u044C \u043E\u0442 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 \u0442\u043E\u043D\u043A\u043E\u0439 [pr\u0101\u1E47\u0101y\u0101ma], \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0441\u0440\u0430\u0437\u0443 \u043F\u043E\u0441\u043B\u0435 \u0433\u0440\u0443\u0431\u043E\u0439 pr\u0101\u1E47\u0101y\u0101ma [\u0438] \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u044B\u0434\u043E\u0445, \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435 \u0438 \u0442.\u0434. \u0447\u0435\u0440\u0435\u0437 \u0441\u0440\u0435\u0434\u0438\u043D\u043D\u044B\u0439 \u043F\u0443\u0442\u044C (\u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u044B\u0439 \u043A\u0430\u043D\u0430\u043B) --\u0442.\u0435. Su\u1E63umn\u0101--&#39;. &#39;Yatas&#39;, \u0442.\u0435. &#39;\u0438\u0437-\u0437\u0430 \u0447\u0435\u0433\u043E&#39; --\u0438\u0437-\u0437\u0430 \u043E\u0442\u043A\u0430\u0437\u0430 \u043E\u0442 \u0433\u0440\u0443\u0431\u043E\u0439 \u0438 \u0442\u043E\u043D\u043A\u043E\u0439 pr\u0101\u1E47\u0101y\u0101ma-s--, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0412\u044B\u0441\u0448\u0430\u044F \u0412\u0438\u0431\u0440\u0430\u0446\u0438\u044F [\u0438\u043B\u0438 Spanda], \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u0438\u0442 \u0434\u0430\u0436\u0435 \u0442\u043E\u043D\u043A\u0443\u044E pr\u0101\u1E47\u0101y\u0101ma --\u043F\u043E\u044D\u0442\u043E\u043C\u0443 \u0412\u044B\u0441\u0448\u0430\u044F-- \u0438 \u0447\u044C\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F Sphuratt\u0101, \u0438\u043B\u0438 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u043D\u043E\u0435 \u043D\u0435\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u043F\u0435\u0440\u0435\u0434 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439 --Pr\u0101\u1E47a--...&quot;.</li></ol><p>\u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u0421\u043F\u0430\u043D\u0434\u0430 \u2014 \u044D\u0442\u043E \u043D\u0438\u0447\u0442\u043E \u0438\u043D\u043E\u0435 \u043A\u0430\u043A \u0412\u044B\u0441\u0448\u0435\u0435 \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0432\u0441\u0435\u0433\u0434\u0430 \u043F\u0440\u0435\u0434\u0448\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043B\u044E\u0431\u044B\u043C \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F\u043C, \u0442\u0430\u043A\u0438\u043C \u043A\u0430\u043A \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F \u0438 \u043F\u0440. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435. OK, \u0442\u0435\u043F\u0435\u0440\u044C \u0432\u0441\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u044F\u0441\u043D\u043E... \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u0435\u0441\u043B\u0438 \u0432\u044B \u0437\u043D\u0430\u0435\u0442\u0435, \u0447\u0442\u043E \u0442\u0430\u043A\u043E\u0435 \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 pr\u0101\u1E47\u0101y\u0101ma, Su\u1E63umn\u0101, \u0438 \u0442.\u0434. \u0415\u0441\u043B\u0438 \u0432\u044B \u043D\u0435 \u0438\u043C\u0435\u0435\u0442\u0435 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u043E\u0431 \u044D\u0442\u043E\u043C, \u0432\u0430\u043C \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u043F\u0435\u0440\u0435\u0447\u0438\u0442\u0430\u0442\u044C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430 \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0438\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C \u044D\u0442\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F. \u041C\u043E\u0438 \u0438\u0437\u0432\u0438\u043D\u0435\u043D\u0438\u044F, \u043D\u043E \u044F \u043D\u0435 \u043C\u043E\u0433\u0443 \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0442\u044C \u043E\u0434\u043D\u0438 \u0438 \u0442\u0435 \u0436\u0435 \u0432\u0435\u0449\u0438, \u0432\u044B \u0437\u043D\u0430\u0435\u0442\u0435, \u0445\u0435-\u0445\u0435. \u0423\u0431\u0435\u0434\u0438\u0442\u0435\u0441\u044C, \u0447\u0442\u043E \u0432\u044B \u043E\u0447\u0435\u043D\u044C \u0445\u043E\u0440\u043E\u0448\u043E \u0437\u043D\u0430\u043A\u043E\u043C\u044B \u0441 \u044D\u0442\u0438\u043C\u0438 \u043E\u0431\u0449\u0435\u043F\u0440\u0438\u043D\u044F\u0442\u044B\u043C\u0438 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u043C\u0438 \u0442\u0435\u0440\u043C\u0438\u043D\u0430\u043C\u0438, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432\u044B \u0431\u0443\u0434\u0435\u0442\u0435 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0441\u0442\u0430\u043B\u043A\u0438\u0432\u0430\u0442\u044C\u0441\u044F \u0441 \u043D\u0438\u043C\u0438 \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u0438\u0437\u0443\u0447\u0435\u043D\u0438\u044F \u0422\u0440\u0438\u043A\u0438 \u0438 \u0434\u0440\u0443\u0433\u0438\u0445 \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0441\u043A\u0438\u0445 \u0441\u0438\u0441\u0442\u0435\u043C.</p><ol start="2"><li>\u041A\u0430\u0436\u0435\u0442\u0441\u044F, \u0447\u0442\u043E K\u1E63emar\u0101ja \u0443\u043F\u0440\u043E\u0441\u0442\u0438\u043B \u044D\u0442\u0443 \u043C\u0430\u043B\u0435\u043D\u044C\u043A\u0443\u044E \u0447\u0430\u0441\u0442\u044C \u0438\u043B\u0438 \u0438\u043C\u0435\u043B \u0434\u0440\u0443\u0433\u043E\u0435 \u043F\u0440\u043E\u0447\u0442\u0435\u043D\u0438\u0435. \u042F \u043F\u0440\u043E\u0447\u0438\u0442\u0430\u043B \u0432 Netratantra VIII, 14: &quot; ... \u092A\u094D\u0930\u0935\u093F\u0936\u0947\u0926\u094D\u0927\u093E\u092E \u092A\u0930\u092E\u0902 \u0924\u0924\u094D\u0938\u094D\u0935\u091A\u0947\u0924\u0938\u093E\u0964&quot; - &quot;... pravi\u015Beddh\u0101ma parama\u1E41 tatsvacetas\u0101|&quot; - &quot;... \u043E\u043D \u0432\u0445\u043E\u0434\u0438\u0442 \u0432 \u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u0432\u043E\u0438\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0443\u043C\u043E\u043C \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u044D\u0442\u043E\u043C\u0443 --\u0442.\u0435. \u043A\u0430\u043A \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439--&quot;.</li></ol><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 &quot;pravi\u015Bet&quot; \u2014 \u044D\u0442\u043E \u0441\u043F\u0440\u044F\u0436\u0435\u043D\u0438\u0435 \u0433\u043B\u0430\u0433\u043E\u043B\u0430 &quot;pravi\u015B&quot; (\u0432\u0445\u043E\u0434\u0438\u0442\u044C) \u0432 \u041F\u043E\u0442\u0435\u043D\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u043C \u041D\u0430\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0438, 3<sup>\u0435\u043C</sup> \u043B\u0438\u0446\u0435, \u0435\u0434. \u0447. (Parasmaipada), \u043E\u0431\u044B\u0447\u043D\u043E \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0438\u0442\u0441\u044F \u043A\u0430\u043A &quot;\u0435\u043C\u0443/\u0435\u0439 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0445\u043E\u0434\u0438\u0442\u044C&quot;. \u041D\u043E \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0443, \u041F\u043E\u0442\u0435\u043D\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0435 \u041D\u0430\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0435 \u0438\u043C\u0435\u0435\u0442 \u0441\u0438\u043B\u0443 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u0438, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, &quot;pravi\u015Bet&quot; \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0442\u0430\u043A\u0436\u0435 \u0438\u043C\u0435\u0442\u044C \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434, \u043A\u0430\u043A &quot;\u043E\u043D/\u043E\u043D\u0430/\u043E\u043D\u043E \u0432\u0445\u043E\u0434\u0438\u0442&quot;. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u043C\u043E\u0439 \u0432\u044B\u0448\u0435\u043F\u0440\u0438\u0432\u0435\u0434\u0435\u043D\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 &quot;pravi\u015Bet&quot; \u2014 \u0432 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u0438 (&quot;\u043E\u043D \u0432\u0445\u043E\u0434\u0438\u0442&quot;), \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u0432 \u0441\u0430\u043C\u043E\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 21 \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u044D\u0442\u043E \u043A\u0430\u043A &quot; \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0445\u043E\u0434\u0438\u0442\u044C&quot;. \u0422\u0435\u043F\u0435\u0440\u044C \u0432\u044B \u043F\u043E\u043D\u0438\u043C\u0430\u0435\u0442\u0435, \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C.</p><ol start="3"><li>\u0421\u043D\u043E\u0432\u0430, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432 \u044D\u0442\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0442\u0435\u0440\u043C\u0438\u043D\u0430 &quot;bodha&quot; \u043D\u0435\u044F\u0441\u043D\u043E, \u044F \u043E\u0431\u044A\u044F\u0441\u043D\u044E \u044D\u0442\u043E, \u043F\u0440\u0438\u0431\u0435\u0433\u043D\u0443\u0432 \u043A \u043F\u043E\u043C\u043E\u0449\u0438 Svacchandoddyota \u0432\u044B\u0434\u0430\u044E\u0449\u0435\u0433\u043E\u0441\u044F K\u1E63emar\u0101ja: &quot; \u092C\u094B\u0927\u0930\u0942\u092A\u0947\u0923\u0947\u0924\u093F \u0905\u0935\u093F\u0915\u0932\u094D\u092A\u0938\u0902\u0935\u093F\u0924\u094D\u0938\u094D\u092A\u0930\u094D\u0936\u0947\u0928\u0948\u0935&quot; - &quot;bodhar\u016Bpe\u1E47eti avikalpasa\u1E41vitspar\u015Benaiva&quot; - &quot;[\u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435] &#39;bodhar\u016Bpe\u1E47a&#39; [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &#39;\u043F\u0440\u0438 \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u0438 \u0431\u0435\u0437 \u043A\u0430\u043A\u0438\u0445-\u043B\u0438\u0431\u043E \u043C\u044B\u0441\u043B\u0435\u0439&#39;&quot;.</li></ol></div><div class="stanza"><a href="#s3.22" id="s3.22" class="num">3.22</a><div class="sans"><p>\u0907\u0924\u094D\u0925\u0902 \u091A \u092A\u0930\u092E\u092A\u0926\u092A\u094D\u0930\u0935\u093F\u0937\u094D\u091F\u0938\u094D\u092F\u093E\u0938\u094D\u092F \u0935\u0938\u094D\u0924\u0941\u0938\u094D\u0935\u093E\u092D\u093E\u0935\u094D\u092F\u093E\u0926\u094D\u092F\u0926\u093E \u092A\u0941\u0928\u0903 \u092A\u094D\u0930\u0938\u0930\u0923\u0902 \u092D\u0935\u0924\u093F \u0924\u0926\u093E\u2014</p><blockquote><p><strong>\u092A\u094D\u0930\u093E\u0923\u0938\u092E\u093E\u091A\u093E\u0930\u0947 \u0938\u092E\u0926\u0930\u094D\u0936\u0928\u092E\u094D\u0965\u0968\u0968\u0965</strong></p></blockquote><p>\u092A\u0930\u0938\u094D\u092B\u0941\u0930\u0924\u094D\u0924\u093E\u0924\u094D\u092E\u0915\u0936\u093E\u0915\u094D\u0924\u092A\u0930\u093F\u092E\u0932\u0938\u0902\u0938\u094D\u0915\u0943\u0924\u0938\u094D\u092F \u092A\u094D\u0930\u093E\u0923\u0938\u094D\u092F \u0938\u092E\u094D\u092F\u0917\u093F\u0924\u093F \u0935\u093F\u0915\u0938\u093F\u0924\u0938\u092E\u0917\u094D\u0930\u0917\u094D\u0930\u0928\u094D\u0925\u094D\u092F\u093E\u0924\u094D\u092E\u0915\u093E\u0928\u094D\u0924\u0930\u093E\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u092C\u0932\u093E\u0926\u094D \u0906 \u0908\u0937\u0926\u094D\u092C\u0939\u093F\u0930\u094D\u092E\u0928\u094D\u0926\u092E\u0928\u094D\u0926\u0902 \u091A\u093E\u0930\u0947 \u092A\u094D\u0930\u0938\u0930\u0923\u0947 \u0938\u092E\u0902 \u091A\u093F\u0926\u093E\u0928\u0928\u094D\u0926\u0918\u0928\u093E\u0924\u094D\u092E\u0924\u092F\u0948\u0915\u0930\u0942\u092A\u0902 \u0926\u0930\u094D\u0936\u0928\u0902 \u0938\u0902\u0935\u0947\u0926\u0928\u092E\u0930\u094D\u0925\u093E\u0924\u094D\u0938\u0930\u094D\u0935\u0926\u0936\u093E\u0938\u094D\u0935\u0938\u094D\u092F \u092D\u0935\u0924\u0940\u0924\u094D\u092F\u0930\u094D\u0925\u0903\u0964 \u0909\u0915\u094D\u0924\u0902 \u091A \u0936\u094D\u0930\u0940\u092E\u0926\u093E\u0928\u0928\u094D\u0926\u092D\u0948\u0930\u0935\u0947</p><blockquote><p>\u0909\u0924\u094D\u0938\u0943\u091C\u094D\u092F \u0932\u094C\u0915\u093F\u0915\u093E\u091A\u093E\u0930\u092E\u0926\u094D\u0935\u0948\u0924\u0902 \u092E\u0941\u0915\u094D\u0924\u093F\u0926\u0902 \u0936\u094D\u0930\u092F\u0947\u0924\u094D\u0964<br> \u0938 \u0938\u092E\u0902 \u0938\u0930\u094D\u0935\u0926\u0947\u0935\u093E\u0928\u093E\u0902 \u0924\u0925\u093E \u0935\u0930\u094D\u0923\u093E\u0936\u094D\u0930\u092E\u093E\u0926\u093F\u0915\u0947\u0965<br> \u0926\u094D\u0930\u0935\u094D\u092F\u093E\u0923\u093E\u0902 \u0938\u092E\u0924\u093E\u0926\u0930\u094D\u0936\u0940 \u0938 \u092E\u0941\u0915\u094D\u0924\u0903 \u0938\u0930\u094D\u0935\u092C\u0928\u094D\u0927\u0928\u0948\u0903\u0964</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0905\u0924 \u090F\u0935 \u0936\u094D\u0930\u0940\u092A\u094D\u0930\u0924\u094D\u092F\u092D\u093F\u091C\u094D\u091E\u093E\u092F\u093E\u092E\u094D</p><blockquote><p>\u092C\u0941\u0926\u094D\u0927\u093F\u092A\u094D\u0930\u093E\u0923\u092A\u094D\u0930\u0938\u0930\u0947\u093D\u092A\u093F \u092C\u093E\u0939\u094D\u092F\u0926\u0947\u0936\u093E\u0926\u094D\u092F\u0941\u092A\u093E\u0926\u093E\u0928\u093E\u0928\u093E\u0939\u093F\u0924\u0938\u0919\u094D\u0915\u094B\u091A\u093E\u0928\u093E\u0902 \u0935\u093F\u0936\u094D\u0935\u093E\u0924\u094D\u092E\u0938\u094D\u0935\u0930\u0942\u092A\u0932\u093E\u092D \u090F\u0935\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u092E\u094D\u0965\u0968\u0968\u0965</p></div><hr><div class="trans"><p>Ittha\u1E41 ca paramapadapravi\u1E63\u1E6Dasy\u0101sya vastusv\u0101bh\u0101vy\u0101dyad\u0101 puna\u1E25 prasara\u1E47a\u1E41 bhavati tad\u0101\u2014</p><blockquote><p><strong>Pr\u0101\u1E47asam\u0101c\u0101re samadar\u015Banam||22||</strong></p></blockquote><p>Parasphuratt\u0101tmaka\u015B\u0101ktaparimalasa\u1E41sk\u1E5Btasya pr\u0101\u1E47asya samyagiti vikasitasamagragranthy\u0101tmak\u0101ntar\u0101va\u1E63\u1E6Dambhabal\u0101d \u0101 \u012B\u1E63adbahirmandamanda\u1E41 c\u0101re prasara\u1E47e sama\u1E41 cid\u0101nandaghan\u0101tmatayaikar\u016Bpa\u1E41 dar\u015Bana\u1E41 sa\u1E41vedanamarth\u0101tsarvada\u015B\u0101svasya bhavat\u012Btyartha\u1E25| Ukta\u1E41 ca \u015Br\u012Bmad\u0101nandabhairave</p><blockquote><p>Uts\u1E5Bjya laukik\u0101c\u0101ramadvaita\u1E41 muktida\u1E41 \u015Brayet|<br> Sa sama\u1E41 sarvadev\u0101n\u0101\u1E41 tath\u0101 var\u1E47\u0101\u015Bram\u0101dike||<br> Dravy\u0101\u1E47\u0101\u1E41 samat\u0101dar\u015B\u012B sa mukta\u1E25 sarvabandhanai\u1E25|</p></blockquote><p>iti| Ata eva \u015Br\u012Bpratyabhij\xF1\u0101y\u0101m</p><blockquote><p>Buddhipr\u0101\u1E47aprasare&#39;pi b\u0101hyade\u015B\u0101dyup\u0101d\u0101n\u0101n\u0101hitasa\u1E45koc\u0101n\u0101\u1E41 vi\u015Bv\u0101tmasvar\u016Bpal\u0101bha eva||</p></blockquote><p>ityuktam||22||</p></div><hr><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(ittham ca)</em>, \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u044D\u0442\u043E\u0433\u043E [Yog\u012B] <em>(asya)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0432\u043E\u0448\u0435\u043B \u0432 <em>(pravi\u1E63\u1E6Dasya)</em> \u0412\u044B\u0441\u0448\u0435\u0435 <em>(parama)</em> \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(pada)</em>, \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(bhavati)</em> \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0435 --\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435-- <em>(prasara\u1E47am)</em> \u0441\u043D\u043E\u0432\u0430 <em>(punar)</em>, \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(sv\u0101bh\u0101vy\u0101t)</em> \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(vastu)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>\u2014</p><blockquote><p><strong>\u041A\u043E\u0433\u0434\u0430 [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E\u0435, \u043D\u043E \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0435 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0435 <em>(sam\u0101c\u0101re)</em> \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 [Yog\u012B] <em>(pr\u0101\u1E47a)</em>, \u043D\u0430\u0441\u0442\u0443\u043F\u0430\u0435\u0442 \u0440\u0430\u0432\u043D\u043E\u0435 <em>(sama)</em> \u0432\u0438\u0434\u0435\u043D\u0438\u0435 <em>(dar\u015Banam)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C Yog\u012B \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E, \u043B\u0435\u0436\u0430\u0449\u0435\u0435 \u0432 \u043E\u0441\u043D\u043E\u0432\u0435 \u0432\u0441\u0435\u0433\u043E]||22||</strong></p></blockquote><p>&quot;\u0416\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 [Yog\u012B] <em>(pr\u0101\u1E47asya)</em>&quot; [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &quot;\u0442\u043E\u0439, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0431\u044B\u043B\u0430 \u043E\u0441\u0432\u044F\u0449\u0435\u043D\u0430 <em>(sa\u1E41sk\u1E5Btasya)</em> \u0430\u0440\u043E\u043C\u0430\u0442\u043E\u043C <em>(parimala)</em> \u015Aakti <em>(\u015B\u0101kta)</em>, \u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0439\u0441\u044F <em>(\u0101tmaka)</em> \u0412\u044B\u0441\u0448\u0435\u0439 <em>(para)</em> Sphuratt\u0101, \u0438\u043B\u0438 \u0441\u0432\u0435\u0442\u044F\u0449\u0438\u043C\u0441\u044F \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(sphuratt\u0101)</em>&quot;. [\u0412 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435, \u0442\u0435\u0440\u043C\u0438\u043D &quot;sam\u0101c\u0101re&quot; \u2014 \u043C\u0435\u0441\u0442\u043D\u044B\u0439 (\u043B\u043E\u043A\u0430\u0442\u0438\u0432) \u043F\u0430\u0434\u0435\u0436 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0447\u0438\u0441\u043B\u0430 \u043E\u0442 &quot;sam\u0101c\u0101ra&quot;. \u041F\u0440\u0438\u0441\u0442\u0430\u0432\u043A\u0430 &quot;sam&quot; \u0432 &quot;sam\u0101c\u0101re&quot; \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442] &quot;samyak&quot; --\u043F\u043E\u043B\u0443\u0447\u0435\u043D\u043D\u044B\u0439 \u043E\u0442 &quot;samya\xF1c&quot;-- <em>(samyak iti)</em> [\u0438\u043B\u0438] &quot;\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0441\u0438\u043B\u044B <em>(bal\u0101t)</em> \u043D\u0435\u043F\u043E\u043A\u043E\u043B\u0435\u0431\u0438\u043C\u043E\u0433\u043E \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043D\u0438\u044F <em>(ava\u1E63\u1E6Dambha)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 [\u0421\u0430\u043C\u043E\u0441\u0442\u0438] <em>(antara)</em>, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0432\u0441\u0435 <em>(samagra)</em> \u0443\u0437\u043B\u044B <em>(granthi)</em> \u043E\u0442\u043A\u0440\u044B\u0442\u044B --\u0442.\u0435 \u0440\u0430\u0437\u0432\u044F\u0437\u0430\u043D\u044B-- <em>(vikasita)</em>&quot;<sup>1</sup>. [\u041F\u0440\u0438\u0441\u0442\u0430\u0432\u043A\u0430] &quot;\u0101&quot; [\u0432 &quot;sam\u0101c\u0101re&quot;] <em>(\u0101tmani)</em> [\u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430] &quot;\u043D\u0435\u0431\u043E\u043B\u044C\u0448\u0443\u044E <em>(\u012B\u1E63at)</em> \u043C\u0435\u0434\u043B\u0435\u043D\u043D\u0443\u044E <em>(manda-mandam)</em> \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u0432\u043E\u0432\u043D\u0435 <em>(bahis)</em>&quot;, [\u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A] &quot;c\u0101re&quot; [\u0432 &quot;sam\u0101c\u0101re&quot;] <em>(c\u0101re)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &quot;\u0432 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0438 <em>(prasara\u1E47e)</em>&quot; --\u0442.\u0435. \u043A\u043E\u0433\u0434\u0430 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0435--. [\u0422\u0435\u0440\u043C\u0438\u043D] &quot;sama&quot; [\u0432 &quot;samadar\u015Banam&quot;] <em>(samam)</em> [\u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430] &quot;\u0442\u043E, \u0447\u0442\u043E \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0435\u0434\u0438\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u043E <em>(eka-r\u016Bpam)</em> \u043A\u0430\u043A <em>(\u0101tmatay\u0101)</em> \u043C\u0430\u0441\u0441\u0430 <em>(ghana)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F --\u0442.\u0435. \u015Aiva-- <em>(cit)</em> \u0438 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 --\u0442.\u0435. \u015Aakti-- <em>(\u0101nanda)</em>&quot;. [\u0412 \u0437\u0430\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435,] &quot;dar\u015Bana&quot; <em>(dar\u015Banam)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &quot;\u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u044C <em>(sa\u1E41vedanam)</em>&quot;. [\u0418\u0442\u0430\u043A,] \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0441\u043C\u044B\u0441\u043B\u0443 [\u0441\u043B\u043E\u0432] \u2014\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0431\u044B\u043B\u0438 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u0440\u0430\u0437\u044A\u044F\u0441\u043D\u0435\u043D\u044B\u2014 <em>(arth\u0101t)</em>, [samadar\u015Bana, \u0438\u043B\u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u044C, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0432\u0441\u0435 \u0435\u0434\u0438\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u043E \u043A\u0430\u043A \u043C\u0430\u0441\u0441\u0443 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430, \u0442.\u0435. &quot;\u0435\u0434\u0438\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u043E\u0435 \u0432\u0438\u0434\u0435\u043D\u0438\u0435&quot;,] \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E <em>(bhavati)</em> \u0443 \u044D\u0442\u043E\u0433\u043E [Yog\u012B] <em>(asya)</em> \u043F\u0440\u0438 \u043B\u044E\u0431\u044B\u0445 \u043E\u0431\u0441\u0442\u043E\u044F\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u0430\u0445 --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043F\u0440\u0438 \u0432\u0441\u0435\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0438 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u0440\u043E\u043D\u0438\u0437\u0430\u043D\u044B \u0422\u0443\u0440\u044C\u0435\u0439, \u0438\u043B\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u044B\u043C \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C-- <em>(sarva-da\u015B\u0101su)</em>. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 <em>(iti artha\u1E25)</em>|</p><p>[\u042D\u0442\u043E \u0436\u0435] \u0442\u0430\u043A\u0436\u0435 \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam ca)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C \u0100nandabhairava <em>(\u015Br\u012Bmat-\u0101nandabhairave)</em>:</p><blockquote><p>&quot;\u041E\u0442\u043A\u0430\u0437\u0430\u0432\u0448\u0438\u0441\u044C \u043E\u0442 <em>(uts\u1E5Bjya)</em> \u043F\u0440\u0438\u0432\u044B\u0447\u043D\u044B\u0445 <em>(laukika)</em> \u043F\u0440\u0430\u043A\u0442\u0438\u043A <em>(\u0101c\u0101ram)</em>, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0438\u0431\u0435\u0433\u043D\u0443\u0442\u044C <em>(\u015Brayet)</em> \u043A \u043D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(advaitam)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0434\u0430\u0435\u0442 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 <em>(mukti-dam)</em>. \u041E\u043D <em>(sa\u1E25)</em> [\u0432\u0438\u0434\u0438\u0442] \u0440\u0430\u0432\u043D\u043E\u0441\u0442\u043D\u043E <em>(samam)</em> \u0432\u0441\u0435\u0445 \u0431\u043E\u0433\u043E\u0432 <em>(sarva-dev\u0101n\u0101m)</em>, \u0430 \u0442\u0430\u043A\u0436\u0435 <em>(tath\u0101)</em> \u043A\u0430\u0441\u0442\u044B <em>(var\u1E47a)</em>, \u044D\u0442\u0430\u043F\u044B \u0436\u0438\u0437\u043D\u0438 <em>(\u0101\u015Brama)</em>, \u0438 \u0442.\u043F. <em>(\u0101dike)</em><sup>2</sup>. \u041E\u043D \u043D\u0430\u0431\u043B\u044E\u0434\u0430\u0435\u0442 <em>(dar\u015B\u012B)</em> [\u0432\u0441\u0435] \u0432\u0435\u0449\u0438 <em>(dravy\u0101\u1E47\u0101m)</em> \u0441 \u043D\u0435\u0432\u043E\u0437\u043C\u0443\u0442\u0438\u043C\u043E\u0441\u0442\u044C\u044E <em>(samat\u0101)</em>. \u041E\u043D <em>(sa\u1E25)</em> \u0441\u0432\u043E\u0431\u043E\u0434\u0435\u043D <em>(mukta\u1E25)</em> \u043E\u0442 \u0432\u0441\u0435\u0445 \u043E\u043A\u043E\u0432 <em>(sarva-bandhanai\u1E25... iti)</em>&quot;||</p></blockquote><p>\u041F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(atas eva)</em>, \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E <em>(uktam)</em> \u0432 [\u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430] \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u0443\u044E \u012A\u015Bvarapratyabhij\xF1\u0101 <em>(\u015Br\u012B-pratyabhij\xF1\u0101y\u0101m)</em>:</p><blockquote><p>&quot;\u0414\u043B\u044F \u0442\u0435\u0445, \u0443 \u043A\u043E\u0433\u043E \u043D\u0435\u0442 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0439 <em>(an\u0101hita-sa\u1E45koc\u0101n\u0101m)</em>, [\u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u043D\u044B\u0445] \u043F\u0440\u0435\u0434\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435\u043C <em>(up\u0101d\u0101na)</em> \u043E \u0432\u043D\u0435\u0448\u043D\u0435\u043C <em>(b\u0101hya)</em> \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 <em>(de\u015Ba)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u0434\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 <em>(api)</em> \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(prasare)</em> \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430 <em>(buddhi)</em> [\u0438] \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(pr\u0101\u1E47a)</em>, [\u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E] \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(l\u0101bha\u1E25 eva)</em> \u0438\u0445 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-r\u016Bpa)</em> \u043A\u0430\u043A \u0421\u0430\u043C\u043E\u0441\u0442\u0438 <em>(\u0101tma)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva... iti)</em> --\u043A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u043E\u043D\u0438 \u0432\u0438\u0434\u044F\u0442, \u0447\u0442\u043E \u0438\u0445 \u042F \u0435\u0441\u0442\u044C \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0421\u0430\u043C\u043E\u0441\u0442\u044C, \u0438\u043B\u0438 \u0414\u0443\u0448\u0430, \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F--&quot;||</p></blockquote><p>||22||</p><hr><ol><li><p>\u0412 \u0442\u043E\u043D\u043A\u043E\u043C \u0442\u0435\u043B\u0435 \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u0442\u0440\u0438 \u0443\u0437\u043B\u0430 (granthi-s), \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0445 Brahmagranthi, Vi\u1E63\u1E47ugranthi \u0438 Rudragranthi.\u041A\u0430\u0436\u0434\u044B\u0439 \u0438\u0437 \u044D\u0442\u0438\u0445 \u0443\u0437\u043B\u043E\u0432 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043E\u0441\u043E\u0431\u043E\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0435 (\u0434\u043B\u0438\u043D\u043D\u0430\u044F \u0442\u0435\u043C\u0430!). \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044F \u0421\u0430\u043C\u043E\u0441\u0442\u044C \u2014 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u0430, \u041E\u043D\u0430 \u043F\u043E\u044D\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442\u0441\u044F \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0435\u0439, \u043A\u0430\u043A \u0422\u0430, \u0443 \u043A\u043E\u0433\u043E \u0432\u0441\u0435 \u0443\u0437\u043B\u044B \u0440\u0430\u0437\u0432\u044F\u0437\u0430\u043D\u044B. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435.</p></li><li><p>\u0421\u0438\u0441\u0442\u0435\u043C\u0430 \u043A\u0430\u0441\u0442 \u0438 \u044D\u0442\u0430\u043F\u043E\u0432 \u0436\u0438\u0437\u043D\u0438 \u2014 \u044D\u0442\u043E \u0434\u043B\u0438\u043D\u043D\u0430\u044F \u0438 \u0441\u043B\u043E\u0436\u043D\u0430\u044F \u0442\u0435\u043C\u0430, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0433\u043B\u0443\u0431\u043E\u043A\u043E \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0432\u043E \u043C\u043D\u043E\u0433\u0438\u0445 \u041F\u0438\u0441\u0430\u043D\u0438\u044F\u0445 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0441\u0432\u043E\u0434 (\u0437\u0430\u043A\u043E\u043D\u043E\u0432) Manu). \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u043F\u0440\u0438\u0432\u043E\u0436\u0443 \u0440\u0435\u0437\u044E\u043C\u0435:</p></li></ol><p>\u0418\u043C\u0435\u0435\u0442\u0441\u044F \u0447\u0435\u0442\u044B\u0440\u0435 \u043A\u0430\u0441\u0442\u044B, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, (1) Br\u0101hma\u1E47a \u2014\u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0441\u043B\u0443\u0436\u0438\u0442\u0435\u043B\u0438\u2014, (2) K\u1E63atriya \u2014\u0447\u043B\u0435\u043D\u044B \u0432\u043E\u0435\u043D\u043D\u043E\u0433\u043E \u0438\u043B\u0438 \u0446\u0430\u0440\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0433\u043E \u0440\u043E\u0434\u0430\u2014, (3) Vai\u015Bya \u2014\u043B\u044E\u0434\u0438, \u0437\u0430\u043D\u044F\u0442\u044B\u0435 \u0442\u043E\u0440\u0433\u043E\u0432\u043B\u0435\u0439 \u0438 \u0441\u0435\u043B\u044C\u0441\u043A\u0438\u043C \u0445\u043E\u0437\u044F\u0439\u0441\u0442\u0432\u043E\u043C\u2014 \u0438 (4) \u015A\u016Bdra \u2014\u0441\u043B\u0443\u0433\u0438\u2014. \u0418 \u0438\u043C\u0435\u044E\u0442 \u043C\u0435\u0441\u0442\u043E \u0447\u0435\u0442\u044B\u0440\u0435 \u044D\u0442\u0430\u043F\u0430 \u0436\u0438\u0437\u043D\u0438, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, (1) Brahmac\u0101rin \u2014\u0443\u0447\u0435\u043D\u0438\u043A\u0438, \u0438\u0437\u0443\u0447\u0430\u044E\u0449\u0438\u0435 \u0412\u0435\u0434\u044B \u0438 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0435 \u0431\u0435\u0437\u0431\u0440\u0430\u0447\u0438\u044E, \u0434\u043E 25 \u043B\u0435\u0442\u2014, (2) G\u1E5Bhastha \u2014\u0434\u043E\u043C\u043E\u0432\u043B\u0430\u0434\u0435\u043B\u044C\u0446\u044B; \u0441 25 \u0434\u043E 50 \u043B\u0435\u0442\u2014, (3) V\u0101naprastha \u2014\u0437\u0430\u0442\u0432\u043E\u0440\u043D\u0438\u043A\u0438, \u043E\u0441\u0442\u0430\u0432\u0438\u0432\u0448\u0438\u0435 \u0441\u0432\u043E\u0438 \u0434\u043E\u043C\u0430 \u0438 \u0441\u0435\u043C\u044C\u0438 \u0434\u043B\u044F \u0430\u0441\u043A\u0435\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0436\u0438\u0437\u043D\u0438 \u0432 \u043B\u0435\u0441\u0443; \u0441 50 \u0434\u043E 75 \u043B\u0435\u0442\u2014 \u0438 (4) Sanny\u0101sin \u2014\u0442\u0435, \u043A\u0442\u043E \u043E\u0442\u0440\u0435\u043A\u0441\u044F \u043E\u0442 \u043C\u0438\u0440\u0441\u043A\u0438\u0445 \u0437\u0430\u0431\u043E\u0442, \u043E\u0442 75 \u043B\u0435\u0442\u2014.</p></div>',8),p=[i];function o(u,s,n,v,d,h){return e(),m("div",null,p)}var b=a(r,[["render",o]]);export{k as __pageData,b as default};
